  "const ZIP_SUPPORTED_GENERAL_PURPOSE_FLAGS = ZIP_UTF8_NAME_FLAG;",
  "const EPUB_REPORTED_FIELD_CONTROL_CHARS_GLOBAL = /[\\u0000-\\u001f\\u007f]/gu;",
  "export function buildEpubArchive(state, markdown) {",
