test("new project creates pending confirmation and volume layout", async () => {
  const pipeline = pipelineInTemp();
  const result = await pipeline.newProject({
    franchiseName: "해리포터",
    workRequest: "해리포터와 불의 잔",
    volumeRequest: "해리포터와 불의 잔 1권",
    genre: "판타지",
    tone: "모험"
  });

  assert.equal(result.status, "pending_user_confirmation");
  const data = result.data as { confirmationId: string; franchiseId: string; workId: string; volumeId: string };
  assert.ok(data.confirmationId);
  const status = await pipeline.status({
    franchiseId: data.franchiseId,
    workId: data.workId,
    volumeId: data.volumeId
  });
  assert.equal(status.status, "pending_user_confirmation");
});

test("slug fallback is deterministic for titles without safe path characters", async () => {
  const first = slugify("😀");
  const second = slugify("😀");
  const different = slugify("🚀");

  assert.equal(first, second);
  assert.ok(first !== different);
  assert.match(first, /^item-[a-f0-9]{16}$/);
});

test("slug generation bounds long safe titles for filesystem path segments", () => {
  const first = slugify("가".repeat(200));
  const second = slugify("가".repeat(200));
  const different = slugify("가".repeat(199) + "나");

  assert.equal(first, second);
  assert.ok(first !== different);
  assert.ok(new TextEncoder().encode(first).length <= 120);
  assert.match(first, /^[a-z0-9가-힣][a-z0-9가-힣._-]*-[a-f0-9]{16}$/u);
});

test("slug generation rejects invalid direct inputs", () => {
  assert.throws(() => slugify(42 as unknown as string), /slugify value must be a string/);
  assert.throws(() => slugify("x".repeat(16 * 1024 + 1)), /slugify value must be at most 16384 characters/);
});

test("exists helper rejects invalid direct path inputs", async () => {
  await assertRejects(
    storageExists(null as unknown as string),
    /exists path must be a non-empty string/
  );
  await assertRejects(
    storageExists("/tmp/novelist\nbad-path"),
    /exists path must not contain control characters/
  );
});

test("shared validation helpers reject invalid direct metadata inputs", () => {
  assert.throws(
    () => assertBoundedNonEmptyString("value", "", 10),
    /Validation label must be a non-empty string/
  );
  assert.throws(
    () => assertBoundedNonEmptyString("value", "field\u0001name", 10),
    /Validation label must not contain control characters/
  );
  assert.throws(
    () => assertBoundedNonEmptyString("value", "field\nname", 10),
    /Validation label must not contain control characters/
  );
  assert.throws(
    () => assertBoundedNonEmptyString("value", "field\tname", 10),
    /Validation label must not contain control characters/
  );
  assert.throws(
    () => assertBoundedNonEmptyString("value", "가".repeat(180), 10),
    /Validation label must be at most 512 UTF-8 bytes/
  );
  assert.throws(
    () => assertBoundedNonEmptyString("value", "field", Number.NaN),
    /Validation maxChars must be an integer/
  );
  assert.throws(
    () => assertBoundedNonEmptyString("value", "field", 0),
    /Validation maxChars must be between 1 and 1048576/
  );
  assert.throws(
    () => assertBoundedNonEmptyString("가".repeat(350_000), "field", 1_000_000),
    /field must be at most 1048576 UTF-8 bytes/
  );
  assert.equal(asOptionalString(undefined), undefined);
  assert.equal(asOptionalString(42), undefined);
  assert.equal(asOptionalString(" \t trimmed value \n "), "trimmed value");
  assert.throws(
    () => asOptionalString(`safe\u0001hidden`),
    /Optional string must not contain control characters/
  );
  assert.throws(
    () => asOptionalString("x".repeat(1024 * 1024 + 1)),
    /Optional string must be at most 1048576 characters/
  );
  assert.throws(
    () => asOptionalString("가".repeat(350_000)),
    /Optional string must be at most 1048576 UTF-8 bytes/
  );

  let getterRan = false;
  const shape = Object.create(null) as Record<string, unknown>;
  Object.defineProperty(shape, "name", {
    enumerable: true,
    get() {
      getterRan = true;
      throw new Error("validation shape getter must not run");
    }
  });
  assert.throws(
    () => assertShape({ name: "value" }, "payload", shape as never),
    /Validation shape must not contain non-enumerable or accessor properties/
  );
  assert.equal(getterRan, false);
  assert.throws(
    () => assertShape({ name: "value" }, "payload", { name: "number" } as never),
    /Validation shape\.name must be a supported field type/
  );
  assert.throws(
    () => assertObject(Object.fromEntries(Array.from({ length: 1001 }, (_value, index) => [`key${index}`, index])), "payload"),
    /payload must contain at most 1000 fields/
  );
  assert.throws(
    () => assertObject({ ["k".repeat(257)]: "value" }, "payload"),
    /payload field names must be at most 256 characters/
  );
  assert.throws(
    () => assertObject({ ["가".repeat(180)]: "value" }, "payload"),
    /payload field names must be at most 512 UTF-8 bytes/
  );
  assert.throws(
    () => assertObject({ "bad\nkey": "value" }, "payload"),
    /payload field names must not contain control characters/
  );
  assert.throws(
    () => assertShape({ name: "value" }, "payload", Object.fromEntries(Array.from({ length: 1001 }, (_value, index) => [`key${index}`, "string"])) as never),
    /Validation shape must contain at most 1000 fields/
  );
  assert.throws(
    () => assertObject(new Proxy({}, {
      getPrototypeOf() {
        throw new Error("leaked validation prototype trap Authorization: Bearer validation-secret");
      }
    }), "payload"),
    /payload prototype must be readable/
  );
  assert.throws(
    () => assertObject(new Proxy({}, {
      ownKeys() {
        throw new Error("leaked validation ownKeys trap Authorization: Bearer validation-secret");
      }
    }), "payload"),
    /payload keys must be readable/
  );
  assert.throws(
    () => assertObject(new Proxy({ name: "value" }, {
      getOwnPropertyDescriptor() {
        throw new Error("leaked validation descriptor trap Authorization: Bearer validation-secret");
      }
    }), "payload"),
    /payload property descriptors must be readable/
  );

  const objectWithPrototypeKey = Object.create(null) as Record<string, unknown>;
  Object.defineProperty(objectWithPrototypeKey, "__proto__", {
    enumerable: true,
    value: { polluted: true }
  });
  const validated = assertObject(objectWithPrototypeKey, "payload");
  assert.equal(Object.prototype.hasOwnProperty.call(validated, "__proto__"), true);
  assert.deepEqual(validated.__proto__, { polluted: true });
  assert.equal(({} as { polluted?: boolean }).polluted, undefined);
  assert.throws(
    () => assertShape(objectWithPrototypeKey, "payload", {}),
    /payload\.__proto__ is not a supported field/
  );
  assert.equal(assertRevisionTargetString("chapter:1,beat:2", "target", 256, 256), "chapter:1,beat:2");
  assert.equal(assertRevisionTargetString("chapter:1 beat:2", "target", 256, 256), "chapter:1 beat:2");
  assert.equal(assertRevisionTargetString("1/2", "target", 256, 256), "1/2");
  assert.throws(
    () => assertRevisionTargetString("chapter:1\tbeat:2", "target", 256, 256),
    /target must be a single-line string/
  );
  assert.throws(
    () => assertRevisionTargetString("chapter:0,beat:1", "target", 256, 256),
    /<chapter>\/<beat>/
  );
  assert.throws(
    () => assertRevisionTargetString(`chapter:${"1".repeat(250)},beat:1`, "target", 512, 256),
    /target must be at most 256 UTF-8 bytes/
  );
  assert.throws(
    () => assertSafeId(" safe-id ", "safeId"),
    /safeId must not have leading or trailing whitespace/
  );
});

test("JSON preflight rejects invalid direct labels and depth bounds", () => {
  assert.throws(
    () => assertNoDuplicateJsonObjectKeys(null as unknown as string, "JSON", 32),
    /JSON preflight text must be a string/
  );
  assert.throws(
    () => assertNoDuplicateJsonObjectKeys(" ".repeat(16 * 1024 * 1024 + 1), "JSON", 32),
    /JSON preflight text must be at most 16777216 characters/
  );
  assert.throws(
    () => assertNoDuplicateJsonObjectKeys("가".repeat(6 * 1024 * 1024), "JSON", 32),
    /JSON preflight text must be at most 16777216 UTF-8 bytes/
  );
  assert.throws(
    () => assertNoDuplicateJsonObjectKeys("{}", "", 32),
    /JSON preflight label must be a non-empty string/
  );
  assert.throws(
    () => assertNoDuplicateJsonObjectKeys("{}", "field\nname", 32),
    /JSON preflight label must not contain control characters/
  );
  assert.throws(
    () => assertNoDuplicateJsonObjectKeys("{}", "x".repeat(257), 32),
    /JSON preflight label must be at most 256 characters/
  );
  assert.throws(
    () => assertNoDuplicateJsonObjectKeys("{}", "가".repeat(171), 32),
    /JSON preflight label must be at most 512 UTF-8 bytes/
  );
  assert.throws(
    () => assertNoDuplicateJsonObjectKeys("{}", "JSON", Number.NaN),
    /JSON preflight maxDepth must be an integer/
  );
  assert.throws(
    () => assertNoDuplicateJsonObjectKeys("{}", "JSON", 0),
    /JSON preflight maxDepth must be between 1 and 1024/
  );
  assert.throws(
    () => assertNoDuplicateJsonObjectKeys("{}", "JSON", 1025),
    /JSON preflight maxDepth must be between 1 and 1024/
  );
  assert.throws(
    () => assertNoDuplicateJsonObjectKeys('{"a":1,"a":2}', "  JSON label  ", 32),
    /JSON label must not contain duplicate object keys/
  );
  assert.throws(
    () => assertNoDuplicateJsonObjectKeys(
      `{${Array.from({ length: 10001 }, (_, index) => `"key${index}":${index}`).join(",")}}`,
      "JSON",
      32
    ),
    /JSON objects must contain at most 10000 keys/
  );
  assertNoDuplicateJsonObjectKeys('{"bad":"\\u00zz","bad":"still malformed"}', "JSON", 32);
});

