test("confirmation lookup ignores non-project filesystem entries", async () => {
  const root = testRoot("novelist-franchise-noise-test");
  const storage = new NovelStorage(root);
  const pipeline = new NovelPipeline(storage);
  const created = await pipeline.newProject({
    franchiseName: "노이즈 프랜차이즈",
    workRequest: "노이즈 작품"
  });
  const data = created.data as { confirmationId: string; franchiseId: string; workId: string; volumeId: string };
  const outside = testRoot("novelist-franchise-noise-outside");
  await mkdir(outside, { recursive: true });

  await writeFile(join(root, "franchises", "safe-but-not-directory"), "operator note", "utf8");
  await writeFile(join(root, "franchises", "operator note.txt"), "operator note", "utf8");
  await writeFile(join(root, "franchises", "operator\nnote.txt"), "operator note", "utf8");
  await mkdir(join(root, "franchises", "bad id"), { recursive: true });
  await mkdir(join(root, "franchises", "bad\nid"), { recursive: true });
  await symlink(outside, join(root, "franchises", "safe-symlink"));
  await writeFile(join(root, "franchises", data.franchiseId, "works", "safe-but-not-directory"), "operator note", "utf8");
  await writeFile(join(root, "franchises", data.franchiseId, "works", "operator\nnote.txt"), "operator note", "utf8");
  await mkdir(join(root, "franchises", data.franchiseId, "works", "bad id"), { recursive: true });
  await mkdir(join(root, "franchises", data.franchiseId, "works", "bad\nid"), { recursive: true });
  await symlink(outside, join(root, "franchises", data.franchiseId, "works", "safe-symlink"));
  await writeFile(join(root, "franchises", data.franchiseId, "works", data.workId, "volumes", "safe-but-not-directory"), "operator note", "utf8");
  await writeFile(join(root, "franchises", data.franchiseId, "works", data.workId, "volumes", "operator\nnote.txt"), "operator note", "utf8");
  await mkdir(join(root, "franchises", data.franchiseId, "works", data.workId, "volumes", "bad id"), { recursive: true });
  await mkdir(join(root, "franchises", data.franchiseId, "works", data.workId, "volumes", "bad\nid"), { recursive: true });
  await symlink(outside, join(root, "franchises", data.franchiseId, "works", data.workId, "volumes", "safe-symlink"));

  assert.deepEqual(await storage.listFranchises(), [data.franchiseId]);
  assert.deepEqual(await storage.listWorks(data.franchiseId), [data.workId]);
  assert.deepEqual(await storage.listVolumes(data.franchiseId, data.workId), [data.volumeId]);
  const confirmed = await pipeline.confirm({ confirmationId: data.confirmationId, approved: true });

  assert.equal(confirmed.status, "drafting");
});

