test("confirmation revisions do not append repeatedly to persisted messages", async () => {
  const root = testRoot("novelist-confirmation-revision-growth-test");
  const storage = new NovelStorage(root);
  const pipeline = new NovelPipeline(storage);
  const created = await pipeline.newProject({
    franchiseName: "수정 누적 세계",
    workRequest: "수정 누적 작품"
  });
  const data = created.data as { confirmationId: string; franchiseId: string; workId: string; volumeId: string };

  await pipeline.confirm({ confirmationId: data.confirmationId, approved: false, revisionInstruction: "첫 수정" });
  await pipeline.confirm({ confirmationId: data.confirmationId, approved: false, revisionInstruction: "두 번째 수정" });
  const pending = await storage.loadState(data.franchiseId, data.workId, data.volumeId);
  const confirmation = pending.confirmations[0];

  assert.equal(confirmation?.revisionInstruction, "두 번째 수정");
  assert.equal((confirmation?.message.match(/사용자 수정 지시/g) ?? []).length, 0);

  const confirmed = await pipeline.confirm({ confirmationId: data.confirmationId, approved: true });
  const work = await readFile(join(storage.workDir(data.franchiseId, data.workId), "work.md"), "utf8");

  assert.equal(confirmed.status, "drafting");
  assert.match(work, /사용자 수정 지시: 두 번째 수정/);
  assert.equal((work.match(/사용자 수정 지시/g) ?? []).length, 1);
});

test("pipeline completes all beats and builds a valid EPUB archive", async () => {
  const pipeline = pipelineInTemp();
  const created = await pipeline.newProject({
    franchiseName: "완결 프랜차이즈",
    workRequest: "완결 작품"
  });
  const data = created.data as { confirmationId: string; franchiseId: string; workId: string; volumeId: string };
  let next = await pipeline.confirm({ confirmationId: data.confirmationId, approved: true });

  while (next.status !== "complete") {
    next = await pipeline.continue({
      franchiseId: data.franchiseId,
      workId: data.workId,
      volumeId: data.volumeId
    });
  }

  const epub = await pipeline.buildEpub({
    franchiseId: data.franchiseId,
    workId: data.workId,
    volumeId: data.volumeId
  });
  assert.equal(epub.status, "ok");
  const epubData = epub.data as { path: string; bytes: number };
  assert.match(epubData.path, /\.epub/);
  assert.ok(epubData.bytes > 100);
  const bytes = await readFile(epubData.path);
  assert.equal(bytes[0], 0x50);
  assert.equal(bytes[1], 0x4b);
  assert.equal(readZipUint16(bytes, 6) & 0x0800, 0x0800);
  const centralDirectoryOffset = findZipCentralDirectoryOffset(bytes);
  assert.equal(readZipUint16(bytes, centralDirectoryOffset + 8) & 0x0800, 0x0800);
  const validation = validateEpubArchive(bytes);
  assert.equal(validation.valid, true, validation.issues.join("\n"));
  assert.deepEqual(validation.entries, [
    "mimetype",
    "META-INF/container.xml",
    "EPUB/package.opf",
    "EPUB/nav.xhtml",
    "EPUB/content.xhtml"
  ]);
});

