test("direct EPUB storage writes reject incomplete states and invalid archives", async () => {
  const storage = new NovelStorage(testRoot("novelist-direct-epub-write-validation-test"));
  const pipeline = new NovelPipeline(storage);
  const data = await completeTinyVolume(pipeline);
  const completeState = await storage.loadState(data.franchiseId, data.workId, data.volumeId);
  const incompleteState = {
    ...completeState,
    status: "drafting"
  } as typeof completeState;
  const validArchive = buildEpubArchive(completeState, "본문");

  await assertRejects(storage.writeEpub(incompleteState, validArchive), /EPUB can only be written for a complete volume/);
  await assertRejects(storage.writeEpub(completeState, new Uint8Array([9, 8, 7])), /EPUB archive validation failed/);
  await assertRejects(readFile(storage.epubPath(completeState)), /ENOENT/);

  const path = await storage.writeEpub(completeState, validArchive);
  assert.equal(path, storage.epubPath(completeState));
  assert.equal(validateEpubArchive(await readFile(path)).valid, true);
});

test("direct EPUB storage writes reject semantically invalid complete states", async () => {
  const storage = new NovelStorage(testRoot("novelist-direct-epub-state-semantic-validation-test"));
  const pipeline = new NovelPipeline(storage);
  const data = await completeTinyVolume(pipeline);
  const completeState = await storage.loadState(data.franchiseId, data.workId, data.volumeId);
  const invalidCompleteState = {
    ...completeState,
    chapters: []
  } as VolumeState;
  const validArchive = buildEpubArchive(completeState, "본문");
  const volumeDir = storage.volumeDir(completeState.franchiseId, completeState.workId, completeState.volumeId);
  const manualCandidate = join(volumeDir, `${completeState.volumeId}.candidate-${randomUUID()}.epub`);

  await assertRejects(storage.writeEpub(invalidCompleteState, validArchive), /VolumeState\.chapters must not be empty/);
  await assertRejects(storage.writeEpubCandidate(invalidCompleteState, validArchive), /VolumeState\.chapters must not be empty/);
  assert.deepEqual((await readdir(volumeDir)).filter((name) => name.includes(".candidate-")), []);
  assert.equal(await storageExists(storage.epubPath(completeState)), false);

  await writeFile(manualCandidate, validArchive);
  await assertRejects(storage.promoteEpubCandidate(invalidCompleteState, manualCandidate), /VolumeState\.chapters must not be empty/);
  assert.equal(validateEpubArchive(await readFile(manualCandidate)).valid, true);
  assert.equal(await storageExists(storage.epubPath(completeState)), false);
});

