test("storage directory scans stream entries instead of materializing full directory arrays", async () => {
  const storageSource = await readFile(join(process.cwd(), "src", "storage.ts"), "utf8");

  assert.match(storageSource, /const MAX_DIRECTORY_SCAN_ENTRIES = 10000/);
  assert.match(storageSource, /const MAX_DIRECTORY_ENTRY_NAME_BYTES = 1024/);
  assert.match(storageSource, /import \{[^}]*opendir[^}]*\} from "node:fs\/promises"/);
  assert.match(storageSource, /for await \(const name of this\.readDirectoryNames\(dir\)\)/);
  assert.match(storageSource, /private async \*readDirectoryNames\(dir: string\): AsyncGenerator<string>/);
  assert.match(storageSource, /const directory = await opendir\(dir\)/);
  assert.match(storageSource, /if \(scanned > MAX_DIRECTORY_SCAN_ENTRIES\)/);
  assert.match(storageSource, /if \(!isSupportedDirectoryEntryName\(entry\.name\)\)/);
  assert.match(storageSource, /for await \(const entry of directory\)/);
  assert.equal(storageSource.includes("for (const name of await readdir(dir))"), false);
});

test("direct EPUB helpers validate state data before deriving paths", async () => {
  const storage = new NovelStorage(testRoot("novelist-direct-epub-state-validation-test"));
  const pipeline = new NovelPipeline(storage);
  const data = await completeTinyVolume(pipeline);
  const state = await storage.loadState(data.franchiseId, data.workId, data.volumeId);
  const validArchive = buildEpubArchive(state, "본문");
  const validCandidate = await storage.writeEpubCandidate(state, validArchive);
  let getterRan = false;
  const invalidState = Object.defineProperty({ ...state }, "volumeId", {
    enumerable: true,
    get() {
      getterRan = true;
      throw new Error("state getter must not run");
    }
  }) as VolumeState;

  assert.throws(() => storage.epubPath(invalidState), /VolumeState must not contain non-enumerable or accessor properties/);
  await assertRejects(storage.writeEpub(invalidState, validArchive), /VolumeState must not contain non-enumerable or accessor properties/);
  await assertRejects(storage.readEpubFile(invalidState), /VolumeState must not contain non-enumerable or accessor properties/);
  await assertRejects(storage.writeEpubCandidate(invalidState, validArchive), /VolumeState must not contain non-enumerable or accessor properties/);
  await assertRejects(storage.promoteEpubCandidate(invalidState, validCandidate), /VolumeState must not contain non-enumerable or accessor properties/);
  await assertRejects(storage.deleteEpubCandidate(invalidState, validCandidate), /VolumeState must not contain non-enumerable or accessor properties/);

  assert.equal(getterRan, false);
  assert.equal(validateEpubArchive(await readFile(validCandidate)).valid, true);
  assert.equal(await storageExists(storage.epubPath(state)), false);
});

