test("EPUB validator rejects package spine and manifest mismatches", async () => {
  const storage = new NovelStorage(testRoot("novelist-epub-opf-link-test"));
  const pipeline = new NovelPipeline(storage);
  const data = await completeTinyVolume(pipeline);
  const epub = await pipeline.buildEpub(data);
  const epubData = epub.data as { path: string };
  const archive = await readFile(epubData.path);
  const encoder = new TextEncoder();

  const missingContentManifest = replaceFirstAsciiAndCrc(
    archive,
    '<item id="content" href=',
    encoder.encode('<item id="missing" href=')
  );
  const missingSpineReference = replaceFirstAsciiAndCrc(
    archive,
    'idref="content"',
    encoder.encode('idref="missing"')
  );

  const manifestValidation = validateEpubArchive(missingContentManifest);
  const spineValidation = validateEpubArchive(missingSpineReference);

  assert.equal(manifestValidation.valid, false);
  assert.match(manifestValidation.issues.join("\n"), /content\.xhtml as an XHTML manifest item/);
  assert.equal(spineValidation.valid, false);
  assert.match(spineValidation.issues.join("\n"), /spine must reference the content manifest item/);
});

