test("EPUB validator rejects malformed required XML entries", async () => {
  const storage = new NovelStorage(testRoot("novelist-epub-malformed-required-xml-test"));
  const pipeline = new NovelPipeline(storage);
  const data = await completeTinyVolume(pipeline);
  const epub = await pipeline.buildEpub(data);
  const epubData = epub.data as { path: string };
  const archive = await readFile(epubData.path);
  const mismatchedClosingTag = replaceFirstAsciiAndCrc(archive, "</body>", new TextEncoder().encode("</main>"));
  const invalidEntity = replaceFirstAsciiAndCrc(archive, "ko", new TextEncoder().encode("A&"));
  const invalidNumericEntity = replaceFirstAsciiAndCrc(archive, "<body>", new TextEncoder().encode("&#0;xx"));

  const tagValidation = validateEpubArchive(mismatchedClosingTag);
  const entityValidation = validateEpubArchive(invalidEntity);
  const numericEntityValidation = validateEpubArchive(invalidNumericEntity);

  assert.equal(tagValidation.valid, false);
  assert.match(tagValidation.issues.join("\n"), /EPUB\/nav\.xhtml must be well-formed XML: closing tag main does not match body/);
  assert.equal(entityValidation.valid, false);
  assert.match(entityValidation.issues.join("\n"), /EPUB\/package\.opf must be well-formed XML: invalid entity reference/);
  assert.equal(numericEntityValidation.valid, false);
  assert.match(numericEntityValidation.issues.join("\n"), /EPUB\/(?:nav|content)\.xhtml must be well-formed XML: invalid numeric character reference &#0;/);
});

