test("EPUB validator wraps unreadable direct archive metadata without throwing", () => {
  const secret = "Authorization: Bearer epub-archive-reflection-secret";
  const assertInvalidArchive = (archive: Uint8Array, expected: RegExp): void => {
    const invalid = validateEpubArchive(archive);
    const text = invalid.issues.join("\n");

    assert.equal(invalid.valid, false);
    assert.deepEqual(invalid.entries, []);
    assert.match(text, expected);
    assert.doesNotMatch(text, /epub-archive-reflection-secret/);
  };

  assertInvalidArchive(new Proxy(new Uint8Array([1, 2, 3]), {
    getPrototypeOf() {
      throw new Error(`raw epub prototype trap leaked ${secret}`);
    }
  }), /EPUB archive must be a Uint8Array/);

  assertInvalidArchive(new Proxy(new Uint8Array([1, 2, 3]), {
    get(target, key, receiver) {
      if (key === "byteLength") {
        throw new Error(`raw epub byteLength trap leaked ${secret}`);
      }
      return Reflect.get(target, key, receiver);
    }
  }), /EPUB archive byte length must be readable/);

  assertInvalidArchive(new Proxy(new Uint8Array([1, 2, 3]), {
    get(target, key, receiver) {
      if (key === "byteLength") {
        return target.byteLength;
      }
      if (key === Symbol.iterator) {
        throw new Error(`raw epub snapshot trap leaked ${secret}`);
      }
      return Reflect.get(target, key, receiver);
    }
  }), /EPUB archive must be snapshot-readable/);
});

