test("EPUB validator caps reported issues and entry lists", () => {
  const archive = createTestStoredZip(
    Array.from({ length: 320 }, (_, index) => `../unsafe-${String(index).padStart(3, "0")}-${"x".repeat(500)}.txt`)
  );
  const validation = validateEpubArchive(archive);

  assert.equal(validation.valid, false);
  assert.equal(validation.issues.length, 50);
  assert.match(validation.issues.at(-1) ?? "", /truncated additional EPUB validation issues/);
  assert.equal(validation.entries.length, 257);
  assert.match(validation.entries[0] ?? "", /truncated/);
  assert.ok((validation.entries[0] ?? "").length < 260);
  assert.match(validation.entries.at(-1) ?? "", /truncated 64 EPUB entries/);
  assert.ok(JSON.stringify(validation).length < 80_000);
});

