test("continue review feedback returns defensive beat copies", async () => {
  const storage = new NovelStorage(testRoot("novelist-continue-beat-copy-test"));
  const pipeline = new NovelPipeline(storage, new JoinedIssueAgents());
  const created = await pipeline.newProject({
    franchiseName: "반환 복사 세계",
    workRequest: "반환 복사 작품"
  });
  const data = created.data as { confirmationId: string; franchiseId: string; workId: string; volumeId: string };
  await pipeline.confirm({ confirmationId: data.confirmationId, approved: true });

  const continued = await pipeline.continue({ franchiseId: data.franchiseId, workId: data.workId, volumeId: data.volumeId });
  const returned = continued.data as { beat?: { status?: string; retryCount?: number; lastFeedback?: string } };
  const originalFeedback = returned.beat?.lastFeedback;
  const originalRetryCount = returned.beat?.retryCount;

  assert.equal(continued.status, "drafting");
  assert.equal(returned.beat?.status, "needs_revision");
  if (!returned.beat) {
    throw new Error("Expected returned beat.");
  }
  returned.beat.status = "complete";
  returned.beat.retryCount = 999;
  returned.beat.lastFeedback = "mutated public return value";

  const persisted = await storage.loadState(data.franchiseId, data.workId, data.volumeId);
  const persistedBeat = persisted.chapters[0]?.beats[0];

  assert.equal(persistedBeat?.status, "needs_revision");
  assert.equal(persistedBeat?.retryCount, originalRetryCount);
  assert.equal(persistedBeat?.lastFeedback, originalFeedback);
});

