test("status summaries bound pending confirmation text and conflict arrays", async () => {
  const storage = new NovelStorage(testRoot("novelist-status-summary-bound-test"));
  const pipeline = new NovelPipeline(storage);
  const created = await pipeline.newProject({
    franchiseName: "큰 상태 세계",
    workRequest: "큰 상태 작품"
  });
  const data = created.data as { franchiseId: string; workId: string; volumeId: string };
  const state = await storage.loadState(data.franchiseId, data.workId, data.volumeId);
  state.status = "pending_user_confirmation";
  state.confirmations = [{
    id: "confirm-single-long",
    kind: "revision" as const,
    message: `확인 Authorization: Bearer status-summary-secret ${"x".repeat(4000)}`,
    createdAt: state.createdAt,
    revisionInstruction: `수정 api_key=status-summary-api-secret ${"y".repeat(4000)}`
  }];
  state.conflicts = Array.from({ length: 60 }, (_, index) => ({
    id: `conflict-many-${index}`,
    scope: `summary sk-statussummary${index} ${"s".repeat(3000)}`,
    description: `충돌 ${index} refresh_token=status-summary-refresh-secret ${"z".repeat(3000)}`,
    severity: "warning" as const,
    resolved: false
  }));
  await storage.saveState(state);

  const server = new McpServer(pipeline, new Logger("silent"), storage);
  const response = await server.handle({
    jsonrpc: "2.0",
    id: 85,
    method: "tools/call",
    params: {
      name: "novel_status",
      arguments: {
        franchiseId: data.franchiseId,
        workId: data.workId,
        volumeId: data.volumeId
      }
    }
  });
  const continueResponse = await server.handle({
    jsonrpc: "2.0",
    id: 86,
    method: "tools/call",
    params: {
      name: "novel_continue",
      arguments: {
        franchiseId: data.franchiseId,
        workId: data.workId,
        volumeId: data.volumeId
      }
    }
  });
  const responseText = JSON.stringify(response);
  const continueResponseText = JSON.stringify(continueResponse);
  const payload = extractToolPayload(response) as {
    data?: {
      pendingConfirmationCount?: number;
      unresolvedConflictCount?: number;
      pendingConfirmationHasMore?: boolean;
      unresolvedConflictHasMore?: boolean;
      summaryItemLimit?: number;
      summaryTextLimit?: number;
      pendingConfirmations?: Array<{ message?: string; revisionInstruction?: string }>;
      unresolvedConflicts?: Array<{ scope?: string; description?: string }>;
    };
  };
  const continuePayload = extractToolPayload(continueResponse) as {
    data?: {
      pendingConfirmationCount?: number;
      pendingConfirmationHasMore?: boolean;
      pendingConfirmations?: Array<{ message?: string }>;
    };
  };

  assert.equal(responseText.length < 256 * 1024, true);
  assert.equal(continueResponseText.length < 256 * 1024, true);
  assert.equal(responseText.includes("status-summary-secret"), false);
  assert.equal(responseText.includes("status-summary-api-secret"), false);
  assert.equal(responseText.includes("statussummary0"), false);
  assert.equal(responseText.includes("status-summary-refresh-secret"), false);
  assert.match(responseText, /Bearer \[Redacted\]/);
  assert.match(responseText, /api_key=\[Redacted\]/);
  assert.match(responseText, /sk-\[Redacted\]/);
  assert.match(responseText, /refresh_token=\[Redacted\]/);
  assert.equal(payload.data?.pendingConfirmationCount, 1);
  assert.equal(payload.data?.unresolvedConflictCount, 60);
  assert.equal(payload.data?.pendingConfirmationHasMore, false);
  assert.equal(payload.data?.unresolvedConflictHasMore, true);
  assert.equal(payload.data?.summaryItemLimit, 20);
  assert.equal(payload.data?.summaryTextLimit, 1000);
  assert.equal(payload.data?.pendingConfirmations?.length, 1);
  assert.equal(payload.data?.unresolvedConflicts?.length, 20);
  assert.match(payload.data?.pendingConfirmations?.[0]?.message ?? "", /truncated/);
  assert.match(payload.data?.pendingConfirmations?.[0]?.revisionInstruction ?? "", /truncated/);
  assert.match(payload.data?.unresolvedConflicts?.[0]?.scope ?? "", /truncated/);
  assert.match(payload.data?.unresolvedConflicts?.[0]?.description ?? "", /truncated/);
  assert.equal(continuePayload.data?.pendingConfirmationCount, 1);
  assert.equal(continuePayload.data?.pendingConfirmationHasMore, false);
  assert.equal(continuePayload.data?.pendingConfirmations?.length, 1);
  assert.match(continuePayload.data?.pendingConfirmations?.[0]?.message ?? "", /truncated/);
});

