test("direct pipeline storage errors redact storage roots", async () => {
  const root = testRoot("novelist-direct-pipeline-root-redaction-test");
  const outside = testRoot("novelist-direct-pipeline-root-redaction-outside");
  const storage = new NovelStorage(root);
  const pipeline = new NovelPipeline(storage);
  await mkdir(join(root, "franchises", "safe-world", "works", "safe-work", "volumes"), { recursive: true });
  await mkdir(outside, { recursive: true });
  await writeFile(join(outside, "state.json"), "{}", "utf8");
  await symlink(outside, storage.volumeDir("safe-world", "safe-work", "safe-volume"));

  try {
    await pipeline.status({ franchiseId: "safe-world", workId: "safe-work", volumeId: "safe-volume" });
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    assert.match(message, /<data-root>/);
    assert.equal(message.includes(storage.root), false);
    return;
  }
  throw new Error("Expected status to reject.");
});

test("direct pipeline argument validation rejects non-plain objects without invoking accessors", async () => {
  const pipeline = pipelineInTemp();

  await assertRejects(
    pipeline.newProject(new Date() as unknown as Parameters<NovelPipeline["newProject"]>[0]),
    /novel_new_project arguments must be a plain object/
  );

  const symbolInput = {
    franchiseName: "심볼 입력 세계",
    workRequest: "심볼 입력 작품",
    [Symbol("hidden")]: "secret"
  };
  await assertRejects(
    pipeline.newProject(symbolInput as unknown as Parameters<NovelPipeline["newProject"]>[0]),
    /novel_new_project arguments must not contain symbol properties/
  );

  const hiddenInput = Object.defineProperty({
    franchiseName: "숨김 입력 세계",
    workRequest: "숨김 입력 작품"
  }, "hidden", { value: "secret", enumerable: false });
  await assertRejects(
    pipeline.newProject(hiddenInput as unknown as Parameters<NovelPipeline["newProject"]>[0]),
    /novel_new_project arguments must not contain non-enumerable or accessor properties/
  );

  const accessorInput = Object.defineProperty({
    franchiseName: "접근자 입력 세계"
  }, "workRequest", {
    enumerable: true,
    get() {
      throw new Error("pipeline input getter must not run");
    }
  });
  await assertRejects(
    pipeline.newProject(accessorInput as unknown as Parameters<NovelPipeline["newProject"]>[0]),
    /novel_new_project arguments must not contain non-enumerable or accessor properties/
  );

  await assertRejects(pipeline.status({ current: true }), /No current novel pipeline/);
});

test("MCP tools call returns structured content and invalid requests return JSON-RPC errors", async () => {
  const pipeline = pipelineInTemp();
  const server = new McpServer(pipeline, new Logger("silent"));
  const expectedVersion = await packageVersion();
  const initialized = await server.handle({ jsonrpc: "2.0", id: "init", method: "initialize" });
  const initializeResult = (initialized as { result?: { serverInfo?: { name?: string; version?: string } } }).result;
  assert.equal(initializeResult?.serverInfo?.name, "novelist-mcp");
  assert.equal(initializeResult?.serverInfo?.version, expectedVersion);
  const invalid = await server.handle({ jsonrpc: "2.0", id: 1, method: "tools/call", params: { arguments: {} } });
  assert.match(JSON.stringify(invalid), /tools\/call requires params\.name/);
  const invalidId = await server.handle({ jsonrpc: "2.0", id: { bad: true }, method: "tools/list" });
  assert.equal((invalidId as { id: unknown }).id, null);
  assert.match(JSON.stringify(invalidId), /id must be a string/);
  const oversizedId = await server.handle({ jsonrpc: "2.0", id: "x".repeat(257), method: "tools/list" });
  assert.equal((oversizedId as { id: unknown }).id, null);
  assert.match(JSON.stringify(oversizedId), /up to 256 characters/);
  const oversizedMultibyteId = await server.handle({ jsonrpc: "2.0", id: "가".repeat(86), method: "tools/list" });
  assert.equal((oversizedMultibyteId as { id: unknown }).id, null);
  assert.match(JSON.stringify(oversizedMultibyteId), /256 UTF-8 bytes/);
  const unsafeId = await server.handle({ jsonrpc: "2.0", id: "bad\nid", method: "tools/list" });
  assert.equal((unsafeId as { id: unknown }).id, null);
  assert.match(JSON.stringify(unsafeId), /id must be a string/);
  const fractionalId = await server.handle({ jsonrpc: "2.0", id: 1.5, method: "tools/list" });
  assert.equal((fractionalId as { id: unknown }).id, null);
  assert.match(JSON.stringify(fractionalId), /safe integer/);
  const batchRequest = await server.handle([{ jsonrpc: "2.0", id: 10, method: "tools/list" }]);
  assert.equal((batchRequest as { id: unknown }).id, null);
  assert.match(JSON.stringify(batchRequest), /Request must be an object/);
  const primitiveRequest = await server.handle("not a request");
  assert.equal((primitiveRequest as { id: unknown }).id, null);
  assert.match(JSON.stringify(primitiveRequest), /Request must be an object/);
  const oversizedMethod = await server.handle({ jsonrpc: "2.0", id: 16, method: "x".repeat(129) });
  assert.match(JSON.stringify(oversizedMethod), /method must be at most 128/);
  const oversizedMultibyteMethod = await server.handle({ jsonrpc: "2.0", id: 46, method: "가".repeat(43) });
  assert.match(JSON.stringify(oversizedMultibyteMethod), /method must be at most 128 UTF-8 bytes/);
  const unsafeMethod = await server.handle({ jsonrpc: "2.0", id: 17, method: "tools/list\n" });
  assert.match(JSON.stringify(unsafeMethod), /method must not contain control characters/);
  const paddedMethod = await server.handle({ jsonrpc: "2.0", id: 44, method: " tools/list " });
  assert.match(JSON.stringify(paddedMethod), /method must not have leading or trailing whitespace/);
  const invalidParams = await server.handle({ jsonrpc: "2.0", id: 13, method: "tools/call", params: null });
  assert.match(JSON.stringify(invalidParams), /tools\/call params must be an object/);
  const invalidNullArguments = await server.handle({ jsonrpc: "2.0", id: 11, method: "tools/call", params: { name: "novel_status", arguments: null } });
  assert.match(JSON.stringify(invalidNullArguments), /params\.arguments must be an object/);
  const invalidArrayArguments = await server.handle({ jsonrpc: "2.0", id: 12, method: "tools/call", params: { name: "novel_status", arguments: [] } });
  assert.match(JSON.stringify(invalidArrayArguments), /params\.arguments must be an object/);
  const invalidTopLevelField = await server.handle({ jsonrpc: "2.0", id: 14, method: "tools/list", unexpected: true });
  assert.match(JSON.stringify(invalidTopLevelField), /JSON-RPC request\.unexpected is not a supported field/);
  const invalidToolParamsField = await server.handle({ jsonrpc: "2.0", id: 15, method: "tools/call", params: { name: "novel_status", arguments: {}, extra: true } });
  assert.match(JSON.stringify(invalidToolParamsField), /tools\/call params\.extra is not a supported field/);
  Object.defineProperty(Object.prototype, "jsonrpc", { configurable: true, value: "2.0" });
  Object.defineProperty(Object.prototype, "method", { configurable: true, value: "tools/list" });
  try {
    const inheritedProtocolFields = await server.handle({ id: 42 });
    assert.equal((inheritedProtocolFields as { id?: unknown }).id, 42);
    assert.match(JSON.stringify(inheritedProtocolFields), /JSON-RPC request\.jsonrpc is required/);
  } finally {
    delete (Object.prototype as Record<string, unknown>).jsonrpc;
    delete (Object.prototype as Record<string, unknown>).method;
  }
  Object.defineProperty(Object.prototype, "name", { configurable: true, value: "novel_health" });
  try {
    const inheritedToolName = await server.handle({ jsonrpc: "2.0", id: 43, method: "tools/call", params: { arguments: {} } });
    assert.match(JSON.stringify(inheritedToolName), /tools\/call requires params\.name/);
  } finally {
    delete (Object.prototype as Record<string, unknown>).name;
  }
  const oversizedToolName = await server.handle({ jsonrpc: "2.0", id: 18, method: "tools/call", params: { name: "x".repeat(129), arguments: {} } });
  assert.match(JSON.stringify(oversizedToolName), /params\.name must be at most 128/);
  const oversizedMultibyteToolName = await server.handle({ jsonrpc: "2.0", id: 47, method: "tools/call", params: { name: "가".repeat(43), arguments: {} } });
  assert.match(JSON.stringify(oversizedMultibyteToolName), /params\.name must be at most 128 UTF-8 bytes/);
  const unsafeToolName = await server.handle({ jsonrpc: "2.0", id: 19, method: "tools/call", params: { name: "novel_status\n", arguments: {} } });
  assert.match(JSON.stringify(unsafeToolName), /params\.name must not contain control characters/);
  const paddedToolName = await server.handle({ jsonrpc: "2.0", id: 45, method: "tools/call", params: { name: " novel_status ", arguments: {} } });
  assert.match(JSON.stringify(paddedToolName), /params\.name must not have leading or trailing whitespace/);
  let deeplyNested: Record<string, unknown> = {};
  for (let index = 0; index < 40; index += 1) {
    deeplyNested = { child: deeplyNested };
  }
  const oversizedDepth = await server.handle({ jsonrpc: "2.0", id: 20, method: "tools/list", params: deeplyNested });
  assert.match(JSON.stringify(oversizedDepth), /nested at most 32 levels/);
  const oversizedWidth = await server.handle({
    jsonrpc: "2.0",
    id: 21,
    method: "tools/list",
    params: Object.fromEntries(Array.from({ length: 101 }, (_, index) => [`field${index}`, index]))
  });
  assert.match(JSON.stringify(oversizedWidth), /at most 100 object fields/);
  const oversizedArray = await server.handle({ jsonrpc: "2.0", id: 22, method: "tools/list", params: Array.from({ length: 1001 }, () => null) });
  assert.match(JSON.stringify(oversizedArray), /at most 1000 array items/);
  const circularParams: Record<string, unknown> = {};
  circularParams.self = circularParams;
  const circular = await server.handle({ jsonrpc: "2.0", id: 23, method: "tools/list", params: circularParams });
  assert.match(JSON.stringify(circular), /circular references/);
  const undefinedField = await server.handle({ jsonrpc: "2.0", id: 24, method: "tools/list", params: { value: undefined } });
  assert.match(JSON.stringify(undefinedField), /must not be undefined/);
  const nonFiniteNumber = await server.handle({ jsonrpc: "2.0", id: 25, method: "tools/list", params: { value: Number.NaN } });
  assert.match(JSON.stringify(nonFiniteNumber), /finite number/);
  const unsafeInteger = await server.handle({ jsonrpc: "2.0", id: 26, method: "tools/list", params: { value: Number.MAX_SAFE_INTEGER + 1 } });
  assert.match(JSON.stringify(unsafeInteger), /JSON-RPC request\.params\.value must be a safe integer/);
  const oversizedMultibyteParam = await server.handle({ jsonrpc: "2.0", id: 48, method: "tools/list", params: { value: "가".repeat(6000) } });
  assert.match(JSON.stringify(oversizedMultibyteParam), /JSON-RPC request\.params\.value must be at most 16384 UTF-8 bytes/);
  const sparseParams: unknown[] = [];
  sparseParams[1] = "present";
  const sparseArray = await server.handle({ jsonrpc: "2.0", id: 29, method: "tools/list", params: { value: sparseParams } });
  assert.match(JSON.stringify(sparseArray), /sparse array hole/);
  const nonStandardArray = ["safe"];
  Object.setPrototypeOf(nonStandardArray, { inherited: "bad" });
  const nonStandardArrayProperty = await server.handle({ jsonrpc: "2.0", id: 39, method: "tools/list", params: { value: nonStandardArray } });
  assert.match(JSON.stringify(nonStandardArrayProperty), /JSON-RPC request\.params\.value must be a standard array/);
  let arrayGetterRan = false;
  const accessorArray = ["safe"];
  Object.defineProperty(accessorArray, "0", {
    enumerable: true,
    get() {
      arrayGetterRan = true;
      throw new Error("array getter must not run");
    }
  });
  const accessorArrayProperty = await server.handle({ jsonrpc: "2.0", id: 35, method: "tools/list", params: { value: accessorArray } });
  assert.equal(arrayGetterRan, false);
  assert.match(JSON.stringify(accessorArrayProperty), /non-enumerable or accessor properties/);
  const hiddenArray = ["safe"];
  Object.defineProperty(hiddenArray, "0", { value: "hidden", enumerable: false });
  const nonEnumerableArrayProperty = await server.handle({ jsonrpc: "2.0", id: 36, method: "tools/list", params: { value: hiddenArray } });
  assert.match(JSON.stringify(nonEnumerableArrayProperty), /non-enumerable or accessor properties/);
  const extraArray = ["safe"] as string[] & { extra?: string };
  extraArray.extra = "unsupported";
  const extraArrayProperty = await server.handle({ jsonrpc: "2.0", id: 37, method: "tools/list", params: { value: extraArray } });
  assert.match(JSON.stringify(extraArrayProperty), /JSON-RPC request\.params\.value\.extra is not a supported array field/);
  const symbolArray = ["safe"];
  Object.defineProperty(symbolArray, Symbol("hidden"), {
    enumerable: true,
    value: "unsupported"
  });
  const symbolArrayProperty = await server.handle({ jsonrpc: "2.0", id: 38, method: "tools/list", params: { value: symbolArray } });
  assert.match(JSON.stringify(symbolArrayProperty), /JSON-RPC request\.params\.value must not contain symbol properties/);
  const dateValue = await server.handle({ jsonrpc: "2.0", id: 30, method: "tools/list", params: { value: new Date("2026-06-24T00:00:00.000Z") } });
  assert.match(JSON.stringify(dateValue), /plain JSON object/);
  const symbolParams: Record<string | symbol, unknown> = { value: true };
  symbolParams[Symbol("hidden")] = "secret";
  const symbolProperty = await server.handle({ jsonrpc: "2.0", id: 31, method: "tools/list", params: symbolParams });
  assert.match(JSON.stringify(symbolProperty), /symbol properties/);
  const hiddenParams = Object.defineProperty({ value: true }, "hidden", { value: "secret", enumerable: false });
  const nonEnumerableProperty = await server.handle({ jsonrpc: "2.0", id: 32, method: "tools/list", params: hiddenParams });
  assert.match(JSON.stringify(nonEnumerableProperty), /non-enumerable or accessor properties/);
  const accessorParams = Object.defineProperty({ value: true }, "danger", {
    enumerable: true,
    get() {
      throw new Error("getter must not run");
    }
  });
  const accessorProperty = await server.handle({ jsonrpc: "2.0", id: 33, method: "tools/list", params: accessorParams });
  assert.match(JSON.stringify(accessorProperty), /non-enumerable or accessor properties/);
  const reflectionSecret = "Authorization: Bearer json-rpc-reflection-secret";
  const assertWrappedReflectionError = async (request: unknown, expected: RegExp): Promise<void> => {
    const response = await server.handle(request);
    const text = JSON.stringify(response);
    assert.match(text, expected);
    assert.equal(text.includes(reflectionSecret), false);
  };
  await assertWrappedReflectionError(new Proxy({ jsonrpc: "2.0", id: 51, method: "tools/list", params: {} }, {
    getPrototypeOf() {
      throw new Error(`leaked JSON-RPC request prototype trap ${reflectionSecret}`);
    }
  }), /JSON-RPC request prototype must be readable/);
  const descriptorTrapResponse = await server.handle(new Proxy({ jsonrpc: "2.0", id: 57, method: "tools/list", params: {} }, {
    getOwnPropertyDescriptor() {
      throw new Error(`leaked JSON-RPC request fallback descriptor trap ${reflectionSecret}`);
    }
  }));
  assert.equal(descriptorTrapResponse, undefined);
  await assertWrappedReflectionError({ jsonrpc: "2.0", id: 52, method: "tools/list", params: new Proxy({ value: true }, {
    ownKeys() {
      throw new Error(`leaked JSON-RPC params keys trap ${reflectionSecret}`);
    }
  }) }, /JSON-RPC request\.params keys must be readable/);
  await assertWrappedReflectionError({ jsonrpc: "2.0", id: 53, method: "tools/list", params: new Proxy({ value: true }, {
    getOwnPropertyDescriptor() {
      throw new Error(`leaked JSON-RPC params descriptor trap ${reflectionSecret}`);
    }
  }) }, /JSON-RPC request\.params property descriptors must be readable/);
  await assertWrappedReflectionError({ jsonrpc: "2.0", id: 54, method: "tools/list", params: { value: new Proxy(["safe"], {
    getPrototypeOf() {
      throw new Error(`leaked JSON-RPC array prototype trap ${reflectionSecret}`);
    }
  }) } }, /JSON-RPC request\.params\.value prototype must be readable/);
  await assertWrappedReflectionError({ jsonrpc: "2.0", id: 55, method: "tools/list", params: { value: new Proxy(["safe"], {
    ownKeys() {
      throw new Error(`leaked JSON-RPC array keys trap ${reflectionSecret}`);
    }
  }) } }, /JSON-RPC request\.params\.value keys must be readable/);
  await assertWrappedReflectionError({ jsonrpc: "2.0", id: 56, method: "tools/list", params: { value: new Proxy(["safe"], {
    getOwnPropertyDescriptor() {
      throw new Error(`leaked JSON-RPC array descriptor trap ${reflectionSecret}`);
    }
  }) } }, /JSON-RPC request\.params\.value property descriptors must be readable/);
  let topLevelGetterRan = false;
  const accessorTopLevelRequest = Object.defineProperties({}, {
    jsonrpc: { enumerable: true, value: "2.0" },
    id: {
      enumerable: true,
      get() {
        topLevelGetterRan = true;
        throw new Error("top-level id getter must not run");
      }
    },
    method: {
      enumerable: true,
      get() {
        topLevelGetterRan = true;
        throw new Error("top-level method getter must not run");
      }
    }
  });
  const accessorTopLevel = await server.handle(accessorTopLevelRequest);
  assert.equal(topLevelGetterRan, false);
  assert.equal((accessorTopLevel as { id: unknown }).id, null);
  assert.match(JSON.stringify(accessorTopLevel), /non-enumerable or accessor properties/);
  const sharedParams = { value: true };
  const sharedReference = await server.handle({
    jsonrpc: "2.0",
    id: 34,
    method: "tools/list",
    params: { first: sharedParams, second: sharedParams }
  });
  assert.equal((sharedReference as { result?: unknown }).result !== undefined, true);
  const oversizedNestedString = await server.handle({
    jsonrpc: "2.0",
    id: 26,
    method: "tools/list",
    params: { value: "x".repeat(16 * 1024 + 1) }
  });
  assert.match(JSON.stringify(oversizedNestedString), /at most 16384 characters/);
  const unsafeNestedString = await server.handle({
    jsonrpc: "2.0",
    id: 39,
    method: "tools/list",
    params: { value: "unsafe\u0001value" }
  });
  assert.match(JSON.stringify(unsafeNestedString), /must not contain non-printing control characters/);
  const multilineNestedString = await server.handle({
    jsonrpc: "2.0",
    id: 40,
    method: "tools/list",
    params: { value: "첫 줄\n둘째 줄\t탭" }
  });
  assert.equal((multilineNestedString as { result?: unknown }).result !== undefined, true);
  const oversizedObjectKey = await server.handle({
    jsonrpc: "2.0",
    id: 27,
    method: "tools/list",
    params: { ["x".repeat(257)]: true }
  });
  assert.match(JSON.stringify(oversizedObjectKey), /object keys must be at most 256 characters/);
  const oversizedMultibyteObjectKey = await server.handle({
    jsonrpc: "2.0",
    id: 42,
    method: "tools/list",
    params: { ["가".repeat(180)]: true }
  });
  assert.match(JSON.stringify(oversizedMultibyteObjectKey), /object keys must be at most 512 UTF-8 bytes/);
  let oversizedKeyGetterRan = false;
  const oversizedAccessorKeyParams = Object.defineProperty({}, "x".repeat(257), {
    enumerable: true,
    get() {
      oversizedKeyGetterRan = true;
      throw new Error("oversized key getter must not run");
    }
  });
  const oversizedAccessorKey = await server.handle({
    jsonrpc: "2.0",
    id: 41,
    method: "tools/list",
    params: oversizedAccessorKeyParams
  });
  assert.equal(oversizedKeyGetterRan, false);
  assert.match(JSON.stringify(oversizedAccessorKey), /object keys must be at most 256 characters/);
  const unsafeObjectKey = await server.handle({
    jsonrpc: "2.0",
    id: 28,
    method: "tools/list",
    params: { "unsafe\nkey": true }
  });
  assert.match(JSON.stringify(unsafeObjectKey), /object keys must not contain control characters/);

  const created = await server.handle({
    jsonrpc: "2.0",
    id: 2,
    method: "tools/call",
    params: {
      name: "novel_new_project",
      arguments: {
        franchiseName: "MCP 세계",
        workRequest: "MCP 작품"
      }
    }
  });
  const serialized = JSON.stringify(created);
  assert.match(serialized, /pending_user_confirmation/);
  assert.match(serialized, /confirmationId/);

  const health = await server.handle({
    jsonrpc: "2.0",
    id: 3,
    method: "tools/call",
    params: {
      name: "novel_health",
      arguments: {}
    }
  });
  assert.match(JSON.stringify(health), /Novelist MCP server is healthy/);

  const jobStarted = await server.handle({
    jsonrpc: "2.0",
    id: 4,
    method: "tools/call",
    params: {
      name: "novel_job_start",
      arguments: {
        toolName: "novel_new_project",
        args: {
          franchiseName: "MCP 작업 세계",
          workRequest: "MCP 작업 작품"
        }
      }
    }
  });
  const jobId = (extractToolPayload(jobStarted).data as { jobId: string }).jobId;
  assert.match(jobId, /^job-/);

  const jobStatus = await server.handle({
    jsonrpc: "2.0",
    id: 5,
    method: "tools/call",
    params: {
      name: "novel_job_status",
      arguments: { jobId }
    }
  });
  assert.match(JSON.stringify(jobStatus), /Job status/);

  const jobList = await server.handle({
    jsonrpc: "2.0",
    id: 6,
    method: "tools/call",
    params: {
      name: "novel_job_list",
      arguments: {}
    }
  });
  const listed = extractToolPayload(jobList).data as { count: number; jobs: Array<{ jobId: string }> };
  assert.equal(listed.count, 1);
  assert.equal(listed.jobs[0]?.jobId, jobId);
});

test("MCP tools/list returns isolated schema copies per request", async () => {
  const server = new McpServer(pipelineInTemp(), new Logger("silent"));
  const first = await server.handle({ jsonrpc: "2.0", id: 1, method: "tools/list" });
  const firstTools = (first as { result?: { tools?: Array<{ name?: string; inputSchema?: Record<string, unknown> }> } }).result?.tools;
  if (!firstTools?.[0]) {
    throw new Error("Expected tools/list to return at least one tool.");
  }
  const originalName = firstTools[0].name;
  firstTools[0].name = "mutated_tool";
  firstTools[0].inputSchema = { mutated: true };

  const second = await server.handle({ jsonrpc: "2.0", id: 2, method: "tools/list" });
  const secondTools = (second as { result?: { tools?: Array<{ name?: string; inputSchema?: Record<string, unknown> }> } }).result?.tools;

  assert.equal(secondTools?.[0]?.name, originalName);
  assert.ok(secondTools?.[0]?.inputSchema !== firstTools[0].inputSchema);
  assert.equal(Boolean(secondTools?.[0]?.inputSchema?.mutated), false);
});

test("MCP tools/list clones schemas without invoking polluted toJSON prototypes", async () => {
  const server = new McpServer(pipelineInTemp(), new Logger("silent"));
  const objectHadToJson = Object.prototype.hasOwnProperty.call(Object.prototype, "toJSON");
  const arrayHadToJson = Object.prototype.hasOwnProperty.call(Array.prototype, "toJSON");
  const originalObjectToJson = (Object.prototype as { toJSON?: unknown }).toJSON;
  const originalArrayToJson = (Array.prototype as { toJSON?: unknown }).toJSON;
  let objectToJsonRan = false;
  let arrayToJsonRan = false;
  let response: unknown;

  try {
    Object.defineProperty(Object.prototype, "toJSON", {
      configurable: true,
      value() {
        objectToJsonRan = true;
        return { name: "polluted_tool", inputSchema: { polluted: true } };
      }
    });
    Object.defineProperty(Array.prototype, "toJSON", {
      configurable: true,
      value() {
        arrayToJsonRan = true;
        return [{ name: "polluted_array_tool", inputSchema: { polluted: true } }];
      }
    });
    response = await server.handle({ jsonrpc: "2.0", id: 119, method: "tools/list" });
  } finally {
    if (objectHadToJson) {
      Object.defineProperty(Object.prototype, "toJSON", {
        value: originalObjectToJson,
        configurable: true,
        writable: true
      });
    } else {
      delete (Object.prototype as { toJSON?: unknown }).toJSON;
    }
    if (arrayHadToJson) {
      Object.defineProperty(Array.prototype, "toJSON", {
        value: originalArrayToJson,
        configurable: true,
        writable: true
      });
    } else {
      delete (Array.prototype as { toJSON?: unknown }).toJSON;
    }
  }

  const listedResponse = JSON.parse(JSON.stringify(response)) as { result?: { tools?: Array<{ name?: string; inputSchema?: Record<string, unknown> }> } };
  const listedTools = listedResponse.result?.tools ?? [];

  assert.equal(objectToJsonRan, false);
  assert.equal(arrayToJsonRan, false);
  assert.equal(listedTools.some((tool) => tool.name === "novel_new_project"), true);
  assert.equal(listedTools.some((tool) => tool.name === "polluted_tool" || tool.name === "polluted_array_tool"), false);
});

