test("MCP tool schemas expose closed non-empty inputs", async () => {
  const server = new McpServer(pipelineInTemp(), new Logger("silent"));
  const response = await server.handle({ jsonrpc: "2.0", id: 9, method: "tools/list" });
  const listedResponse = JSON.parse(JSON.stringify(response)) as { result?: { tools?: Array<{ name: string; inputSchema: ToolSchema }> } };
  const tools = listedResponse.result?.tools ?? [];
  const newProject = tools.find((tool) => tool.name === "novel_new_project")?.inputSchema;
  const confirm = tools.find((tool) => tool.name === "novel_confirm")?.inputSchema;
  const jobStart = tools.find((tool) => tool.name === "novel_job_start")?.inputSchema;
  const jobList = tools.find((tool) => tool.name === "novel_job_list")?.inputSchema;
  const status = tools.find((tool) => tool.name === "novel_status")?.inputSchema;
  const revise = tools.find((tool) => tool.name === "novel_revise")?.inputSchema;
  const jobNewProject = jobStart?.oneOf?.find((schema) => schema.properties?.toolName?.enum?.[0] === "novel_new_project");
  const jobConfirm = jobStart?.oneOf?.find((schema) => schema.properties?.toolName?.enum?.[0] === "novel_confirm");
  const jobContinue = jobStart?.oneOf?.find((schema) => schema.properties?.toolName?.enum?.[0] === "novel_continue");

  assert.equal(newProject?.additionalProperties, false);
  assert.equal(jobList?.properties?.status?.minLength, 1);
  assert.equal(jobList?.properties?.limit?.maximum, 1000);
  assert.equal(jobList?.properties?.offset?.minimum, 0);
  assert.equal(newProject?.properties?.franchiseName?.minLength, 1);
  assert.equal(newProject?.properties?.franchiseName?.maxLength, 512);
  assert.equal(newProject?.properties?.franchiseName?.["x-maxUtf8Bytes"], 512);
  assert.match(newProject?.properties?.franchiseName?.pattern ?? "", /\\u001f/);
  assert.equal(new RegExp(newProject?.properties?.franchiseName?.pattern ?? "", "u").test("   "), false);
  assert.equal(new RegExp(newProject?.properties?.franchiseName?.pattern ?? "", "u").test("MCP 세계"), true);
  assert.equal(newProject?.properties?.genre?.maxLength, 256);
  assert.equal(newProject?.properties?.genre?.["x-maxUtf8Bytes"], 256);
  assert.match(newProject?.properties?.genre?.pattern ?? "", /\\u001f/);
  assert.equal(confirm?.oneOf?.length, 2);
  assert.deepEqual(confirm?.oneOf?.[0]?.properties?.approved?.enum, [true]);
  assert.deepEqual(confirm?.oneOf?.[1]?.required, ["revisionInstruction"]);
  assert.deepEqual(confirm?.oneOf?.[1]?.properties?.approved?.enum, [false]);
  assert.equal(status?.properties?.franchiseId?.minLength, 1);
  assert.equal(status?.properties?.franchiseId?.maxLength, 120);
  assert.equal(status?.properties?.franchiseId?.["x-maxUtf8Bytes"], 120);
  assert.match(status?.properties?.franchiseId?.pattern ?? "", /\(\?!\.\*\\\.\\\.\)/);
  assert.match(status?.properties?.franchiseId?.description ?? "", /120 UTF-8 bytes/);
  assert.equal(status?.anyOf?.length, 3);
  assert.deepEqual(status?.anyOf?.[0]?.not?.anyOf?.map((schema) => schema.required?.[0]), ["franchiseId", "workId", "volumeId", "current"]);
  assert.deepEqual(status?.anyOf?.[1]?.required, ["current"]);
  assert.deepEqual(status?.anyOf?.[1]?.properties?.current?.enum, [true]);
  assert.deepEqual(status?.anyOf?.[2]?.required, ["franchiseId", "workId", "volumeId"]);
  assert.deepEqual(status?.anyOf?.[2]?.properties?.current?.enum, [false]);
  assert.equal(revise?.properties?.instruction?.minLength, 1);
  assert.equal(revise?.properties?.instruction?.maxLength, 16 * 1024);
  assert.equal(revise?.properties?.instruction?.["x-maxUtf8Bytes"], 16 * 1024);
  assert.match(revise?.properties?.instruction?.pattern ?? "", /\\u0008/);
  assert.equal(new RegExp(revise?.properties?.instruction?.pattern ?? "", "u").test("\n\t  "), false);
  assert.equal(new RegExp(revise?.properties?.instruction?.pattern ?? "", "u").test("첫 줄\n둘째 줄"), true);
  assert.match(revise?.properties?.target?.pattern ?? "", /\[Cc\]\[Hh\]\[Aa\]\[Pp\]\[Tt\]\[Ee\]\[Rr\]:/);
  assert.match(revise?.properties?.target?.description ?? "", /<chapter>-<beat>/);
  assert.equal(revise?.properties?.target?.["x-maxUtf8Bytes"], 256);
  const reviseTargetPattern = new RegExp(revise?.properties?.target?.pattern ?? "", "u");
  assert.equal(reviseTargetPattern.test("chapter:1,beat:2"), true);
  assert.equal(reviseTargetPattern.test("chapter:1 beat:2"), true);
  assert.equal(reviseTargetPattern.test("Chapter:1,Beat:2"), true);
  assert.equal(reviseTargetPattern.test("chapter:1\tbeat:2"), false);
  assert.equal(reviseTargetPattern.test("1-2"), true);
  assert.equal(reviseTargetPattern.test("1/2"), true);
  assert.equal(reviseTargetPattern.test("chapter:0,beat:1"), false);
  assert.equal(reviseTargetPattern.test("1"), false);
  assert.equal(reviseTargetPattern.test("chapter:1,\nbeat:2"), false);
  assert.equal(jobStart?.oneOf?.length, 5);
  assert.deepEqual(jobNewProject?.required, ["toolName", "args"]);
  assert.deepEqual(jobNewProject?.properties?.args?.required, ["franchiseName", "workRequest"]);
  assert.equal(jobNewProject?.properties?.args?.additionalProperties, false);
  assert.deepEqual(jobConfirm?.properties?.args?.oneOf?.[1]?.required, ["revisionInstruction"]);
  assert.deepEqual(jobContinue?.required, ["toolName"]);
  assert.equal(jobContinue?.properties?.args?.properties?.current?.type, "boolean");
  assert.equal(jobContinue?.properties?.args?.anyOf?.length, 3);
  assert.deepEqual(jobContinue?.properties?.args?.anyOf?.[0]?.not?.anyOf?.map((schema) => schema.required?.[0]), ["franchiseId", "workId", "volumeId", "current"]);
  assert.deepEqual(jobContinue?.properties?.args?.anyOf?.[1]?.required, ["current"]);
  assert.deepEqual(jobContinue?.properties?.args?.anyOf?.[1]?.properties?.current?.enum, [true]);
});

test("README tool list matches MCP tools/list names", async () => {
  const server = new McpServer(pipelineInTemp(), new Logger("silent"));
  const response = await server.handle({ jsonrpc: "2.0", id: 910, method: "tools/list" });
  const listedResponse = JSON.parse(JSON.stringify(response)) as { result?: { tools?: Array<{ name?: unknown }> } };
  const toolNames = (listedResponse.result?.tools ?? [])
    .map((tool) => tool.name)
    .filter((name): name is string => typeof name === "string")
    .sort();
  const readme = await readFile(join(process.cwd(), "README.md"), "utf8");
  const toolsSection = readme.match(/## Tools\n(?<section>[\s\S]*?)\n## /u)?.groups?.section;
  if (toolsSection === undefined) {
    throw new Error("README must contain a Tools section before the next heading.");
  }
  const documentedToolNames = Array.from(toolsSection.matchAll(/^- `(?<name>novel_[a-z_]+)`:/gmu), (match) => match.groups?.name ?? "").sort();

  assert.deepEqual(documentedToolNames, toolNames);
});

test("MCP waits for persisted job recovery before serving job tools", async () => {
  const storage = new SlowJobStorage(testRoot("novelist-mcp-ready-test"), 20);
  const jobId = "job-ready";
  const finishedAt = new Date().toISOString();
  await storage.writeJob(jobId, {
    jobId,
    toolName: "novel_continue",
    status: "succeeded",
    createdAt: finishedAt,
	    startedAt: finishedAt,
	    finishedAt,
	    cancelRequested: false,
	    result: { status: "ok", message: "ready" },
	    args: { current: true }
	  });
  const server = new McpServer(new NovelPipeline(storage), new Logger("silent"), storage);
  let resolved = false;

  const responsePromise = server.handle({
    jsonrpc: "2.0",
    id: 77,
    method: "tools/call",
    params: {
      name: "novel_job_status",
      arguments: { jobId }
    }
  }).then((response) => {
    resolved = true;
    return response;
  });
  await delay(5);
  assert.equal(resolved, false);

  const response = await responsePromise;
  const payload = extractToolPayload(response) as { status: string; data?: unknown };
  assert.equal((payload.data as { jobId: string; status: string }).jobId, jobId);
  assert.equal((payload.data as { status: string }).status, "succeeded");
});

