test("CLI argument parser validates direct argument arrays without invoking getters", () => {
  assert.equal(parseCliArgs([]), "start");
  assert.equal(parseCliArgs(["--help"]), "help");
  assert.equal(parseCliArgs(["-v"]), "version");
  assert.throws(() => parseCliArgs(null), /CLI arguments must be an array/);
  assert.throws(() => parseCliArgs(Array.from({ length: 257 }, () => "x")), /at most 256 items/);
  assert.throws(() => parseCliArgs(["x".repeat(8193)]), /at most 8192 characters/);
  assert.throws(() => parseCliArgs(["가".repeat(2731)]), /CLI arguments\[0\] must be at most 8192 UTF-8 bytes/);
  assert.throws(() => parseCliArgs(["--help\n"]), /CLI arguments\[0\] must not contain control characters/);

  const sparse = new Array<string>(1);
  assert.throws(() => parseCliArgs(sparse), /CLI arguments\[0\] must not be a sparse array hole/);

  const nonStandard = ["--help"];
  Object.setPrototypeOf(nonStandard, { inherited: "bad" });
  assert.throws(() => parseCliArgs(nonStandard), /CLI arguments must be a standard array/);

  const extra = ["--help"] as string[] & { extra?: string };
  extra.extra = "bad";
  assert.throws(() => parseCliArgs(extra), /CLI arguments\.extra is not a supported array field/);

  const symbolArgs = ["--help"] as unknown as Array<string> & Record<symbol, string>;
  symbolArgs[Symbol("cli")] = "bad";
  assert.throws(() => parseCliArgs(symbolArgs), /CLI arguments must not contain symbol properties/);

  let getterRan = false;
  const accessor = ["--help"];
  Object.defineProperty(accessor, "0", {
    enumerable: true,
    get() {
      getterRan = true;
      throw new Error("CLI arg getter must not run");
    }
  });
  assert.throws(() => parseCliArgs(accessor), /CLI arguments\[0\] must be an enumerable data item/);
  assert.equal(getterRan, false);
});

test("CLI argument parser wraps unreadable reflection failures", () => {
  const secret = "Authorization: Bearer cli-args-secret";
  const assertWrapped = (args: unknown, expected: RegExp): void => {
    assert.throws(() => parseCliArgs(args), expected);
    try {
      parseCliArgs(args);
    } catch (error) {
      assert.doesNotMatch(String(error), new RegExp(secret));
      return;
    }
    throw new Error("expected CLI argument validation failure");
  };

  assertWrapped(new Proxy(["--help"], {
    getPrototypeOf() {
      throw new Error(`leaked CLI prototype trap ${secret}`);
    }
  }), /CLI arguments prototype must be readable/);

  assertWrapped(new Proxy(["--help"], {
    ownKeys() {
      throw new Error(`leaked CLI keys trap ${secret}`);
    }
  }), /CLI arguments property keys must be readable/);

  assertWrapped(new Proxy(["--help"], {
    getOwnPropertyDescriptor() {
      throw new Error(`leaked CLI descriptor trap ${secret}`);
    }
  }), /CLI arguments property descriptors must be readable/);
});

