test("startup error formatter redacts inline secrets and bounds output", () => {
  const message = startupErrorMessage(
    new Error(`failed\u0001with\nAuthorization:\tbearer startup-secret-token and sk-startupsecret ${"x".repeat(5000)}`)
  );

  assert.equal(/[\u0000-\u001f\u007f]/u.test(message), false);
  assert.match(message, /failed with Authorization:/);
  assert.equal(message.includes("startup-secret-token"), false);
  assert.equal(message.includes("sk-startupsecret"), false);
  assert.match(message, /Bearer \[Redacted\]/);
  assert.match(message, /sk-\[Redacted\]/);
  assert.match(message, /truncated/);
  assert.ok(message.length < 4100);

  let startupToStringRan = false;
  const unstringifiable = startupErrorMessage({
    toString() {
      startupToStringRan = true;
      throw new Error("startup formatter leaked Authorization: Bearer startup-tostring-secret");
    }
  });
  assert.equal(unstringifiable, "[Object]");
  assert.equal(startupToStringRan, false);

  let startupMessageGetterRan = false;
  const accessorStartupError = new Error("safe");
  Object.defineProperty(accessorStartupError, "message", {
    enumerable: true,
    get() {
      startupMessageGetterRan = true;
      throw new Error("startup formatter message getter must not run");
    }
  });
  assert.equal(startupErrorMessage(accessorStartupError), "[Object]");
  assert.equal(startupMessageGetterRan, false);
});

