test("startup error JSON line ignores polluted toJSON prototypes", () => {
  const objectToJson = Object.getOwnPropertyDescriptor(Object.prototype, "toJSON");
  let line = "";
  try {
    Object.defineProperty(Object.prototype, "toJSON", {
      configurable: true,
      value: () => ({
        level: "info",
        event: "polluted_startup_event",
        error: "polluted sk-startup-json-secret"
      })
    });
    line = startupErrorJsonLine(new Error("startup failed Authorization: Bearer startup-json-secret"));
  } finally {
    if (objectToJson) {
      Object.defineProperty(Object.prototype, "toJSON", objectToJson);
    } else {
      delete (Object.prototype as { toJSON?: unknown }).toJSON;
    }
  }

  const entry = JSON.parse(line) as { level?: string; event?: string; error?: string };
  assert.equal(line.endsWith("\n"), true);
  assert.equal(entry.level, "error");
  assert.equal(entry.event, "novelist_startup_failed");
  assert.match(entry.error ?? "", /startup failed Authorization: Bearer \[Redacted\]/);
  assert.equal(line.includes("polluted_startup_event"), false);
  assert.equal(line.includes("startup-json-secret"), false);
  assert.equal(line.includes("sk-startup-json-secret"), false);
});

test("stdio processor serializes requests and flushes trailing input on EOF", async () => {
  const output: string[] = [];
  const calls: Array<string | number | null | undefined> = [];
  const processor = new StdioLineProcessor(
    {
      async handle(request: { id?: string | number | null; method: string }) {
        calls.push(request.id);
        if (request.id === 1) {
          await delay(20);
        }
        return { jsonrpc: "2.0", id: request.id ?? null, result: { method: request.method } };
      }
    },
    (line) => {
      output.push(line);
    }
  );

  processor.push('{"jsonrpc":"2.0","id":1,"method":"slow"}\n{"jsonrpc":"2.0","id":2,"method":"fast"}');
  processor.end();
  await processor.drain();

  assert.deepEqual(calls, [1, 2]);
  assert.equal(JSON.parse(output[0] ?? "{}").id, 1);
  assert.equal(JSON.parse(output[1] ?? "{}").id, 2);
});

test("stdio processor rejects invalid direct line length options", () => {
  const handler = { async handle() { return undefined; } };
  const write = () => undefined;
  let getterRan = false;
  const accessorOptions = Object.create(null) as { maxLineLength?: unknown };
  Object.defineProperty(accessorOptions, "maxLineLength", {
    enumerable: true,
    get() {
      getterRan = true;
      throw new Error("stdio options getter must not run");
    }
  });
  const hiddenOptions = Object.create(null) as { maxLineLength?: unknown };
  Object.defineProperty(hiddenOptions, "maxLineLength", {
    enumerable: false,
    value: 512
  });
  const symbolOptions = { maxLineLength: 512 } as Record<string | symbol, unknown>;
  symbolOptions[Symbol("maxLineLength")] = 512;

  assert.throws(
    () => new StdioLineProcessor(handler, write, { maxLineLength: Number.NaN }),
    /StdioLineProcessor\.maxLineLength must be an integer/
  );
  assert.throws(
    () => new StdioLineProcessor(handler, write, { maxLineLength: 255 }),
    /StdioLineProcessor\.maxLineLength must be between 256 and 16777216/
  );
  assert.throws(
    () => new StdioLineProcessor(handler, write, { maxLineLength: 16 * 1024 * 1024 + 1 }),
    /StdioLineProcessor\.maxLineLength must be between 256 and 16777216/
  );
  assert.throws(
    () => new StdioLineProcessor(handler, write, accessorOptions as unknown as ConstructorParameters<typeof StdioLineProcessor>[2]),
    /StdioLineProcessor\.options must not contain non-enumerable or accessor properties/
  );
  assert.equal(getterRan, false);
  assert.throws(
    () => new StdioLineProcessor(handler, write, hiddenOptions as unknown as ConstructorParameters<typeof StdioLineProcessor>[2]),
    /StdioLineProcessor\.options must not contain non-enumerable or accessor properties/
  );
  assert.throws(
    () => new StdioLineProcessor(handler, write, { maxLineLength: 512, extra: true } as unknown as ConstructorParameters<typeof StdioLineProcessor>[2]),
    /StdioLineProcessor\.options\.extra is not a supported field/
  );
  assert.throws(
    () => new StdioLineProcessor(handler, write, new Date() as unknown as ConstructorParameters<typeof StdioLineProcessor>[2]),
    /StdioLineProcessor\.options must be a plain object/
  );
  assert.throws(
    () => new StdioLineProcessor(handler, write, symbolOptions as unknown as ConstructorParameters<typeof StdioLineProcessor>[2]),
    /StdioLineProcessor\.options must not contain symbol properties/
  );
  const secret = "Authorization: Bearer stdio-options-secret";
  const assertWrappedOptionsError = (options: ConstructorParameters<typeof StdioLineProcessor>[2], expected: RegExp): void => {
    assert.throws(() => new StdioLineProcessor(handler, write, options), expected);
    try {
      new StdioLineProcessor(handler, write, options);
    } catch (error) {
      assert.doesNotMatch(String(error), new RegExp(secret));
      return;
    }
    throw new Error("expected stdio options validation failure");
  };
  assertWrappedOptionsError(new Proxy({ maxLineLength: 512 }, {
    getPrototypeOf() {
      throw new Error(`leaked stdio options prototype trap ${secret}`);
    }
  }), /StdioLineProcessor\.options prototype must be readable/);
  assertWrappedOptionsError(new Proxy({ maxLineLength: 512 }, {
    ownKeys() {
      throw new Error(`leaked stdio options keys trap ${secret}`);
    }
  }), /StdioLineProcessor\.options keys must be readable/);
  assertWrappedOptionsError(new Proxy({ maxLineLength: 512 }, {
    getOwnPropertyDescriptor() {
      throw new Error(`leaked stdio options descriptor trap ${secret}`);
    }
  }), /StdioLineProcessor\.options property descriptors must be readable/);
});

