test("stdio processor bounds queued request lines and recovers after draining", async () => {
  const output: string[] = [];
  const calls: Array<string | number | null | undefined> = [];
  let releaseFirst: (() => void) | undefined;
  const firstBlocked = new Promise<void>((resolveBlocked) => {
    releaseFirst = resolveBlocked;
  });
  const processor = new StdioLineProcessor(
    {
      async handle(request: { id?: string | number | null }) {
        calls.push(request.id);
        if (request.id === 1) {
          await firstBlocked;
        }
        return { jsonrpc: "2.0", id: request.id ?? null, result: {} };
      }
    },
    (line) => {
      output.push(line);
    },
    { maxLineLength: 256 }
  );

  for (let index = 1; index <= 1001; index += 1) {
    processor.push(`{"jsonrpc":"2.0","id":${index},"method":"queued"}\n`);
  }

  const queueError = JSON.parse(output[0] ?? "{}") as { id: null; error: { code: number; message: string } };
  assert.equal(queueError.id, null);
  assert.equal(queueError.error.code, -32000);
  assert.match(queueError.error.message, /queue exceeds 1000 pending lines/);

  releaseFirst?.();
  await processor.drain();
  processor.push('{"jsonrpc":"2.0","id":1002,"method":"after-drain"}\n');
  await processor.drain();

  assert.equal(calls.length, 1001);
  assert.equal(calls.includes(1001), false);
  assert.equal(calls.includes(1002), true);
});

