test("shutdown helper drains once and suppresses shutdown failures", async () => {
  let drained = 0;
  let shutdowns = 0;
  const shutdownOnce = createShutdownOnce(
    {
      async shutdown() {
        shutdowns += 1;
        throw new Error("shutdown failed");
      }
    },
    async () => {
      drained += 1;
    }
  );

  await Promise.all([shutdownOnce(), shutdownOnce(), shutdownOnce()]);

  assert.equal(drained, 1);
  assert.equal(shutdowns, 1);
});

