test("shutdown helper rejects invalid direct server and hook inputs", () => {
  let getterRan = false;
  const accessorServer = Object.create(null) as { shutdown?: unknown };
  Object.defineProperty(accessorServer, "shutdown", {
    enumerable: true,
    get() {
      getterRan = true;
      throw new Error("shutdown getter must not run");
    }
  });

  assert.throws(
    () => createShutdownOnce(null as unknown as Parameters<typeof createShutdownOnce>[0]),
    /shutdown server must be an object/
  );
  assert.throws(
    () => createShutdownOnce({ shutdown: "nope" } as unknown as Parameters<typeof createShutdownOnce>[0]),
    /shutdown server\.shutdown must be a data function/
  );
  assert.throws(
    () => createShutdownOnce(accessorServer as unknown as Parameters<typeof createShutdownOnce>[0]),
    /shutdown server\.shutdown must be a data function/
  );
  assert.equal(getterRan, false);
  assert.throws(
    () => createShutdownOnce({ async shutdown() { return undefined; } }, null as unknown as Parameters<typeof createShutdownOnce>[1]),
    /beforeShutdown must be a function/
  );
});

test("MCP server rejects invalid direct constructor inputs without invoking getters", () => {
  const storage = new NovelStorage(testRoot("novelist-mcp-constructor-validation-test"));
  const pipeline = new NovelPipeline(storage);
  const logger = new Logger("silent");
  let pipelineGetterRan = false;
  const accessorPipeline = Object.create(pipeline) as NovelPipeline;
  Object.defineProperty(accessorPipeline, "health", {
    enumerable: true,
    get() {
      pipelineGetterRan = true;
      throw new Error("mcp pipeline getter must not run");
    }
  });
  let loggerGetterRan = false;
  const accessorLogger = Object.create(logger) as Logger;
  Object.defineProperty(accessorLogger, "info", {
    enumerable: true,
    get() {
      loggerGetterRan = true;
      throw new Error("mcp logger getter must not run");
    }
  });
  let storageGetterRan = false;
  const accessorStorage = Object.create(storage) as NovelStorage;
  Object.defineProperty(accessorStorage, "root", {
    enumerable: true,
    get() {
      storageGetterRan = true;
      throw new Error("mcp storage getter must not run");
    }
  });

  assert.throws(
    () => new McpServer(null as unknown as ConstructorParameters<typeof McpServer>[0], logger),
    /McpServer\.pipeline must be an object/
  );
  const constructorSecret = "Authorization: Bearer mcp-constructor-secret";
  const assertWrappedConstructorError = (operation: () => unknown, expected: RegExp): void => {
    assert.throws(operation, expected);
    try {
      operation();
    } catch (error) {
      assert.doesNotMatch(String(error), new RegExp(constructorSecret));
      return;
    }
    throw new Error("expected MCP constructor validation failure");
  };
  assertWrappedConstructorError(
    () => new McpServer(new Proxy(pipeline, {
      getPrototypeOf() {
        throw new Error(`leaked mcp pipeline prototype trap ${constructorSecret}`);
      }
    }), logger),
    /McpServer\.pipeline prototype must be readable/
  );
  assertWrappedConstructorError(
    () => new McpServer(new Proxy(pipeline, {
      ownKeys() {
        throw new Error(`leaked mcp pipeline keys trap ${constructorSecret}`);
      }
    }), logger),
    /McpServer\.pipeline keys must be readable/
  );
  assertWrappedConstructorError(
    () => new McpServer(new Proxy(pipeline, {
      getOwnPropertyDescriptor() {
        throw new Error(`leaked mcp pipeline descriptor trap ${constructorSecret}`);
      }
    }), logger),
    /McpServer\.pipeline property descriptors must be readable/
  );
  assertWrappedConstructorError(
    () => new McpServer(pipeline, new Proxy(logger, {
      ownKeys() {
        throw new Error(`leaked mcp logger keys trap ${constructorSecret}`);
      }
    })),
    /McpServer\.logger keys must be readable/
  );
  assertWrappedConstructorError(
    () => new McpServer(pipeline, logger, new Proxy(storage, {
      getOwnPropertyDescriptor() {
        throw new Error(`leaked mcp storage descriptor trap ${constructorSecret}`);
      }
    })),
    /McpServer\.storage property descriptors must be readable/
  );
  const datePipeline = Object.assign(new Date(), {
    newProject: pipeline.newProject.bind(pipeline),
    health: pipeline.health.bind(pipeline),
    confirm: pipeline.confirm.bind(pipeline),
    continue: pipeline.continue.bind(pipeline),
    status: pipeline.status.bind(pipeline),
    revise: pipeline.revise.bind(pipeline),
    buildEpub: pipeline.buildEpub.bind(pipeline)
  }) as unknown as NovelPipeline;
  assert.throws(
    () => new McpServer(datePipeline, logger),
    /McpServer\.pipeline must be a NovelPipeline instance/
  );
  assert.throws(
    () => new McpServer(accessorPipeline, logger),
    /McpServer\.pipeline\.health must be a data function/
  );
  assert.equal(pipelineGetterRan, false);
  const symbolPipeline = Object.create(pipeline) as NovelPipeline & Record<symbol, unknown>;
  symbolPipeline[Symbol("mcp-pipeline")] = true;
  assert.throws(
    () => new McpServer(symbolPipeline, logger),
    /McpServer\.pipeline must not contain symbol properties/
  );
  assert.throws(
    () => new McpServer(pipeline, accessorLogger),
    /McpServer\.logger\.info must be a data function/
  );
  assert.equal(loggerGetterRan, false);
  const dateLogger = Object.assign(new Date(), {
    info: logger.info.bind(logger),
    warn: logger.warn.bind(logger),
    error: logger.error.bind(logger)
  }) as unknown as Logger;
  assert.throws(
    () => new McpServer(pipeline, dateLogger),
    /McpServer\.logger must be a Logger instance/
  );
  const symbolLogger = Object.create(logger) as Logger & Record<symbol, unknown>;
  symbolLogger[Symbol("mcp-logger")] = true;
  assert.throws(
    () => new McpServer(pipeline, symbolLogger),
    /McpServer\.logger must not contain symbol properties/
  );
  assert.throws(
    () => new McpServer(pipeline, logger, accessorStorage),
    /McpServer\.storage\.root must be an enumerable data string/
  );
  assert.equal(storageGetterRan, false);
  const dateStorage = Object.assign(new Date(), {
    root: storage.root,
    listJobIds: storage.listJobIds.bind(storage),
    readJob: storage.readJob.bind(storage),
    writeJob: storage.writeJob.bind(storage),
    deleteJob: storage.deleteJob.bind(storage),
    quarantineJob: storage.quarantineJob.bind(storage),
    cleanupJobQuarantine: storage.cleanupJobQuarantine.bind(storage)
  }) as unknown as NovelStorage;
  assert.throws(
    () => new McpServer(pipeline, logger, dateStorage),
    /McpServer\.storage must be a NovelStorage instance/
  );
  const symbolStorage = Object.create(storage) as NovelStorage & Record<symbol, unknown>;
  symbolStorage[Symbol("mcp-storage")] = true;
  assert.throws(
    () => new McpServer(pipeline, logger, symbolStorage),
    /McpServer\.storage must not contain symbol properties/
  );
  const relativeRootStorage = Object.create(storage) as NovelStorage;
  Object.defineProperty(relativeRootStorage, "root", {
    enumerable: true,
    value: "relative-root"
  });
  assert.throws(
    () => new McpServer(pipeline, logger, relativeRootStorage),
    /McpServer\.storage\.root must be an absolute path/
  );
  const longRootStorage = Object.create(storage) as NovelStorage;
  Object.defineProperty(longRootStorage, "root", {
    enumerable: true,
    value: `/tmp/${"x".repeat(4097)}`
  });
  assert.throws(
    () => new McpServer(pipeline, logger, longRootStorage),
    /McpServer\.storage\.root must be at most 4096 characters/
  );
  const multibyteLongRootStorage = Object.create(storage) as NovelStorage;
  Object.defineProperty(multibyteLongRootStorage, "root", {
    enumerable: true,
    value: `/tmp/${"가".repeat(1365)}`
  });
  assert.throws(
    () => new McpServer(pipeline, logger, multibyteLongRootStorage),
    /McpServer\.storage\.root must be at most 4096 UTF-8 bytes/
  );
  const rootStorage = Object.create(storage) as NovelStorage;
  Object.defineProperty(rootStorage, "root", {
    enumerable: true,
    value: "/tmp/.."
  });
  assert.throws(
    () => new McpServer(pipeline, logger, rootStorage),
    /McpServer\.storage\.root must not be the filesystem root/
  );
  const controlRootStorage = Object.create(storage) as NovelStorage;
  Object.defineProperty(controlRootStorage, "root", {
    enumerable: true,
    value: "/tmp/bad\nroot"
  });
  assert.throws(
    () => new McpServer(pipeline, logger, controlRootStorage),
    /McpServer\.storage\.root must not contain control characters/
  );
});

test("MCP server shutdown logs background job shutdown summary", async () => {
  const storage = new NovelStorage(testRoot("novelist-mcp-shutdown-log-test"));
  const server = new McpServer(new NovelPipeline(storage), new Logger("info"), storage);
  const originalWrite = process.stderr.write;
  const output: string[] = [];
  process.stderr.write = ((chunk: string | Uint8Array) => {
    output.push(typeof chunk === "string" ? chunk : new TextDecoder().decode(chunk));
    return true;
  }) as typeof process.stderr.write;

  try {
    await server.shutdown();
  } finally {
    process.stderr.write = originalWrite;
  }

  const shutdownLog = output
    .map((line) => JSON.parse(line) as { message?: string; queuedCancelled?: number; stillRunning?: number; persistencePending?: number })
    .find((entry) => entry.message === "mcp_shutdown_jobs");

  assert.equal(shutdownLog?.queuedCancelled, 0);
  assert.equal(shutdownLog?.stillRunning, 0);
  assert.equal(shutdownLog?.persistencePending, 0);
});

test("health reports writable storage and persisted job visibility", async () => {
  const storage = new NovelStorage(testRoot("novelist-health-test"));
  await storage.writeJob("job-health", {
    jobId: "job-health",
    toolName: "novel_continue",
    status: "succeeded",
    createdAt: "2026-06-24T12:00:00.000Z",
    startedAt: "2026-06-24T12:00:00.500Z",
    finishedAt: "2026-06-24T12:00:01.000Z",
    cancelRequested: false,
    result: { status: "ok", message: "healthy" },
    args: { current: true }
  });
  await storage.writeJob("job-health-invalid", {
    jobId: "job-health-invalid",
    toolName: "novel_continue",
    status: "running",
    createdAt: "2026-06-24T12:00:00.000Z",
    startedAt: "2026-06-24T12:00:00.500Z",
    cancelRequested: false,
    args: "invalid"
  });
  const restarted = new JobManager(new NovelPipeline(storage), storage);
  const loaded = await restarted.loadPersistedJobs();
  const pipeline = new NovelPipeline(storage);

  const health = await pipeline.health({});
  const data = health.data as {
    storage: { root?: string; rootHash: string; writable: boolean; jobStoreReadable: boolean; currentPointerReadable: boolean; jobCount: number; jobQuarantineCount: number };
    dataDir?: string;
    agent: { provider: string; ready: boolean };
    reviewMaxRetries: number;
    jobRetentionMs: number;
    maxConcurrentJobs: number;
    maxJobs: number;
    stdioMaxLineLength: number;
  };

  assert.equal(loaded.loaded, 1);
  assert.equal(loaded.quarantined, 1);
  assert.equal(health.status, "ok");
  assert.equal(data.dataDir, undefined);
  assert.equal(data.storage.root, undefined);
  assert.match(data.storage.rootHash, /^[a-f0-9]{16}$/);
  assert.equal(data.storage.writable, true);
  assert.equal(data.storage.jobStoreReadable, true);
  assert.equal(data.storage.currentPointerReadable, true);
  assert.equal(data.storage.jobCount, 1);
  assert.equal(data.storage.jobQuarantineCount, 1);
  assert.equal(data.agent.provider, "stub");
  assert.equal(data.agent.ready, true);
  assert.equal(data.reviewMaxRetries, loadConfig({}).reviewMaxRetries);
  assert.equal(data.jobRetentionMs, loadConfig({}).jobRetentionMs);
  assert.equal(data.maxConcurrentJobs, loadConfig({}).maxConcurrentJobs);
  assert.equal(data.maxJobs, loadConfig({}).maxJobs);
  assert.equal(data.stdioMaxLineLength, loadConfig({}).stdioMaxLineLength);
});

