test("default MCP server can report health when OpenAI provider is missing an API key", async () => {
  const previousProvider = process.env.NOVELIST_AGENT_PROVIDER;
  const previousApiKey = process.env.NOVELIST_OPENAI_API_KEY;
  const previousDataDir = process.env.NOVELIST_DATA_DIR;
  try {
    process.env.NOVELIST_AGENT_PROVIDER = "openai";
    delete process.env.NOVELIST_OPENAI_API_KEY;
    process.env.NOVELIST_DATA_DIR = testRoot("novelist-default-mcp-openai-health-test");
    const server = new McpServer(undefined, new Logger("silent"));

    const response = await server.handle({
      jsonrpc: "2.0",
      id: 79,
      method: "tools/call",
      params: {
        name: "novel_health",
        arguments: {}
      }
    });
    const payload = extractToolPayload(response) as { status: string; data?: unknown };

    assert.equal(payload.status, "blocked");
    assert.match(JSON.stringify(payload.data), /OPENAI_API_KEY/);
  } finally {
    restoreEnv("NOVELIST_AGENT_PROVIDER", previousProvider);
    restoreEnv("NOVELIST_OPENAI_API_KEY", previousApiKey);
    restoreEnv("NOVELIST_DATA_DIR", previousDataDir);
  }
});

