test("background job manager rejects invalid direct constructor bounds", () => {
  const pipeline = pipelineInTemp();
  const storage = new NovelStorage(testRoot("novelist-job-manager-constructor-validation-test"));
  let pipelineGetterRan = false;
  const accessorPipeline = Object.create(pipeline) as NovelPipeline;
  Object.defineProperty(accessorPipeline, "newProject", {
    enumerable: true,
    get() {
      pipelineGetterRan = true;
      throw new Error("job pipeline getter must not run");
    }
  });
  let storageGetterRan = false;
  const accessorStorage = Object.create(storage) as NovelStorage;
  Object.defineProperty(accessorStorage, "root", {
    enumerable: true,
    get() {
      storageGetterRan = true;
      throw new Error("job storage getter must not run");
    }
  });

  assert.throws(
    () => new JobManager(null as unknown as ConstructorParameters<typeof JobManager>[0]),
    /JobManager\.pipeline must be an object/
  );
  const constructorSecret = "Authorization: Bearer job-constructor-secret";
  const assertWrappedConstructorError = (operation: () => unknown, expected: RegExp): void => {
    assert.throws(operation, expected);
    try {
      operation();
    } catch (error) {
      assert.doesNotMatch(String(error), new RegExp(constructorSecret));
      return;
    }
    throw new Error("expected JobManager constructor validation failure");
  };
  assertWrappedConstructorError(
    () => new JobManager(new Proxy(pipeline, {
      getPrototypeOf() {
        throw new Error(`leaked job pipeline prototype trap ${constructorSecret}`);
      }
    })),
    /JobManager\.pipeline prototype must be readable/
  );
  assertWrappedConstructorError(
    () => new JobManager(new Proxy(pipeline, {
      ownKeys() {
        throw new Error(`leaked job pipeline keys trap ${constructorSecret}`);
      }
    })),
    /JobManager\.pipeline keys must be readable/
  );
  assertWrappedConstructorError(
    () => new JobManager(new Proxy(pipeline, {
      getOwnPropertyDescriptor() {
        throw new Error(`leaked job pipeline descriptor trap ${constructorSecret}`);
      }
    })),
    /JobManager\.pipeline property descriptors must be readable/
  );
  assertWrappedConstructorError(
    () => new JobManager(pipeline, new Proxy(storage, {
      ownKeys() {
        throw new Error(`leaked job storage keys trap ${constructorSecret}`);
      }
    })),
    /JobManager\.storage keys must be readable/
  );
  assertWrappedConstructorError(
    () => new JobManager(pipeline, new Proxy(storage, {
      getOwnPropertyDescriptor() {
        throw new Error(`leaked job storage descriptor trap ${constructorSecret}`);
      }
    })),
    /JobManager\.storage property descriptors must be readable/
  );
  const datePipeline = Object.assign(new Date(), {
    newProject: pipeline.newProject.bind(pipeline),
    confirm: pipeline.confirm.bind(pipeline),
    continue: pipeline.continue.bind(pipeline),
    revise: pipeline.revise.bind(pipeline),
    buildEpub: pipeline.buildEpub.bind(pipeline)
  }) as unknown as NovelPipeline;
  assert.throws(
    () => new JobManager(datePipeline),
    /JobManager\.pipeline must be a NovelPipeline instance/
  );
  assert.throws(
    () => new JobManager(accessorPipeline),
    /JobManager\.pipeline\.newProject must be a data function/
  );
  assert.equal(pipelineGetterRan, false);
  const symbolPipeline = Object.create(pipeline) as NovelPipeline & Record<symbol, unknown>;
  symbolPipeline[Symbol("job-pipeline")] = true;
  assert.throws(
    () => new JobManager(symbolPipeline),
    /JobManager\.pipeline must not contain symbol properties/
  );
  assert.throws(
    () => new JobManager(pipeline, accessorStorage),
    /JobManager\.storage\.root must be an enumerable data string/
  );
  assert.equal(storageGetterRan, false);
  const dateStorage = Object.assign(new Date(), {
    root: storage.root,
    listJobIds: storage.listJobIds.bind(storage),
    readJob: storage.readJob.bind(storage),
    writeJob: storage.writeJob.bind(storage),
    deleteJob: storage.deleteJob.bind(storage),
    quarantineJob: storage.quarantineJob.bind(storage),
    cleanupJobQuarantine: storage.cleanupJobQuarantine.bind(storage)
  }) as unknown as NovelStorage;
  assert.throws(
    () => new JobManager(pipeline, dateStorage),
    /JobManager\.storage must be a NovelStorage instance/
  );
  const symbolStorage = Object.create(storage) as NovelStorage & Record<symbol, unknown>;
  symbolStorage[Symbol("job-storage")] = true;
  assert.throws(
    () => new JobManager(pipeline, symbolStorage),
    /JobManager\.storage must not contain symbol properties/
  );
  const emptyRootStorage = Object.create(storage) as NovelStorage;
  Object.defineProperty(emptyRootStorage, "root", {
    enumerable: true,
    value: "   "
  });
  assert.throws(
    () => new JobManager(pipeline, emptyRootStorage),
    /JobManager\.storage\.root must be a non-empty absolute path/
  );
  const relativeRootStorage = Object.create(storage) as NovelStorage;
  Object.defineProperty(relativeRootStorage, "root", {
    enumerable: true,
    value: "relative-root"
  });
  assert.throws(
    () => new JobManager(pipeline, relativeRootStorage),
    /JobManager\.storage\.root must be an absolute path/
  );
  const longRootStorage = Object.create(storage) as NovelStorage;
  Object.defineProperty(longRootStorage, "root", {
    enumerable: true,
    value: `/tmp/${"x".repeat(4097)}`
  });
  assert.throws(
    () => new JobManager(pipeline, longRootStorage),
    /JobManager\.storage\.root must be at most 4096 characters/
  );
  const multibyteLongRootStorage = Object.create(storage) as NovelStorage;
  Object.defineProperty(multibyteLongRootStorage, "root", {
    enumerable: true,
    value: `/tmp/${"가".repeat(1365)}`
  });
  assert.throws(
    () => new JobManager(pipeline, multibyteLongRootStorage),
    /JobManager\.storage\.root must be at most 4096 UTF-8 bytes/
  );
  const rootStorage = Object.create(storage) as NovelStorage;
  Object.defineProperty(rootStorage, "root", {
    enumerable: true,
    value: "/tmp/.."
  });
  assert.throws(
    () => new JobManager(pipeline, rootStorage),
    /JobManager\.storage\.root must not be the filesystem root/
  );

  assert.throws(
    () => new JobManager(pipeline, undefined, 0),
    /JobManager\.retentionMs must be between 1/
  );
  assert.throws(
    () => new JobManager(pipeline, undefined, 604800000, 0),
    /JobManager\.maxConcurrentJobs must be between 1 and 64/
  );
  assert.throws(
    () => new JobManager(pipeline, undefined, 604800000, 1, 100001),
    /JobManager\.maxJobs must be between 1 and 100000/
  );
});

test("cancelled queued jobs do not block later queued jobs", async () => {
  const storage = new NovelStorage(testRoot("novelist-job-queued-cancel-test"));
  const jobs = new JobManager(new NovelPipeline(storage, new SlowPlanningAgents()), storage, 604800000, 1);
  const first = jobs.start({
    toolName: "novel_new_project",
    args: {
      franchiseName: "큐 취소 세계 1",
      workRequest: "큐 취소 작품 1"
    }
  });
  const second = jobs.start({
    toolName: "novel_new_project",
    args: {
      franchiseName: "큐 취소 세계 2",
      workRequest: "큐 취소 작품 2"
    }
  });
  const third = jobs.start({
    toolName: "novel_new_project",
    args: {
      franchiseName: "큐 취소 세계 3",
      workRequest: "큐 취소 작품 3"
    }
  });
  const firstJobId = (first.data as { jobId: string }).jobId;
  const secondJobId = (second.data as { jobId: string }).jobId;
  const thirdJobId = (third.data as { jobId: string }).jobId;

  const cancelResult = await jobs.cancel({ jobId: secondJobId });
  assert.equal((cancelResult.data as { persistencePending?: boolean }).persistencePending, false);
  assert.equal((jobs.status({ jobId: secondJobId }).data as { status: string }).status, "cancelled");
  const restartedAfterCancel = new JobManager(new NovelPipeline(storage), storage);
  await restartedAfterCancel.loadPersistedJobs();
  assert.equal((restartedAfterCancel.status({ jobId: secondJobId }).data as { status: string }).status, "cancelled");
  await waitForJob(jobs, firstJobId);
  const thirdSnapshot = await waitForJob(jobs, thirdJobId);

  assert.equal(thirdSnapshot.status, "succeeded");
});

test("cancelled queued jobs return when cancellation persistence is pending", async () => {
  const storage = new HangingJobWriteStorage(testRoot("novelist-job-queued-cancel-pending-test"));
  const jobs = new JobManager(new NovelPipeline(storage, new SlowPlanningAgents()), storage, 604800000, 1);
  jobs.start({
    toolName: "novel_new_project",
    args: {
      franchiseName: "큐 지연 취소 세계 1",
      workRequest: "큐 지연 취소 작품 1"
    }
  });
  const queued = jobs.start({
    toolName: "novel_new_project",
    args: {
      franchiseName: "큐 지연 취소 세계 2",
      workRequest: "큐 지연 취소 작품 2"
    }
  });
  const queuedJobId = (queued.data as { jobId: string }).jobId;

  const startedAt = Date.now();
  const cancelResult = await jobs.cancel({ jobId: queuedJobId });
  const elapsed = Date.now() - startedAt;
  const cancelData = cancelResult.data as { status: string; persistencePending?: boolean };
  const statusData = jobs.status({ jobId: queuedJobId }).data as { status: string; persistencePending?: boolean };
  const listData = jobs.list({}).data as { jobs: Array<{ jobId: string; persistencePending?: boolean }> };
  const listed = listData.jobs.find((job) => job.jobId === queuedJobId);

  assert.equal(cancelData.status, "cancelled");
  assert.equal(cancelData.persistencePending, true);
  assert.equal(statusData.status, "cancelled");
  assert.equal(statusData.persistencePending, true);
  assert.equal(listed?.persistencePending, true);
  assert.ok(elapsed < 1000, `cancel took too long: ${elapsed}ms`);
});

test("running job cancellation returns when cancellation persistence is pending", async () => {
  const storage = new HangingJobWriteStorage(testRoot("novelist-job-running-cancel-pending-test"));
  const agents = new ShutdownHoldAgents();
  const jobs = new JobManager(new NovelPipeline(storage, agents), storage, 604800000, 1);
  const started = jobs.start({
    toolName: "novel_new_project",
    args: {
      franchiseName: "실행 지연 취소 세계",
      workRequest: "실행 지연 취소 작품"
    }
  });
  const jobId = (started.data as { jobId: string }).jobId;
  await waitForJobStatus(jobs, jobId, "running");
  await agents.waitUntilHeld();

  const startedAt = Date.now();
  const cancelResult = await jobs.cancel({ jobId });
  const elapsed = Date.now() - startedAt;
  const cancelData = cancelResult.data as { status: string; cancelRequested?: boolean; persistencePending?: boolean };
  const statusData = jobs.status({ jobId }).data as { status: string; cancelRequested?: boolean; persistencePending?: boolean };
  const listData = jobs.list({}).data as { jobs: Array<{ jobId: string; persistencePending?: boolean }> };
  const listed = listData.jobs.find((job) => job.jobId === jobId);

  assert.equal(cancelData.status, "running");
  assert.equal(cancelData.cancelRequested, true);
  assert.equal(cancelData.persistencePending, true);
  assert.equal(statusData.status, "running");
  assert.equal(statusData.cancelRequested, true);
  assert.equal(statusData.persistencePending, true);
  assert.equal(listed?.persistencePending, true);
  assert.ok(elapsed < 1000, `cancel took too long: ${elapsed}ms`);
  agents.release();
  await waitForJob(jobs, jobId);
});

