test("background job status redacts polluted result data without invoking getters", async () => {
  const storage = new NovelStorage(testRoot("novelist-job-result-redaction-accessor-test"));
  const jobs = new JobManager(new RootLeakingResultPipeline(storage), storage);
  const started = jobs.start({
    toolName: "novel_new_project",
    args: {
      franchiseName: "상태 조회 오염 세계",
      workRequest: "상태 조회 오염 작품"
    }
  });
  const jobId = (started.data as { jobId: string }).jobId;
  await waitForJob(jobs, jobId);

  let getterRan = false;
  const pollutedData = Object.create(null) as { safe?: string; danger?: unknown };
  Object.defineProperty(pollutedData, "safe", {
    value: `${storage.root}/safe/artifact.md`,
    enumerable: true
  });
  Object.defineProperty(pollutedData, "danger", {
    enumerable: true,
    get() {
      getterRan = true;
      throw new Error("job status result getter must not run");
    }
  });
  Object.defineProperty(pollutedData, "Authorization: Bearer polluted-result-key-token", {
    enumerable: true,
    get() {
      getterRan = true;
      throw new Error("job status secret key getter must not run");
    }
  });
  const record = (jobs as unknown as { jobs: Map<string, { result?: ToolResult }> }).jobs.get(jobId);
  if (!record?.result) {
    throw new Error("Expected completed job result.");
  }
  record.result = {
    status: "ok",
    message: "polluted result",
    data: pollutedData
  };

  const snapshot = jobs.status({ jobId }).data as { result?: { data?: { safe?: string; danger?: string } } };
  const text = JSON.stringify(snapshot);

  assert.equal(getterRan, false);
  assert.equal(text.includes(storage.root), false);
  assert.equal(text.includes("polluted-result-key-token"), false);
  assert.equal(snapshot.result?.data?.safe, "<data-root>/safe/artifact.md");
  assert.equal(snapshot.result?.data?.danger, "[Unredactable object property]");
  assert.match(text, /Authorization: Bearer \[Redacted\]/);
});

test("background job status redacts result data with unreadable reflection metadata", async () => {
  const traps = ["objectPrototype", "objectKeys", "objectDescriptor", "arrayPrototype", "arrayKeys", "arrayDescriptor"] as const;

  for (const trap of traps) {
    const jobs = new JobManager(new SharedJsonResultPipeline());
    const started = jobs.start({
      toolName: "novel_new_project",
      args: {
        franchiseName: `상태 리플렉션 세계 ${trap}`,
        workRequest: `상태 리플렉션 작품 ${trap}`
      }
    });
    const jobId = (started.data as { jobId: string }).jobId;
    await waitForJob(jobs, jobId);

    const secret = `Authorization: Bearer job-status-${trap}-reflection-secret`;
    const objectData = new Proxy({ safe: "value" }, {
      getPrototypeOf: trap === "objectPrototype"
        ? () => {
            throw new Error(`leaked object prototype trap ${secret}`);
          }
        : undefined,
      ownKeys: trap === "objectKeys"
        ? () => {
            throw new Error(`leaked object keys trap ${secret}`);
          }
        : undefined,
      getOwnPropertyDescriptor: trap === "objectDescriptor"
        ? () => {
            throw new Error(`leaked object descriptor trap ${secret}`);
          }
        : undefined
    });
    const arrayData = new Proxy(["value"], {
      getPrototypeOf: trap === "arrayPrototype"
        ? () => {
            throw new Error(`leaked array prototype trap ${secret}`);
          }
        : undefined,
      ownKeys: trap === "arrayKeys"
        ? () => {
            throw new Error(`leaked array keys trap ${secret}`);
          }
        : undefined,
      getOwnPropertyDescriptor: trap === "arrayDescriptor"
        ? () => {
            throw new Error(`leaked array descriptor trap ${secret}`);
          }
        : undefined
    });
    const record = (jobs as unknown as { jobs: Map<string, { result?: ToolResult }> }).jobs.get(jobId);
    if (!record?.result) {
      throw new Error("Expected completed job result.");
    }
    record.result = {
      status: "ok",
      message: "reflection trap result",
      data: trap.startsWith("array") ? { items: arrayData } : objectData
    };

    const snapshot = jobs.status({ jobId }).data as { result?: { data?: unknown } };
    const text = JSON.stringify(snapshot);

    assert.equal(text.includes(secret), false);
    assert.equal(text.includes("leaked"), false);
    if (trap.startsWith("array")) {
      assert.equal((snapshot.result?.data as { items?: unknown }).items, "[Unredactable array with unreadable metadata]");
    } else {
      assert.equal(snapshot.result?.data, "[Unredactable object with unreadable metadata]");
    }
  }
});

