test("background job result size checks ignore polluted inherited toJSON hooks", async () => {
  const storage = new NovelStorage(testRoot("novelist-job-result-tojson-size-test"));
  const jobs = new JobManager(new ArrayJsonResultPipeline(storage), storage);
  const objectHadToJson = Object.prototype.hasOwnProperty.call(Object.prototype, "toJSON");
  const arrayHadToJson = Object.prototype.hasOwnProperty.call(Array.prototype, "toJSON");
  const originalObjectToJson = (Object.prototype as { toJSON?: unknown }).toJSON;
  const originalArrayToJson = (Array.prototype as { toJSON?: unknown }).toJSON;
  let objectToJsonRan = false;
  let arrayToJsonRan = false;

  let jobId = "";
  try {
    Object.defineProperty(Object.prototype, "toJSON", {
      value() {
        objectToJsonRan = true;
        return { polluted: true };
      },
      configurable: true
    });
    Object.defineProperty(Array.prototype, "toJSON", {
      value() {
        arrayToJsonRan = true;
        return ["polluted"];
      },
      configurable: true
    });

    const started = jobs.start({
      toolName: "novel_new_project",
      args: {
        franchiseName: "toJSON 결과 세계",
        workRequest: "toJSON 결과 작품"
      }
    });
    jobId = (started.data as { jobId: string }).jobId;
    const snapshot = await waitForJob(jobs, jobId);
    assert.equal(snapshot.status, "succeeded");
  } finally {
    if (objectHadToJson) {
      Object.defineProperty(Object.prototype, "toJSON", {
        value: originalObjectToJson,
        configurable: true,
        writable: true
      });
    } else {
      delete (Object.prototype as { toJSON?: unknown }).toJSON;
    }
    if (arrayHadToJson) {
      Object.defineProperty(Array.prototype, "toJSON", {
        value: originalArrayToJson,
        configurable: true,
        writable: true
      });
    } else {
      delete (Array.prototype as { toJSON?: unknown }).toJSON;
    }
  }

  const persisted = await waitForPersistedJobStatus<{ status?: string; result?: { data?: { items?: string[] } } }>(storage, jobId, "succeeded");
  const text = JSON.stringify(persisted);

  assert.equal(objectToJsonRan, false);
  assert.equal(arrayToJsonRan, false);
  assert.equal(persisted.result?.data?.items?.[0], "Bearer [Redacted]");
  assert.match(text, /array json/);
  assert.equal(text.includes("polluted"), false);
});

