test("pipeline cancellation after continuity review does not persist feedback", async () => {
  const storage = new NovelStorage(testRoot("novelist-cancel-after-continuity-test"));
  const agents = new CancelAfterContinuityAgents();
  const pipeline = new NovelPipeline(storage, agents);
  const created = await pipeline.newProject({
    franchiseName: "연속성 취소 세계",
    workRequest: "연속성 취소 작품"
  });
  const data = created.data as { confirmationId: string; franchiseId: string; workId: string; volumeId: string };
  await pipeline.confirm({ confirmationId: data.confirmationId, approved: true });
  const before = await storage.loadState(data.franchiseId, data.workId, data.volumeId);
  agents.cancelAfterContinuity = true;

  await assertRejects(
    pipeline.continue(
      { franchiseId: data.franchiseId, workId: data.workId, volumeId: data.volumeId },
      { isCancelled: () => agents.cancelled }
    ),
    /cancelled while reviewing beat feedback/
  );

  const after = await storage.loadState(data.franchiseId, data.workId, data.volumeId);
  const currentBeat = after.chapters.flatMap((chapter) => chapter.beats).find((beat) => beat.chapterNo === after.currentChapterNo && beat.beatNo === after.currentBeatNo);
  assert.equal(after.status, before.status);
  assert.equal(after.confirmations.length, before.confirmations.length);
  assert.equal(currentBeat?.status, "pending");
  assert.equal(currentBeat?.retryCount, 0);
  assert.equal(currentBeat?.lastFeedback, undefined);
});

test("background job shutdown persists queued cancellation and running cancellation requests", async () => {
  const storage = new NovelStorage(testRoot("novelist-job-shutdown-test"));
  const agents = new ShutdownHoldAgents();
  const jobs = new JobManager(new NovelPipeline(storage, agents), storage, 604800000, 1);
  const first = jobs.start({
    toolName: "novel_new_project",
    args: {
      franchiseName: "종료 세계 1",
      workRequest: "종료 작품 1"
    }
  });
  const second = jobs.start({
    toolName: "novel_new_project",
    args: {
      franchiseName: "종료 세계 2",
      workRequest: "종료 작품 2"
    }
  });
  const firstJobId = (first.data as { jobId: string }).jobId;
  const secondJobId = (second.data as { jobId: string }).jobId;
  await waitForJobStatus(jobs, firstJobId, "running");
  await agents.waitUntilHeld();

  try {
    const shutdown = await jobs.shutdown(100);
    const persistedRunning = await storage.readJob<{ status?: string; cancelRequested?: boolean }>(firstJobId);
    const persistedQueued = await storage.readJob<{ status?: string; cancelRequested?: boolean; error?: string }>(secondJobId);

    assert.equal(shutdown.queuedCancelled, 1);
    assert.equal(shutdown.runningCancellationRequested, 1);
    assert.equal(shutdown.stillRunning, 1);
    assert.equal(shutdown.persistencePending, 0);
    assert.equal(persistedRunning.status, "running");
    assert.equal(persistedRunning.cancelRequested, true);
    assert.equal(persistedQueued.status, "cancelled");
    assert.equal(persistedQueued.cancelRequested, true);
    assert.match(persistedQueued.error ?? "", /server shutdown/);
  } finally {
    agents.release();
  }
  const firstFinished = await waitForJob(jobs, firstJobId);
  assert.equal(firstFinished.status, "cancelled");
});

test("background job shutdown marks queued jobs before waiting for running cancellation persistence", async () => {
  const agents = new ShutdownHoldAgents();
  const storage = new ReleaseOnRunningCancellationWriteStorage(
    testRoot("novelist-job-shutdown-queue-race-test"),
    () => {
      agents.release();
    }
  );
  const jobs = new JobManager(new NovelPipeline(storage, agents), storage, 604800000, 1);
  const first = jobs.start({
    toolName: "novel_new_project",
    args: {
      franchiseName: "종료 경합 세계 1",
      workRequest: "종료 경합 작품 1"
    }
  });
  const second = jobs.start({
    toolName: "novel_new_project",
    args: {
      franchiseName: "종료 경합 세계 2",
      workRequest: "종료 경합 작품 2"
    }
  });
  const firstJobId = (first.data as { jobId: string }).jobId;
  const secondJobId = (second.data as { jobId: string }).jobId;
  await waitForJobStatus(jobs, firstJobId, "running");
  await agents.waitUntilHeld();

  const shutdown = await jobs.shutdown(200);
  const secondStatus = jobs.status({ jobId: secondJobId }).data as { status: string; cancelRequested?: boolean; error?: string };
  await waitForJob(jobs, firstJobId);
  await delay(20);
  const secondAfterFirstSettles = jobs.status({ jobId: secondJobId }).data as { status: string; cancelRequested?: boolean; error?: string };

  assert.equal(shutdown.queuedCancelled, 1);
  assert.equal(shutdown.runningCancellationRequested, 1);
  assert.equal(secondStatus.status, "cancelled");
  assert.equal(secondStatus.cancelRequested, true);
  assert.match(secondStatus.error ?? "", /server shutdown/);
  assert.equal(secondAfterFirstSettles.status, "cancelled");
});

test("background job shutdown bounds pending persistence waits", async () => {
  const storage = new HangingJobWriteStorage(testRoot("novelist-job-shutdown-persist-timeout-test"));
  const agents = new ShutdownHoldAgents();
  const jobs = new JobManager(new NovelPipeline(storage, agents), storage, 604800000, 1);
  const started = jobs.start({
    toolName: "novel_new_project",
    args: {
      franchiseName: "종료 지연 세계",
      workRequest: "종료 지연 작품"
    }
  });
  const jobId = (started.data as { jobId: string }).jobId;
  await waitForJobStatus(jobs, jobId, "running");
  await agents.waitUntilHeld();

  const startedAt = Date.now();
  const shutdown = await jobs.shutdown(10);
  const elapsed = Date.now() - startedAt;

  assert.equal(shutdown.runningCancellationRequested, 1);
  assert.equal(shutdown.stillRunning, 1);
  assert.ok(shutdown.persistencePending >= 1);
  assert.ok(elapsed < 500, `shutdown took too long: ${elapsed}ms`);
  agents.release();
  await waitForJob(jobs, jobId);
});

