test("background job persistence chains continue after a rejected tail", async () => {
  const storage = new NovelStorage(testRoot("novelist-job-rejected-tail-recovery-test"));
  const agents = new ShutdownHoldAgents();
  const jobs = new JobManager(new NovelPipeline(storage, agents), storage, 604800000, 1);
  const running = jobs.start({
    toolName: "novel_new_project",
    args: {
      franchiseName: "거부된 저장 꼬리 세계 1",
      workRequest: "거부된 저장 꼬리 작품 1"
    }
  });
  const queued = jobs.start({
    toolName: "novel_new_project",
    args: {
      franchiseName: "거부된 저장 꼬리 세계 2",
      workRequest: "거부된 저장 꼬리 작품 2"
    }
  });
  const runningJobId = (running.data as { jobId: string }).jobId;
  const queuedJobId = (queued.data as { jobId: string }).jobId;
  await agents.waitUntilHeld();
  await waitForPersistedJobStatus(storage, queuedJobId, "queued");
  const queuedRecord = (jobs as unknown as { jobs: Map<string, { persistenceTail?: Promise<void> }> }).jobs.get(queuedJobId);
  if (!queuedRecord) {
    throw new Error("Expected queued job record.");
  }
  const rejectedTail = Promise.reject(new Error("stale persistence tail"));
  rejectedTail.catch(() => undefined);
  queuedRecord.persistenceTail = rejectedTail;

  const cancelled = await jobs.cancel({ jobId: queuedJobId });
  const cancelledData = cancelled.data as { status?: string; persistencePending?: boolean };
  const persisted = await waitForPersistedJobStatus<{ status?: string; cancelRequested?: boolean; error?: string }>(storage, queuedJobId, "cancelled");
  agents.release();
  await waitForJob(jobs, runningJobId);

  assert.equal(cancelledData.status, "cancelled");
  assert.equal(cancelledData.persistencePending, false);
  assert.equal(persisted.status, "cancelled");
  assert.equal(persisted.cancelRequested, true);
  assert.match(persisted.error ?? "", /cancelled before it started/);
});

test("background job recovery quarantines corrupt snapshots and continues loading valid jobs", async () => {
  const storage = new NovelStorage(testRoot("novelist-job-quarantine-test"));
  const validJobId = "job-valid";
  await storage.writeJob(validJobId, {
    jobId: validJobId,
    toolName: "novel_continue",
    status: "succeeded",
    createdAt: "2026-06-24T12:00:00.000Z",
    startedAt: "2026-06-24T12:00:00.500Z",
    finishedAt: "2026-06-24T12:00:01.000Z",
    cancelRequested: false,
    result: { status: "ok", message: "valid" },
    args: { current: true }
  });
  await writeFile(storage.jobPath("job-corrupt"), "{bad json", "utf8");
  await writeFile(join(storage.root, "jobs", "operator note.json"), "not a job", "utf8");
  await mkdir(join(storage.root, "jobs", "job-directory.json"), { recursive: true });

  const restarted = new JobManager(new NovelPipeline(storage), storage);
  const loaded = await restarted.loadPersistedJobs();
  const validStatus = restarted.status({ jobId: validJobId });

  assert.equal(loaded.loaded, 1);
  assert.equal(loaded.failed, 1);
  assert.equal(loaded.quarantined, 1);
  assert.match(loaded.errors[0]?.error ?? "", /JSON metadata file must contain valid JSON/);
  assert.match(loaded.errors[0]?.error ?? "", /<data-root>\/jobs\/job-corrupt\.json/);
  assert.equal((validStatus.data as { status: string }).status, "succeeded");
  await assertRejects(storage.readJob("job-corrupt"), /ENOENT/);
  const remainingJobIds = await storage.listJobIds();
  assert.deepEqual(remainingJobIds, [validJobId]);
});

