test("job quarantine paths do not collide for the same job id in one millisecond", async () => {
  const storage = new NovelStorage(testRoot("novelist-job-quarantine-collision-test"));
  const originalNow = Date.now;
  Date.now = () => 1_800_000_000_000;
  try {
    await storage.writeFileAtomic(storage.jobPath("job-repeat"), "{bad json one");
    const firstPath = await storage.quarantineJob("job-repeat");
    await storage.writeFileAtomic(storage.jobPath("job-repeat"), "{bad json two");
    const secondPath = await storage.quarantineJob("job-repeat");

    assert.ok(firstPath !== secondPath);
    assert.equal(await readFile(firstPath, "utf8"), "{bad json one");
    assert.equal(await readFile(secondPath, "utf8"), "{bad json two");
  } finally {
    Date.now = originalNow;
  }
});

