test("background job recovery quarantines snapshot symlinks to directories", async () => {
  const root = testRoot("novelist-job-symlink-dir-root");
  const outside = testRoot("novelist-job-symlink-dir-outside");
  const storage = new NovelStorage(root);
  await mkdir(outside, { recursive: true });
  await writeFile(join(outside, "sentinel.txt"), "outside directory must remain\n", "utf8");
  await mkdir(join(root, "jobs"), { recursive: true });
  await symlink(outside, storage.jobPath("job-symlink-dir"));

  const restarted = new JobManager(new NovelPipeline(storage), storage);
  const loaded = await restarted.loadPersistedJobs();

  assert.equal(loaded.loaded, 0);
  assert.equal(loaded.failed, 1);
  assert.equal(loaded.quarantined, 1);
  assert.match(loaded.errors[0]?.error ?? "", /must not be a symbolic link/);
  await assertRejects(storage.readJob("job-symlink-dir"), /ENOENT/);
  assert.equal(await readFile(join(outside, "sentinel.txt"), "utf8"), "outside directory must remain\n");
});

