test("background job recovery rejects prototype-like persisted snapshot fields", async () => {
  const storage = new NovelStorage(testRoot("novelist-job-prototype-field-test"));
  const snapshot = Object.create(null) as Record<string, unknown>;
  Object.assign(snapshot, {
    jobId: "job-prototype-field",
    toolName: "novel_continue",
    status: "running",
    createdAt: "2026-06-24T12:00:00.000Z",
    startedAt: "2026-06-24T12:00:01.000Z",
    cancelRequested: false,
    args: { current: true }
  });
  Object.defineProperty(snapshot, "__proto__", {
    enumerable: true,
    value: { polluted: true }
  });
  await storage.writeJob("job-prototype-field", snapshot);

  const restarted = new JobManager(new NovelPipeline(storage), storage);
  const loaded = await restarted.loadPersistedJobs();

  assert.equal(loaded.loaded, 0);
  assert.equal(loaded.failed, 1);
  assert.equal(loaded.quarantined, 1);
  assert.match(loaded.errors[0]?.error ?? "", /__proto__ is not a supported field/);
  assert.equal(({} as { polluted?: boolean }).polluted, undefined);
  await assertRejects(Promise.resolve().then(() => restarted.status({ jobId: "job-prototype-field" })), /Job not found/);
});

