  assert.match(status.error ?? "", /Bearer \[Redacted\]/);
  assert.match(status.error ?? "", /api_key=\[Redacted\]/);
  assert.match(status.error ?? "", /sk-\[Redacted\]/);
  assert.match(status.persistenceError ?? "", /x-api-key: \[Redacted\]/);
  assert.match(status.persistenceError ?? "", /refresh_token=\[Redacted\]/);
  assert.equal(list.jobs[0]?.hasError, true);
  assert.equal(list.jobs[0]?.hasPersistenceError, true);
