test("background job recovery validates injected job id listings before loading snapshots", async () => {
  const unsafeIds = new UnsafeJobIdListStorage(testRoot("novelist-job-list-unsafe-id-test"));
  const sparseIds = new SparseJobIdListStorage(testRoot("novelist-job-list-sparse-test"));
  const accessorIds = new AccessorJobIdListStorage(testRoot("novelist-job-list-accessor-test"));
  const duplicateIds = new DuplicateJobIdListStorage(testRoot("novelist-job-list-duplicate-test"));
  const prototypeTrapIds = new ReflectionTrapJobIdListStorage(testRoot("novelist-job-list-prototype-trap-test"), "prototype");
  const keysTrapIds = new ReflectionTrapJobIdListStorage(testRoot("novelist-job-list-keys-trap-test"), "keys");
  const descriptorTrapIds = new ReflectionTrapJobIdListStorage(testRoot("novelist-job-list-descriptor-trap-test"), "descriptor");

  await assertRejects(
    new JobManager(new NovelPipeline(unsafeIds), unsafeIds).loadPersistedJobs(),
    /JobManager\.storage\.listJobIds result\[0\] contains unsafe path characters/
  );
  await assertRejects(
    new JobManager(new NovelPipeline(sparseIds), sparseIds).loadPersistedJobs(),
    /JobManager\.storage\.listJobIds result\[0\] must not be a sparse array hole/
  );
  await assertRejects(
    new JobManager(new NovelPipeline(accessorIds), accessorIds).loadPersistedJobs(),
    /JobManager\.storage\.listJobIds result\[0\] must not contain non-enumerable or accessor properties/
  );
  await assertRejects(
    new JobManager(new NovelPipeline(duplicateIds), duplicateIds).loadPersistedJobs(),
    /JobManager\.storage\.listJobIds result must not contain duplicate job ids/
  );
  await assertRejects(
    new JobManager(new NovelPipeline(prototypeTrapIds), prototypeTrapIds).loadPersistedJobs(),
    /JobManager\.storage\.listJobIds result prototype must be readable/
  );
  await assertRejects(
    new JobManager(new NovelPipeline(keysTrapIds), keysTrapIds).loadPersistedJobs(),
    /JobManager\.storage\.listJobIds result keys must be readable/
  );
  await assertRejects(
    new JobManager(new NovelPipeline(descriptorTrapIds), descriptorTrapIds).loadPersistedJobs(),
    /JobManager\.storage\.listJobIds result property descriptors must be readable/
  );
  assert.equal(accessorIds.getterRan, false);
  for (const storage of [prototypeTrapIds, keysTrapIds, descriptorTrapIds]) {
    try {
      await new JobManager(new NovelPipeline(storage), storage).loadPersistedJobs();
    } catch (error) {
      assert.doesNotMatch(String(error), /Authorization: Bearer job-list-secret/);
      continue;
    }
    throw new Error("expected job id list validation failure");
  }
});

test("background job list paginates returned snapshots and reports total matches", async () => {
  const jobs = new JobManager(pipelineInTemp(new SlowPlanningAgents()), undefined, 604800000, 1, 5);
  for (const index of [1, 2, 3]) {
    jobs.start({
      toolName: "novel_new_project",
      args: { franchiseName: `목록 세계 ${index}`, workRequest: `목록 작품 ${index}` }
    });
  }

  const firstPage = jobs.list({ limit: 2 }).data as { count: number; total: number; limit: number; offset: number; hasMore?: boolean; nextOffset?: number; jobs: Array<{ jobId: string }> };
  const secondPage = jobs.list({ limit: 2, offset: 2 }).data as { count: number; total: number; limit: number; offset: number; hasMore?: boolean; nextOffset?: number; jobs: Array<{ jobId: string }> };

  assert.equal(firstPage.count, 2);
  assert.equal(firstPage.total, 3);
  assert.equal(firstPage.limit, 2);
  assert.equal(firstPage.offset, 0);
  assert.equal(firstPage.hasMore, true);
  assert.equal(firstPage.nextOffset, 2);
  assert.equal(secondPage.count, 1);
  assert.equal(secondPage.total, 3);
  assert.equal(secondPage.limit, 2);
  assert.equal(secondPage.offset, 2);
  assert.equal(secondPage.hasMore, false);
  assert.equal(Object.prototype.hasOwnProperty.call(secondPage, "nextOffset"), false);
  assert.ok(firstPage.jobs[0]?.jobId !== secondPage.jobs[0]?.jobId);
  await assertRejects(Promise.resolve().then(() => jobs.list({ limit: 1001 })), /novel_job_list\.limit/);
});

