test("background job list filters jobs and cleanup removes expired finished snapshots", async () => {
  const storage = new NovelStorage(testRoot("novelist-job-cleanup-test"));
  const oldFinishedAt = new Date(Date.now() - 200_000).toISOString();
  await storage.writeJob("job-old", {
    jobId: "job-old",
    toolName: "novel_continue",
    status: "succeeded",
    createdAt: oldFinishedAt,
    startedAt: oldFinishedAt,
    finishedAt: oldFinishedAt,
    cancelRequested: false,
    result: { status: "ok", message: "old" },
    args: { current: true }
  });
  await storage.writeJob("job-running", {
    jobId: "job-running",
    toolName: "novel_continue",
    status: "running",
    createdAt: new Date().toISOString(),
    startedAt: new Date().toISOString(),
    cancelRequested: false,
    args: { current: true }
  });
  await storage.writeJob("job-quarantine", {
    jobId: "job-quarantine",
    toolName: "novel_continue",
    status: "finished",
    createdAt: oldFinishedAt,
    cancelRequested: false,
    args: { current: true }
  });

  const jobs = new JobManager(new NovelPipeline(storage), storage, 100_000);
  const loaded = await jobs.loadPersistedJobs();
  assert.equal(loaded.quarantined, 1);
  assert.match(loaded.errors[0]?.quarantinePath ?? "", /<data-root>\/jobs\/quarantine\/job-quarantine-/);
  const quarantineFiles = await readdir(join(storage.root, "jobs", "quarantine"));
  const quarantineFile = quarantineFiles.find((name) => name.startsWith("job-quarantine-"));
  if (!quarantineFile) {
    throw new Error("Expected quarantined job file.");
  }
  const quarantinePath = join(storage.root, "jobs", "quarantine", quarantineFile);
  const oldQuarantineTime = new Date(Date.now() - 200_000);
  await utimes(quarantinePath, oldQuarantineTime, oldQuarantineTime);
  const succeeded = jobs.list({ status: "succeeded" }).data as { count: number; jobs: Array<{ jobId: string }> };
  assert.equal(succeeded.count, 1);
  assert.equal(succeeded.jobs[0]?.jobId, "job-old");

  const cleanup = await jobs.cleanup({});
  assert.deepEqual(cleanup.status, "ok");
  const cleanupData = cleanup.data as { deleted: number; quarantineDeleted: number; retained: number };
  assert.equal(cleanupData.deleted, 1);
  assert.equal(cleanupData.quarantineDeleted, 1);
  assert.equal(cleanupData.retained, 1);
  await assertRejects(Promise.resolve().then(() => jobs.status({ jobId: "job-old" })), /Job not found/);
  assert.deepEqual(await storage.listJobIds(), [ "job-running" ]);
});

