test("background job cleanup wraps unreadable quarantine failure array reflection", async () => {
  for (const [trap, expected] of [
    ["prototype", /cleanupJobQuarantine\.failures prototype must be readable/],
    ["keys", /cleanupJobQuarantine\.failures keys must be readable/],
    ["descriptor", /cleanupJobQuarantine\.failures property descriptors must be readable/]
  ] as const) {
    const storage = new ReflectionTrapQuarantineCleanupFailureArrayStorage(
      testRoot(`novelist-job-cleanup-quarantine-array-reflection-${trap}`),
      trap
    );
    const jobs = new JobManager(new NovelPipeline(storage), storage, 100_000);

    const cleanup = await jobs.cleanup({});
    const cleanupData = cleanup.data as { quarantineFailures: Array<{ error: string }> };
    const error = cleanupData.quarantineFailures[0]?.error ?? "";

    assert.equal(cleanup.status, "blocked");
    assert.match(error, expected);
    assert.doesNotMatch(error, /Authorization: Bearer quarantine-array-reflection-secret/);
  }
});

