test("background job cleanup deletes quarantined symlinks without following their targets", async () => {
  const root = testRoot("novelist-job-cleanup-symlink-root");
  const outside = testRoot("novelist-job-cleanup-symlink-outside");
  const storage = new NovelStorage(root);
  const jobs = new JobManager(new NovelPipeline(storage), storage, 100_000);
  const quarantineDir = join(root, "jobs", "quarantine");
  await mkdir(quarantineDir, { recursive: true });
  await mkdir(outside, { recursive: true });
  const outsideSnapshot = join(outside, "target.json");
  await writeFile(outsideSnapshot, "outside target", "utf8");
  const quarantinePath = join(quarantineDir, "job-symlink-old.json");
  await symlink(outsideSnapshot, quarantinePath);
  const oldQuarantineTime = new Date(Date.now() - 200_000);
  await lutimes(quarantinePath, oldQuarantineTime, oldQuarantineTime);

  const cleanup = await jobs.cleanup({});
  const cleanupData = cleanup.data as { quarantineDeleted: number; failed: number };

  assert.equal(cleanup.status, "ok");
  assert.equal(cleanupData.quarantineDeleted, 1);
  assert.equal(cleanupData.failed, 0);
  await assertRejects(readFile(quarantinePath, "utf8"), /ENOENT/);
  assert.equal(await readFile(outsideSnapshot, "utf8"), "outside target");
});

