test("continue does not advance a blocked volume", async () => {
  const root = testRoot("novelist-blocked-continue-test");
  const storage = new NovelStorage(root);
  const pipeline = new NovelPipeline(storage);
  const created = await pipeline.newProject({
    franchiseName: "차단 세계",
    workRequest: "차단 작품"
  });
  const data = created.data as { franchiseId: string; workId: string; volumeId: string };
  const statePath = storage.statePath(data.franchiseId, data.workId, data.volumeId);
  const state = JSON.parse(await readFile(statePath, "utf8")) as {
    status: string;
    confirmations: Array<{ resolvedAt?: string; approved?: boolean }>;
    conflicts: Array<{ id: string; scope: string; description: string; severity: string; resolved: boolean }>;
  };
  state.status = "blocked";
  state.confirmations[0]!.resolvedAt = new Date().toISOString();
  (state as Record<string, unknown>).updatedAt = state.confirmations[0]!.resolvedAt;
  state.confirmations[0]!.approved = true;
  state.conflicts.push({
    id: "blocked-reason",
    scope: "volume",
    description: "운영자 검토가 필요한 차단 사유",
    severity: "blocking",
    resolved: false
  });
  await writeFile(statePath, JSON.stringify(state), "utf8");

  const result = await pipeline.continue({
    franchiseId: data.franchiseId,
    workId: data.workId,
    volumeId: data.volumeId
  });
  assert.equal(result.status, "blocked");
  const summary = result.data as { completedBeats: number };
  assert.equal(summary.completedBeats, 0);
});

test("revision resolves blocking conflicts so a blocked volume can resume", async () => {
  const root = testRoot("novelist-blocked-revision-resume-test");
  const storage = new NovelStorage(root);
  const pipeline = new NovelPipeline(storage);
  const created = await pipeline.newProject({
    franchiseName: "수정 재개 세계",
    workRequest: "수정 재개 작품"
  });
  const data = created.data as { franchiseId: string; workId: string; volumeId: string };
  const statePath = storage.statePath(data.franchiseId, data.workId, data.volumeId);
  const state = JSON.parse(await readFile(statePath, "utf8")) as {
    status: string;
    confirmations: Array<{ resolvedAt?: string; approved?: boolean }>;
    conflicts: Array<{ id: string; scope: string; description: string; severity: string; resolved: boolean }>;
  };
  state.status = "blocked";
  state.confirmations[0]!.resolvedAt = new Date().toISOString();
  (state as Record<string, unknown>).updatedAt = state.confirmations[0]!.resolvedAt;
  state.confirmations[0]!.approved = true;
  state.conflicts.push({
    id: "blocked-revision-reason",
    scope: "volume",
    description: "수정으로 해소할 차단 사유",
    severity: "blocking",
    resolved: false
  });
  await writeFile(statePath, JSON.stringify(state), "utf8");

  const revised = await pipeline.revise({
    franchiseId: data.franchiseId,
    workId: data.workId,
    volumeId: data.volumeId,
    target: "chapter:1,beat:1",
    instruction: "차단 사유를 반영해서 다시 작성"
  });
  const resumed = await storage.loadState(data.franchiseId, data.workId, data.volumeId);

  assert.equal(revised.status, "drafting");
  assert.equal(resumed.status, "drafting");
  assert.equal(resumed.conflicts[0]?.resolved, true);
  assert.equal(resumed.chapters[0]?.beats[0]?.status, "complete");
});

