test("world markdown reads are bounded and do not follow symlinks", async () => {
  const root = testRoot("novelist-world-read-root");
  const outside = testRoot("novelist-world-read-outside");
  const storage = new NovelStorage(root);
  const pipeline = new NovelPipeline(storage);
  const created = await pipeline.newProject({
    franchiseName: "세계관 읽기 세계",
    workRequest: "세계관 읽기 작품"
  });
  const data = created.data as { confirmationId: string; franchiseId: string; workId: string; volumeId: string };
  await pipeline.confirm({ confirmationId: data.confirmationId, approved: true });
  const state = await storage.loadState(data.franchiseId, data.workId, data.volumeId);
  const worldPath = join(storage.franchiseDir(data.franchiseId), "world.md");
  await mkdir(outside, { recursive: true });
  const outsideWorld = join(outside, "world.md");
  await writeFile(outsideWorld, "outside world", "utf8");
  await unlink(worldPath);
  await symlink(outsideWorld, worldPath);

  await assertRejects(storage.readWorld(state), /World markdown file path must not be a symbolic link/);

  await unlink(worldPath);
  await writeFile(worldPath, "x".repeat(10 * 1024 * 1024 + 1), "utf8");
  await assertRejects(storage.readWorld(state), /World markdown file is too large/);

  await writeFile(worldPath, "세계관 본문\u0000hidden", "utf8");
  await assertRejects(storage.readWorld(state), /World markdown file must not contain non-printing control characters/);
});

