test("markdown writer rejects unsupported frontmatter metadata", async () => {
  const storage = new NovelStorage(testRoot("novelist-write-frontmatter-test"));

  await assertRejects(
    storage.writeMarkdown(join(storage.root, "bad-key.md"), { "bad key": "value" }, "body"),
    /not a supported frontmatter field name/
  );
  await assertRejects(
    storage.writeMarkdown(join(storage.root, "bad-constructor-key.md"), { constructor: "value" }, "body"),
    /constructor is not a supported frontmatter field name/
  );
  await assertRejects(
    storage.writeMarkdown(join(storage.root, "bad-prototype-key.md"), { prototype: "value" }, "body"),
    /prototype is not a supported frontmatter field name/
  );
  await assertRejects(
    storage.writeMarkdown(join(storage.root, "long-key.md"), { [`k${"x".repeat(256)}`]: "value" }, "body"),
    /must be at most 256 characters/
  );
  await assertRejects(
    storage.writeMarkdown(join(storage.root, "bad-value.md"), { key: { nested: true } }, "body"),
    /must be a string, finite number, or boolean/
  );
  await assertRejects(
    storage.writeMarkdown(join(storage.root, "bad-control-value.md"), { key: "bad\u0001value" }, "body"),
    /frontmatter .* must not contain control characters/
  );
  await assertRejects(
    storage.writeMarkdown(join(storage.root, "bad-number.md"), { key: 1 / 0 }, "body"),
    /must be a finite number/
  );
  await assertRejects(
    storage.writeMarkdown(join(storage.root, "bad-unsafe-integer.md"), { key: Number.MAX_SAFE_INTEGER + 1 }, "body"),
    /frontmatter .* must be a safe integer/
  );
  await assertRejects(
    storage.writeMarkdown(join(storage.root, "bad-instance.md"), new Date() as unknown as Record<string, unknown>, "body"),
    /frontmatter .* must be a plain object/
  );
  const secret = "Authorization: Bearer frontmatter-secret";
  const assertWrappedFrontmatter = async (frontmatter: Record<string, unknown>, expected: RegExp): Promise<void> => {
    await assertRejects(storage.writeMarkdown(join(storage.root, `bad-reflection-${Date.now()}.md`), frontmatter, "body"), expected);
    try {
      await storage.writeMarkdown(join(storage.root, `bad-reflection-repeat-${Date.now()}.md`), frontmatter, "body");
    } catch (error) {
      assert.doesNotMatch(String(error), new RegExp(secret));
      return;
    }
    throw new Error("expected frontmatter validation failure");
  };
  await assertWrappedFrontmatter(
    new Proxy({ key: "value" }, {
      getPrototypeOf() {
        throw new Error(`leaked frontmatter prototype trap ${secret}`);
      }
    }),
    /Markdown frontmatter .* prototype must be readable/
  );
  await assertWrappedFrontmatter(
    new Proxy({ key: "value" }, {
      ownKeys() {
        throw new Error(`leaked frontmatter keys trap ${secret}`);
      }
    }),
    /Markdown frontmatter .* keys must be readable/
  );
  await assertWrappedFrontmatter(
    new Proxy({ key: "value" }, {
      getOwnPropertyDescriptor() {
        throw new Error(`leaked frontmatter descriptor trap ${secret}`);
      }
    }),
    /Markdown frontmatter .* property descriptors must be readable/
  );
  await assertRejects(
    storage.writeMarkdown(
      join(storage.root, "bad-symbol.md"),
      { [Symbol("hidden")]: "value", key: "value" } as Record<string, unknown>,
      "body"
    ),
    /frontmatter .* must not contain symbol properties/
  );
  await assertRejects(
    storage.writeMarkdown(
      join(storage.root, "bad-hidden.md"),
      Object.defineProperty({ key: "value" }, "hidden", { value: "secret", enumerable: false }),
      "body"
    ),
    /frontmatter .* must not contain non-enumerable or accessor properties/
  );
  await assertRejects(
    storage.writeMarkdown(
      join(storage.root, "bad-accessor.md"),
      Object.defineProperty({ key: "value" }, "danger", {
        enumerable: true,
        get() {
          throw new Error("getter must not run");
        }
      }),
      "body"
    ),
    /frontmatter .* must not contain non-enumerable or accessor properties/
  );
  await assertRejects(
    storage.writeMarkdown(
      join(storage.root, "too-many-fields.md"),
      Object.fromEntries(Array.from({ length: 21 }, (_value, index) => [`key${index}`, "value"])),
      "body"
    ),
    /has too many fields/
  );
  let lateGetterRan = false;
  const tooManyWithGetter = Object.fromEntries(Array.from({ length: 21 }, (_value, index) => [`key${index}`, "value"]));
  Object.defineProperty(tooManyWithGetter, "lateGetter", {
    enumerable: true,
    get() {
      lateGetterRan = true;
      throw new Error("frontmatter late getter must not run");
    }
  });
  await assertRejects(
    storage.writeMarkdown(join(storage.root, "too-many-fields-accessor.md"), tooManyWithGetter, "body"),
    /has too many fields/
  );
  assert.equal(lateGetterRan, false);
  await assertRejects(
    storage.writeMarkdown(join(storage.root, "oversized-frontmatter.md"), { key: "x".repeat(64 * 1024 + 1) }, "body"),
    /frontmatter .* is too large/
  );
  await assertRejects(
    storage.writeMarkdown(join(storage.root, "oversized-frontmatter-bytes.md"), { key: "가".repeat(22 * 1024) }, "body"),
    /frontmatter .* is too large: maximum is 65536 UTF-8 bytes/
  );
  await assertRejects(
    storage.writeMarkdown(join(storage.root, "empty-body.md"), { kind: "test" }, " \n\t "),
    /Markdown body .* must be non-empty/
  );
  await assertRejects(
    storage.writeMarkdown(join(storage.root, "bad-body-type.md"), { kind: "test" }, 42 as unknown as string),
    /Markdown body .* must be a string/
  );
  await assertRejects(
    storage.writeMarkdown(join(storage.root, "bad-body-control.md"), { kind: "test" }, "safe text\u0000hidden"),
    /Markdown body .* must not contain non-printing control characters/
  );
  await assertRejects(
    storage.writeMarkdown(join(storage.root, "raw-body-too-large.md"), { kind: "test" }, `${" ".repeat(10 * 1024 * 1024 + 1)}body`),
    /Markdown body .* must be at most 10485760 characters before trimming/
  );
});

test("logger serializes and bounds metadata safely", () => {
  const logger = new Logger("debug");
  const originalWrite = process.stderr.write;
  const output: string[] = [];
  const circular: { self?: unknown } = {};
  circular.self = circular;
  const deep: Record<string, unknown> = {};
  let current = deep;
  for (let index = 0; index < 10; index += 1) {
    current.next = {};
    current = current.next as Record<string, unknown>;
  }
  let objectGetterRan = false;
  const dangerousObject = Object.defineProperties(
    { visible: "ok" },
    {
      hidden: { value: "hidden-log-secret", enumerable: false },
      danger: {
        enumerable: true,
        get() {
          objectGetterRan = true;
          throw new Error("getter must not run");
        }
      },
      [Symbol("hidden")]: { value: "symbol-log-secret", enumerable: true }
    }
  ) as Record<string, unknown>;
  let arrayGetterRan = false;
  const dangerousArray = ["first"];
  dangerousArray.length = 4;
  Object.defineProperty(dangerousArray, "2", {
    enumerable: true,
    get() {
      arrayGetterRan = true;
      throw new Error("array getter must not run");
    }
  });
  const prototypeLike = Object.create(null) as Record<string, unknown>;
  Object.defineProperty(prototypeLike, "__proto__", {
    enumerable: true,
    value: { logged: true }
  });
  const shared = { sharedValue: "appears twice" };
  process.stderr.write = ((chunk: string | Uint8Array) => {
    output.push(typeof chunk === "string" ? chunk : new TextDecoder().decode(chunk));
    return true;
  }) as typeof process.stderr.write;

  try {
    logger.warn("safe\u0001log\nwith\ttabs", {
      ts: "forged-ts",
      level: "error",
      message: "forged message",
      "bad\nkey\tname": "key control value",
      "bad key name": "key collision value",
      "Authorization: Bearer key-secret-token": "key secret value",
      "Authorization: Bearer key-secret-token-2": "second key secret value",
      "sk-keysecret123": "api key secret value",
      [`${"k".repeat(300)}`]: "long key value",
      circular,
      count: 10n,
      longText: `bad\u0002${"x".repeat(5000)}`,
      manyItems: Array.from({ length: 55 }, (_, index) => index),
      manyFields: Object.fromEntries(Array.from({ length: 105 }, (_, index) => [`field${index}`, index])),
      deep,
      openaiApiKey: "sk-log-secret",
      dangerousObject,
      dangerousArray,
      prototypeLike,
      sharedA: shared,
      sharedB: shared,
      nested: {
        authorization: "Bearer token-secret",
        refresh_token: "refresh-secret",
        harmless: "visible"
      }
    });
  } finally {
    process.stderr.write = originalWrite;
  }

  const logged = JSON.parse(output[0] ?? "{}") as {
    ts?: string;
    level?: string;
    message?: string;
    circular?: { self?: string };
    count?: string;
    longText?: string;
    manyItems?: unknown[];
    manyFields?: { truncatedFields?: number };
    deep?: { next?: { next?: { next?: { next?: { next?: { next?: { next?: string } } } } } } };
    openaiApiKey?: string;
    dangerousObject?: {
      visible?: string;
      hidden?: string;
      danger?: string;
      omittedSymbolProperties?: number;
    };
    dangerousArray?: unknown[];
    prototypeLike?: Record<string, unknown>;
    sharedA?: { sharedValue?: string };
    sharedB?: { sharedValue?: string };
    nested?: { authorization?: string; refresh_token?: string; harmless?: string };
  };
  assert.equal(objectGetterRan, false);
  assert.equal(arrayGetterRan, false);
  assert.ok(logged.ts !== "forged-ts");
  assert.equal(logged.level, "warn");
  assert.equal(logged.message, "safe log with tabs");
  assert.equal(Object.keys(logged).some((key) => /[\u0000-\u001f\u007f]/u.test(key)), false);
  assert.equal((logged as Record<string, unknown>)["bad key name"], "key control value");
  assert.equal((logged as Record<string, unknown>)["bad key name#2"], "key collision value");
  assert.equal(JSON.stringify(logged).includes("key-secret-token"), false);
  assert.equal(JSON.stringify(logged).includes("key-secret-token-2"), false);
  assert.equal(JSON.stringify(logged).includes("sk-keysecret123"), false);
  assert.equal((logged as Record<string, unknown>)["Authorization: Bearer [Redacted]"], "[Redacted]");
  assert.equal((logged as Record<string, unknown>)["Authorization: Bearer [Redacted]#2"], "[Redacted]");
  assert.equal((logged as Record<string, unknown>)["sk-[Redacted]"], "[Redacted]");
  assert.equal(Object.keys(logged).some((key) => key.includes("truncated") && key.length < 290), true);
  assert.equal(logged.circular?.self, "[Circular]");
  assert.equal(logged.count, "10");
  assert.match(logged.longText ?? "", /truncated/);
  assert.equal((logged.longText ?? "").includes("\u0002"), false);
  assert.equal(logged.manyItems?.length, 51);
  assert.equal(logged.manyItems?.[50], "[truncated 5 items]");
  assert.equal(logged.manyFields?.truncatedFields, 5);
  assert.equal(logged.deep?.next?.next?.next?.next?.next?.next?.next, "[MaxDepth]");
  assert.equal(JSON.stringify(logged).includes("sk-log-secret"), false);
  assert.equal(JSON.stringify(logged).includes("token-secret"), false);
  assert.equal(JSON.stringify(logged).includes("refresh-secret"), false);
  assert.equal(JSON.stringify(logged).includes("hidden-log-secret"), false);
  assert.equal(JSON.stringify(logged).includes("symbol-log-secret"), false);
  assert.equal(logged.openaiApiKey, "[Redacted]");
  assert.equal(logged.dangerousObject?.visible, "ok");
  assert.equal(logged.dangerousObject?.hidden, "[NonEnumerableOrAccessor]");
  assert.equal(logged.dangerousObject?.danger, "[NonEnumerableOrAccessor]");
  assert.equal(logged.dangerousObject?.omittedSymbolProperties, 1);
  assert.deepEqual(logged.dangerousArray, ["first", "[SparseArrayHole]", "[NonEnumerableOrAccessor]", "[SparseArrayHole]"]);
  assert.equal(Object.prototype.hasOwnProperty.call(logged.prototypeLike ?? {}, "__proto__"), true);
  assert.equal(((logged.prototypeLike?.__proto__ as { logged?: boolean }) ?? {}).logged, true);
  assert.equal(({} as { logged?: boolean }).logged, undefined);
  assert.equal(logged.sharedA?.sharedValue, "appears twice");
  assert.equal(logged.sharedB?.sharedValue, "appears twice");
  assert.equal(logged.nested?.authorization, "[Redacted]");
  assert.equal(logged.nested?.refresh_token, "[Redacted]");
  assert.equal(logged.nested?.harmless, "visible");
});

test("logger string and key output are capped by UTF-8 bytes", () => {
  const logger = new Logger("debug");
  const originalWrite = process.stderr.write;
  const output: string[] = [];
  process.stderr.write = ((chunk: string | Uint8Array) => {
    output.push(typeof chunk === "string" ? chunk : new TextDecoder().decode(chunk));
    return true;
  }) as typeof process.stderr.write;

  try {
    logger.warn("가".repeat(6000), {
      ["키".repeat(600)]: "값".repeat(6000)
    });
  } finally {
    process.stderr.write = originalWrite;
  }

  const logged = JSON.parse(output[0] ?? "{}") as Record<string, string>;
  assert.ok(testTextEncoder.encode(logged.message ?? "").length <= 16 * 1024);
  assert.match(logged.message ?? "", /truncated/);
  const multibyteKey = Object.keys(logged).find((key) => key.startsWith("키"));
  if (!multibyteKey) {
    throw new Error("Expected multibyte log key to be present.");
  }
  const safeMultibyteKey = multibyteKey;
  assert.ok(testTextEncoder.encode(safeMultibyteKey).length <= 1024);
  assert.match(safeMultibyteKey, /truncated/);
  assert.ok(testTextEncoder.encode(logged[safeMultibyteKey] ?? "").length <= 16 * 1024);
  assert.match(logged[safeMultibyteKey] ?? "", /truncated/);
});

test("logger output ignores polluted toJSON prototypes", () => {
  const logger = new Logger("debug");
  const originalWrite = process.stderr.write;
  const objectToJson = Object.getOwnPropertyDescriptor(Object.prototype, "toJSON");
  const arrayToJson = Object.getOwnPropertyDescriptor(Array.prototype, "toJSON");
  const output: string[] = [];
  process.stderr.write = ((chunk: string | Uint8Array) => {
    output.push(typeof chunk === "string" ? chunk : new TextDecoder().decode(chunk));
    return true;
  }) as typeof process.stderr.write;

  try {
    Object.defineProperty(Object.prototype, "toJSON", {
      configurable: true,
      value: () => ({ level: "error", message: "polluted sk-log-output-secret" })
    });
    Object.defineProperty(Array.prototype, "toJSON", {
      configurable: true,
      value: () => ["polluted", "sk-log-array-secret"]
    });
    logger.warn("real message", {
      items: ["first", "second"],
      detail: "safe"
    });
  } finally {
    process.stderr.write = originalWrite;
    if (objectToJson) {
      Object.defineProperty(Object.prototype, "toJSON", objectToJson);
    } else {
      delete (Object.prototype as { toJSON?: unknown }).toJSON;
    }
    if (arrayToJson) {
      Object.defineProperty(Array.prototype, "toJSON", arrayToJson);
    } else {
      delete (Array.prototype as { toJSON?: unknown }).toJSON;
    }
  }

  const text = output[0] ?? "";
  const logged = JSON.parse(text) as { level?: string; message?: string; items?: string[]; detail?: string };
  assert.equal(logged.level, "warn");
  assert.equal(logged.message, "real message");
  assert.deepEqual(logged.items, ["first", "second"]);
  assert.equal(logged.detail, "safe");
  assert.equal(text.includes("polluted"), false);
  assert.equal(text.includes("sk-log-output-secret"), false);
  assert.equal(text.includes("sk-log-array-secret"), false);
});

