test("inline secret redaction handles direct runtime inputs safely", () => {
  const redactedNumber = redactInlineSecrets(42 as unknown as string);
  assert.equal(redactedNumber, "42");
  const quotedBearer = redactInlineSecrets("Authorization: Bearer \"quoted-direct-secret\" and bearer 'single-direct-secret'");
  assert.equal(quotedBearer.includes("quoted-direct-secret"), false);
  assert.equal(quotedBearer.includes("single-direct-secret"), false);
  assert.match(quotedBearer, /Bearer "\[Redacted\]"/);
  assert.match(quotedBearer, /Bearer '\[Redacted\]'/);

  let objectToStringRan = false;
  const redactedObject = redactInlineSecrets({
    toString() {
      objectToStringRan = true;
      return "Authorization: Bearer direct-secret-token Authorization: Basic direct-basic-secret Authorization=Token direct-token-secret api_key=direct-api-secret sk-directsecret123";
    }
  } as unknown as string);
  assert.equal(objectToStringRan, false);
  assert.equal(redactedObject, "[Object]");
  assert.equal(redactedObject.includes("direct-secret-token"), false);
  assert.equal(redactedObject.includes("direct-basic-secret"), false);
  assert.equal(redactedObject.includes("direct-token-secret"), false);
  assert.equal(redactedObject.includes("direct-api-secret"), false);
  assert.equal(redactedObject.includes("sk-directsecret123"), false);

  const directToken = redactInlineSecrets("token=direct-token-secret token: 'quoted-token-secret'");
  assert.equal(directToken.includes("direct-token-secret"), false);
  assert.equal(directToken.includes("quoted-token-secret"), false);
  assert.match(directToken, /token=\[Redacted\]/);
  assert.match(directToken, /token: '\[Redacted\]'/);

  const camelCaseSecrets = redactInlineSecrets(
    "apiKey=camel-api-secret openaiApiKey: 'camel-openai-secret' xApiKey=camel-x-secret " +
      "accessToken=camel-access-secret refreshToken=camel-refresh-secret clientSecret=camel-client-secret"
  );
  assert.equal(camelCaseSecrets.includes("camel-api-secret"), false);
  assert.equal(camelCaseSecrets.includes("camel-openai-secret"), false);
  assert.equal(camelCaseSecrets.includes("camel-x-secret"), false);
  assert.equal(camelCaseSecrets.includes("camel-access-secret"), false);
  assert.equal(camelCaseSecrets.includes("camel-refresh-secret"), false);
  assert.equal(camelCaseSecrets.includes("camel-client-secret"), false);
  assert.match(camelCaseSecrets, /apiKey=\[Redacted\]/);
  assert.match(camelCaseSecrets, /openaiApiKey: '\[Redacted\]'/);
  assert.match(camelCaseSecrets, /xApiKey=\[Redacted\]/);
  assert.match(camelCaseSecrets, /accessToken=\[Redacted\]/);
  assert.match(camelCaseSecrets, /refreshToken=\[Redacted\]/);
  assert.match(camelCaseSecrets, /clientSecret=\[Redacted\]/);

  const directJwt = redactInlineSecrets("jwt eyJhbGciOiJIUzI1NiJ9.eyJzdWIiOiJkaXJlY3QifQ.directsignaturesecret");
  assert.equal(directJwt.includes("directsignaturesecret"), false);
  assert.match(directJwt, /\[Redacted JWT\]/);

  const providerTokens = redactInlineSecrets(
    "provider keys AIzaSyDirectRuntimeSecret1234567890 ghp_directruntimesecret1234567890 github_pat_11DIRECTRUNTIMESECRET1234567890"
  );
  assert.equal(providerTokens.includes("AIzaSyDirectRuntimeSecret1234567890"), false);
  assert.equal(providerTokens.includes("ghp_directruntimesecret1234567890"), false);
  assert.equal(providerTokens.includes("github_pat_11DIRECTRUNTIMESECRET1234567890"), false);
  assert.match(providerTokens, /AIza\[Redacted\]/);
  assert.match(providerTokens, /gh\[Redacted\]/);
  assert.match(providerTokens, /github_pat_\[Redacted\]/);

  const awsSecrets = redactInlineSecrets(
    "aws keys AKIA1234567890ABCDEF ASIA1234567890ABCDEF " +
      "aws_secret_access_key=aws-secret-value awsSecretAccessKey: 'camel-aws-secret' awsAccessKeyId=field-access-key"
  );
  assert.equal(awsSecrets.includes("AKIA1234567890ABCDEF"), false);
  assert.equal(awsSecrets.includes("ASIA1234567890ABCDEF"), false);
  assert.equal(awsSecrets.includes("aws-secret-value"), false);
  assert.equal(awsSecrets.includes("camel-aws-secret"), false);
  assert.equal(awsSecrets.includes("field-access-key"), false);
  assert.match(awsSecrets, /AWS\[Redacted\]/);
  assert.match(awsSecrets, /aws_secret_access_key=\[Redacted\]/);
  assert.match(awsSecrets, /awsSecretAccessKey: '\[Redacted\]'/);
  assert.match(awsSecrets, /awsAccessKeyId=\[Redacted\]/);

  const oversized = redactInlineSecrets(`${"x".repeat(1024 * 1024 + 10)} Authorization: Bearer oversized-secret-token`);
  assert.match(oversized, /truncated 55 chars before redaction/);
  assert.ok(testTextEncoder.encode(oversized).length <= 1024 * 1024);
  assert.equal(oversized.includes("oversized-secret-token"), false);

  const oversizedMultibyte = redactInlineSecrets(`${"가".repeat(350000)} Authorization: Bearer oversized-byte-secret`);
  assert.match(oversizedMultibyte, /truncated \d+ UTF-8 bytes before redaction/);
  assert.ok(testTextEncoder.encode(oversizedMultibyte).length <= 1024 * 1024);
  assert.equal(oversizedMultibyte.includes("oversized-byte-secret"), false);

  const boundarySecret = redactInlineSecrets(`${"x".repeat(1024 * 1024 - 5)}sk-boundarysecret123`);
  assert.match(boundarySecret, /truncated 15 chars before redaction/);
  assert.equal(boundarySecret.includes("sk-boundarysecret123"), false);
  assert.equal(boundarySecret.includes("boundarysecret123"), false);

  const throwingToString = {
    toString() {
      throw new Error("toString leaked Authorization: Bearer tostring-secret-token");
    }
  };
  assert.equal(redactInlineSecrets(throwingToString), "[Object]");

  let primitiveGetterRan = false;
  const throwingPrimitive = {
    [Symbol.toPrimitive]() {
      primitiveGetterRan = true;
      throw new Error("primitive leaked sk-primitivesecret123");
    }
  };
  assert.equal(redactInlineSecrets(throwingPrimitive), "[Object]");
  assert.equal(primitiveGetterRan, false);

  const directError = new Error("Authorization: Bearer direct-error-secret");
  assert.equal(redactInlineSecrets(directError), "[Object]");

  const accessorError = new Error("safe");
  let errorMessageGetterRan = false;
  Object.defineProperty(accessorError, "message", {
    enumerable: true,
    get() {
      errorMessageGetterRan = true;
      throw new Error("error message getter must not run");
    }
  });
  assert.equal(redactInlineSecrets(accessorError), "[Object]");
  assert.equal(errorMessageGetterRan, false);

  const secretError = new Error("Authorization: Bearer error-helper-secret and sk-errorhelper123");
  const redactedError = redactErrorMessage(secretError);
  assert.equal(redactedError.includes("error-helper-secret"), false);
  assert.equal(redactedError.includes("sk-errorhelper123"), false);
  assert.match(redactedError, /Bearer \[Redacted\]/);
  assert.match(redactedError, /sk-\[Redacted\]/);

  let helperMessageGetterRan = false;
  let helperNameGetterRan = false;
  const accessorHelperError = new Error("safe");
  Object.defineProperty(accessorHelperError, "message", {
    enumerable: true,
    get() {
      helperMessageGetterRan = true;
      throw new Error("redact error helper message getter must not run");
    }
  });
  Object.defineProperty(accessorHelperError, "name", {
    enumerable: true,
    get() {
      helperNameGetterRan = true;
      throw new Error("redact error helper name getter must not run");
    }
  });
  assert.equal(redactErrorMessage(accessorHelperError), "[Object]");
  assert.equal(helperMessageGetterRan, false);
  assert.equal(helperNameGetterRan, false);
});

test("logger validates direct level and coerces runtime message values safely", () => {
  assert.throws(
    () => new Logger("verbose" as unknown as ConstructorParameters<typeof Logger>[0]),
    /Logger\.level must be one of debug, info, warn, error, or silent/
  );

  const logger = new Logger("debug");
  const originalWrite = process.stderr.write;
  const output: string[] = [];
  process.stderr.write = ((chunk: string | Uint8Array) => {
    output.push(typeof chunk === "string" ? chunk : new TextDecoder().decode(chunk));
    return true;
  }) as typeof process.stderr.write;

  try {
    logger.warn(42 as unknown as string, { detail: "ok" });
    logger.warn({
      toString() {
        throw new Error("logger message leaked Authorization: Bearer logger-tostring-secret");
      }
    } as unknown as string);
  } finally {
    process.stderr.write = originalWrite;
  }

  const logged = JSON.parse(output[0] ?? "{}") as { message?: string; detail?: string };
  const unstringifiable = JSON.parse(output[1] ?? "{}") as { message?: string };
  assert.equal(logged.message, "42");
  assert.equal(logged.detail, "ok");
  assert.equal(unstringifiable.message, "[Object]");
});

test("logger treats repeated stderr write failures as best-effort", () => {
  const logger = new Logger("debug");
  const originalWrite = process.stderr.write;
  let writes = 0;
  process.stderr.write = (() => {
    writes += 1;
    throw new Error(`stderr unavailable Authorization: Bearer logger-write-secret-${writes}`);
  }) as typeof process.stderr.write;

  let thrown: unknown;
  try {
    logger.warn("write failure should not escape", { detail: "ok" });
  } catch (error) {
    thrown = error;
  } finally {
    process.stderr.write = originalWrite;
  }

  assert.equal(thrown, undefined);
  assert.equal(writes, 2);
});

test("concurrent continue calls are serialized per volume", async () => {
  const pipeline = pipelineInTemp(new DelayedAgents());
  const created = await pipeline.newProject({
    franchiseName: "동시성 세계",
    workRequest: "동시성 작품"
  });
  const data = created.data as { confirmationId: string; franchiseId: string; workId: string; volumeId: string };
  await pipeline.confirm({ confirmationId: data.confirmationId, approved: true });

  await Promise.all([
    pipeline.continue({ franchiseId: data.franchiseId, workId: data.workId, volumeId: data.volumeId }),
    pipeline.continue({ franchiseId: data.franchiseId, workId: data.workId, volumeId: data.volumeId })
  ]);

  const status = await pipeline.status({
    franchiseId: data.franchiseId,
    workId: data.workId,
    volumeId: data.volumeId
  });
  const summary = status.data as { completedBeats: number };
  assert.equal(summary.completedBeats, 3);
});

