test("documented environment variables match runtime configuration inputs", async () => {
  const configSource = await readFile(join(process.cwd(), "src", "config.ts"), "utf8");
  const readme = await readFile(join(process.cwd(), "README.md"), "utf8");
  const runtimeNames = sortedUnique([...configSource.matchAll(/readEnv\("([A-Z0-9_]+)"\)/g)].map((match) => match[1]!));
  const documentedNames = sortedUnique([...readme.matchAll(/^- `(NOVELIST_[A-Z0-9_]+)`:/gm)].map((match) => match[1]!));

  assert.deepEqual(documentedNames, runtimeNames);
});

