test("configuration reads environment values without invoking accessors", () => {
  let getterRan = false;
  const accessorEnv = Object.defineProperty({}, "NOVELIST_LOG_LEVEL", {
    enumerable: true,
    get() {
      getterRan = true;
      throw new Error("environment getter must not run");
    }
  }) as Record<string, string | undefined>;
  const hiddenEnv = Object.defineProperty({}, "NOVELIST_LOG_LEVEL", {
    value: "info",
    enumerable: false
  }) as Record<string, string | undefined>;

  assert.throws(
    () => loadConfig(accessorEnv),
    /NOVELIST_LOG_LEVEL environment value must be an enumerable data property/
  );
  assert.equal(getterRan, false);
  assert.throws(
    () => loadConfig(hiddenEnv),
    /NOVELIST_LOG_LEVEL environment value must be an enumerable data property/
  );
  assert.throws(
    () => loadConfig({ NOVELIST_LOG_LEVEL: 42 } as unknown as Record<string, string | undefined>),
    /NOVELIST_LOG_LEVEL environment value must be a string/
  );
});

test("configuration wraps unreadable environment reflection failures", () => {
  assert.throws(
    () => loadConfig(new Proxy({}, {
      getPrototypeOf() {
        throw new Error("leaked prototype trap Authorization: Bearer config-proxy-secret");
      }
    }) as Record<string, string | undefined>),
    /Configuration environment prototype must be readable/
  );

  assert.throws(
    () => loadConfig(new Proxy({}, {
      ownKeys() {
        throw new Error("leaked ownKeys trap Authorization: Bearer config-proxy-secret");
      }
    }) as Record<string, string | undefined>),
    /Configuration environment keys must be readable/
  );

  assert.throws(
    () => loadConfig(new Proxy({ NOVELIST_LOG_LEVEL: "info" }, {
      getOwnPropertyDescriptor() {
        throw new Error("leaked descriptor trap Authorization: Bearer config-proxy-secret");
      }
    }) as Record<string, string | undefined>),
    /Configuration environment property descriptors must be readable/
  );
});

test("configuration ignores inherited environment values without invoking accessors", () => {
  let inheritedGetterRan = false;
  const inheritedNames = ["NOVELIST_LOG_LEVEL", "NOVELIST_OPENAI_API_KEY"] as const;
  const previousDescriptors = inheritedNames.map((name) => Object.getOwnPropertyDescriptor(Object.prototype, name));

  try {
    Object.defineProperty(Object.prototype, "NOVELIST_LOG_LEVEL", {
      configurable: true,
      value: "debug"
    });
    Object.defineProperty(Object.prototype, "NOVELIST_OPENAI_API_KEY", {
      configurable: true,
      get() {
        inheritedGetterRan = true;
        throw new Error("inherited environment getter must not run");
      }
    });

    const config = loadConfig({});

    assert.equal(config.logLevel, "warn");
    assert.equal(config.openaiApiKey, undefined);
    assert.equal(inheritedGetterRan, false);
  } finally {
    for (let index = 0; index < inheritedNames.length; index += 1) {
      const name = inheritedNames[index];
      const descriptor = previousDescriptors[index];
      if (descriptor) {
        Object.defineProperty(Object.prototype, name, descriptor);
      } else {
        delete (Object.prototype as Record<string, unknown>)[name];
      }
    }
  }
});

test("configuration rejects hidden environment object properties before reading values", () => {
  let unusedGetterRan = false;
  const accessorEnv = Object.defineProperty({}, "UNUSED_ENV_GETTER", {
    enumerable: true,
    get() {
      unusedGetterRan = true;
      throw new Error("unused environment getter must not run");
    }
  }) as Record<string, string | undefined>;
  const hiddenEnv = Object.defineProperty({}, "UNUSED_ENV_HIDDEN", {
    value: "secret",
    enumerable: false
  }) as Record<string, string | undefined>;
  const symbolEnv = {
    [Symbol("env")]: "secret"
  } as unknown as Record<string, string | undefined>;

  assert.throws(
    () => loadConfig(accessorEnv),
    /UNUSED_ENV_GETTER environment value must be an enumerable data property/
  );
  assert.equal(unusedGetterRan, false);
  assert.throws(
    () => loadConfig(hiddenEnv),
    /UNUSED_ENV_HIDDEN environment value must be an enumerable data property/
  );
  assert.throws(
    () => loadConfig(symbolEnv),
    /Configuration environment must not contain symbol properties/
  );
});

