test("storage rejects malformed direct config object surfaces", () => {
  const config = { ...loadConfig({}) };
  const extraConfig = { ...config, unsupported: true };
  const symbolConfig = { ...config } as Record<string | symbol, unknown>;
  symbolConfig[Symbol("storage")] = true;
  let unrelatedGetterRan = false;
  const accessorConfig = { ...config };
  Object.defineProperty(accessorConfig, "openaiApiKey", {
    enumerable: true,
    get() {
      unrelatedGetterRan = true;
      throw new Error("storage config unrelated getter must not run");
    }
  });

  assert.throws(
    () => new NovelStorage(extraConfig as unknown as ConstructorParameters<typeof NovelStorage>[0]),
    /NovelStorage\.unsupported is not a supported config field/
  );
  assert.throws(
    () => new NovelStorage(symbolConfig as unknown as ConstructorParameters<typeof NovelStorage>[0]),
    /NovelStorage config must not contain symbol properties/
  );
  assert.throws(
    () => new NovelStorage(new Date() as unknown as ConstructorParameters<typeof NovelStorage>[0]),
    /NovelStorage config must be a plain object/
  );
  assert.throws(
    () => new NovelStorage(accessorConfig),
    /NovelStorage\.openaiApiKey must be an enumerable data property/
  );
  assert.equal(unrelatedGetterRan, false);
  assert.throws(
    () => new NovelStorage(new Proxy({}, {
      getPrototypeOf() {
        throw new Error("leaked storage prototype trap Authorization: Bearer storage-config-secret");
      }
    }) as ConstructorParameters<typeof NovelStorage>[0]),
    /NovelStorage config prototype must be readable/
  );
  assert.throws(
    () => new NovelStorage(new Proxy(config, {
      ownKeys() {
        throw new Error("leaked storage ownKeys trap Authorization: Bearer storage-config-secret");
      }
    }) as ConstructorParameters<typeof NovelStorage>[0]),
    /NovelStorage config keys must be readable/
  );
  assert.throws(
    () => new NovelStorage(new Proxy(config, {
      getOwnPropertyDescriptor() {
        throw new Error("leaked storage descriptor trap Authorization: Bearer storage-config-secret");
      }
    }) as ConstructorParameters<typeof NovelStorage>[0]),
    /NovelStorage config property descriptors must be readable/
  );
});

