test("configuration requires EPUB validator args to reference the generated file", () => {
  assert.throws(
    () =>
      loadConfig({
        NOVELIST_EPUBCHECK_COMMAND: "/bin/true",
        NOVELIST_EPUBCHECK_ARGS: "--version"
      }),
    /EPUBCHECK_ARGS.*exactly one \{epub\}/
  );
  assert.throws(
    () =>
      loadConfig({
        NOVELIST_EPUBCHECK_COMMAND: "/bin/true",
        NOVELIST_EPUBCHECK_ARGS: JSON.stringify(["{epub}", "--also", "{epub}"])
      }),
    /EPUBCHECK_ARGS.*exactly one \{epub\}/
  );
  assert.throws(
    () =>
      loadConfig({
        NOVELIST_EPUBCHECK_ARGS: "--version"
      }),
    /EPUBCHECK_ARGS requires NOVELIST_EPUBCHECK_COMMAND/
  );
  assert.deepEqual(
    loadConfig({
      NOVELIST_EPUBCHECK_COMMAND: "/usr/bin/java",
      NOVELIST_EPUBCHECK_ARGS: JSON.stringify(["-jar", "/path with spaces/epubcheck.jar", "{epub}"])
    }).epubCheckArgs,
    ["-jar", "/path with spaces/epubcheck.jar", "{epub}"]
  );
  assert.equal(loadConfig({
    NOVELIST_EPUBCHECK_COMMAND: "java",
    NOVELIST_EPUBCHECK_ARGS: "-jar checker.jar {epub}"
  }).epubCheckCommand, "java");
  assert.equal(loadConfig({
    NOVELIST_EPUBCHECK_COMMAND: "epubcheck-cli_3.0",
    NOVELIST_EPUBCHECK_ARGS: "{epub}"
  }).epubCheckCommand, "epubcheck-cli_3.0");
  assert.throws(
    () =>
      loadConfig({
        NOVELIST_EPUBCHECK_COMMAND: "/bin/true",
        NOVELIST_EPUBCHECK_ARGS: "[bad json"
      }),
    /JSON array is malformed/
  );
  assert.throws(
    () =>
      loadConfig({
        NOVELIST_EPUBCHECK_COMMAND: "/bin/true",
        NOVELIST_EPUBCHECK_ARGS: '[{"arg":"{epub}","arg":"shadow"}]'
      }),
    /duplicate object keys/
  );
  assert.throws(
    () =>
      loadConfig({
        NOVELIST_EPUBCHECK_COMMAND: "/bin/true",
        NOVELIST_EPUBCHECK_ARGS: `${"[".repeat(70)}"{epub}"${"]".repeat(70)}`
      }),
    /nested at most 64 levels/
  );
  assert.throws(
    () =>
      loadConfig({
        NOVELIST_EPUBCHECK_COMMAND: "/bin/true",
        NOVELIST_EPUBCHECK_ARGS: JSON.stringify(["{epub}", "bad\narg"])
      }),
    /must not contain control characters/
  );
  assert.throws(
    () =>
      loadConfig({
        NOVELIST_EPUBCHECK_COMMAND: "/bin/true",
        NOVELIST_EPUBCHECK_ARGS: "{epub} bad\u0001arg"
      }),
    /must not contain control characters/
  );
  assert.throws(
    () =>
      loadConfig({
        NOVELIST_EPUBCHECK_COMMAND: "/bin/true",
        NOVELIST_EPUBCHECK_ARGS: JSON.stringify(["{epub}", " spaced"])
      }),
    /must not have leading or trailing whitespace/
  );
  assert.throws(
    () =>
      loadConfig({
        NOVELIST_EPUBCHECK_COMMAND: "/bin/true",
        NOVELIST_EPUBCHECK_ARGS: JSON.stringify(["{epub}", "spaced "])
      }),
    /must not have leading or trailing whitespace/
  );
  assert.throws(
    () =>
      loadConfig({
        NOVELIST_EPUBCHECK_COMMAND: "/bin/true",
        NOVELIST_EPUBCHECK_ARGS: JSON.stringify(Array.from({ length: 65 }, (_, index) => `arg-${index}`))
      }),
    /at most 64 arguments/
  );
  assert.throws(
    () =>
      loadConfig({
        NOVELIST_EPUBCHECK_COMMAND: "/bin/true",
        NOVELIST_EPUBCHECK_ARGS: JSON.stringify(["{epub}", "x".repeat(4097)])
      }),
    /at most 4096 characters/
  );
  assert.throws(
    () =>
      loadConfig({
        NOVELIST_EPUBCHECK_COMMAND: "/bin/true",
        NOVELIST_EPUBCHECK_ARGS: JSON.stringify(["{epub}", "가".repeat(1366)])
      }),
    /at most 4096 UTF-8 bytes/
  );
  assert.throws(
    () =>
      loadConfig({
        NOVELIST_EPUBCHECK_COMMAND: "/bin/tr\nue",
        NOVELIST_EPUBCHECK_ARGS: "{epub}"
      }),
    /EPUBCHECK_COMMAND.*control characters/
  );
  assert.throws(
    () =>
      loadConfig({
        NOVELIST_EPUBCHECK_COMMAND: "java -jar",
        NOVELIST_EPUBCHECK_ARGS: "{epub}"
      }),
    /EPUBCHECK_COMMAND.*without whitespace/
  );
  assert.throws(
    () =>
      loadConfig({
        NOVELIST_EPUBCHECK_COMMAND: "./epubcheck",
        NOVELIST_EPUBCHECK_ARGS: "{epub}"
      }),
    /EPUBCHECK_COMMAND.*absolute executable path/
  );
  assert.throws(
    () =>
      loadConfig({
        NOVELIST_EPUBCHECK_COMMAND: "-epubcheck",
        NOVELIST_EPUBCHECK_ARGS: "{epub}"
      }),
    /EPUBCHECK_COMMAND PATH command names/
  );
  assert.throws(
    () =>
      loadConfig({
        NOVELIST_EPUBCHECK_COMMAND: "epubcheck;rm",
        NOVELIST_EPUBCHECK_ARGS: "{epub}"
      }),
    /EPUBCHECK_COMMAND PATH command names/
  );
  assert.throws(
    () =>
      loadConfig({
        NOVELIST_EPUBCHECK_COMMAND: "..",
        NOVELIST_EPUBCHECK_ARGS: "{epub}"
      }),
    /EPUBCHECK_COMMAND PATH command names/
  );
  assert.throws(
    () =>
      loadConfig({
        NOVELIST_EPUBCHECK_COMMAND: "x".repeat(1025),
        NOVELIST_EPUBCHECK_ARGS: "{epub}"
      }),
    /EPUBCHECK_COMMAND.*at most 1024/
  );
  assert.throws(
    () =>
      loadConfig({
        NOVELIST_EPUBCHECK_COMMAND: "가".repeat(342),
        NOVELIST_EPUBCHECK_ARGS: "{epub}"
      }),
    /EPUBCHECK_COMMAND.*at most 1024 UTF-8 bytes/
  );
  assert.throws(
    () =>
      loadConfig({
        NOVELIST_EPUBCHECK_COMMAND: "/bin/true",
        NOVELIST_EPUBCHECK_ARGS: `${" ".repeat(1)}${"["}${"x".repeat(300 * 1024)}`
      }),
    /EPUBCHECK_ARGS.*at most 307200 characters/
  );
  assert.throws(
    () =>
      loadConfig({
        NOVELIST_EPUBCHECK_COMMAND: "/bin/true",
        NOVELIST_EPUBCHECK_ARGS: " ".repeat(300 * 1024 + 1)
      }),
    /EPUBCHECK_ARGS.*at most 307200 characters/
  );
  assert.throws(
    () =>
      loadConfig({
        NOVELIST_EPUBCHECK_COMMAND: "/bin/true",
        NOVELIST_EPUBCHECK_ARGS: "가".repeat(102401)
      }),
    /EPUBCHECK_ARGS.*at most 307200 UTF-8 bytes/
  );
});

