test("GitHub workflows keep CI and release permissions bounded", async () => {
  const testWorkflow = await readFile(join(process.cwd(), ".github", "workflows", "test.yml"), "utf8");
  const releaseWorkflow = await readFile(join(process.cwd(), ".github", "workflows", "release.yml"), "utf8");

  assert.match(testWorkflow, /timeout-minutes:\s*10/);
  assert.match(testWorkflow, /permissions:\s*\n\s*contents:\s*read/);
  assert.match(testWorkflow, /uses:\s*actions\/checkout@v4\.2\.2/);
  assert.match(testWorkflow, /persist-credentials:\s*false/);
  assert.match(testWorkflow, /uses:\s*actions\/setup-node@v4\.4\.0/);
  assert.equal(/uses:\s*actions\/(?:checkout|setup-node)@v4(?:\s|$)/.test(testWorkflow), false);
  assert.match(testWorkflow, /npm ci --cache \/tmp\/novelist-npm-cache/);
  assert.match(testWorkflow, /npm run verify/);

  assert.match(releaseWorkflow, /timeout-minutes:\s*10/);
  assert.match(releaseWorkflow, /contents:\s*read/);
  assert.match(releaseWorkflow, /id-token:\s*write/);
  assert.match(releaseWorkflow, /uses:\s*actions\/checkout@v4\.2\.2/);
  assert.match(releaseWorkflow, /persist-credentials:\s*false/);
  assert.match(releaseWorkflow, /uses:\s*actions\/setup-node@v4\.4\.0/);
  assert.equal(/uses:\s*actions\/(?:checkout|setup-node)@v4(?:\s|$)/.test(releaseWorkflow), false);
  assert.match(releaseWorkflow, /npm run verify/);
  assert.match(releaseWorkflow, /npm publish --provenance --access public --ignore-scripts/);
});

test("pack check script streams npm pack metadata instead of sharing a fixed temporary path", async () => {
  const packageJson = JSON.parse(await readFile(join(process.cwd(), "package.json"), "utf8")) as {
    scripts?: { "pack:check"?: unknown };
  };
  const packCheck = await readFile(join(process.cwd(), "scripts", "pack-check.mjs"), "utf8");

  assert.equal(
    packageJson.scripts?.["pack:check"],
    "npm run build && npm pack --dry-run --json --cache /tmp/novelist-npm-cache | node scripts/pack-check.mjs -"
  );
  assert.match(packCheck, /function readJsonInput\(path, label, maxBytes\)/);
  assert.match(packCheck, /function readTextFile\(path, label, maxBytes\)/);
  assert.match(packCheck, /function readTextFileRecord\(path, label, maxBytes\)/);
  assert.match(packCheck, /function assertFileUnchanged\(fd, expected, label\)/);
  assert.match(packCheck, /assertFileUnchanged\(fd, stats, label\)/);
  assert.match(packCheck, /if \(path !== "-"\)/);
  assert.match(packCheck, /function readBoundedStdin\(label, maxBytes\)/);
  assert.match(packCheck, /readSync\(0, buffer, 0, buffer\.length, null\)/);
  assert.match(packCheck, /const MAX_PACK_JSON_PATH_BYTES = 4096/);
  assert.match(packCheck, /const MAX_PACK_FILE_PATH_BYTES = 4096/);
  assert.match(packCheck, /const MAX_PACKAGE_DESCRIPTION_BYTES = 256/);
  assert.match(packCheck, /const MAX_PACKAGE_VERSION_BYTES = 128/);
  assert.match(packCheck, /const MAX_JSON_OBJECT_KEY_BYTES = 2048/);
  assert.match(packCheck, /const MAX_JSON_STRING_BYTES = 1024 \* 1024/);
  assert.match(packCheck, /const MAX_ERROR_MESSAGE_BYTES = 1000/);
  assert.match(packCheck, /function validatedJsonRpcResponse\(value\)/);
  assert.match(packCheck, /function directErrorResponse\(id, code, message\)/);
  assert.match(packCheck, /async loadCurrentState\(\)/);
  assert.match(packCheck, /validateCurrentPointer\(value\)/);
  assert.match(packCheck, /assertKnownFields\(pointer, \\"current pointer\\", \[\\"franchiseId\\", \\"workId\\", \\"volumeId\\"\]\)/);
  assert.match(packCheck, /name: \\"novel_health\\"/);
  assert.match(packCheck, /name: \\"novel_build_epub\\"/);
  assert.match(packCheck, /toolName: \\"novel_new_project\\"/);
  assert.match(packCheck, /toolName: \\"novel_build_epub\\"/);
  assert.match(packCheck, /function utf8ByteLength\(value\)/);
  assert.match(packCheck, /function truncatePackCheckMessageWithMarker\(value, marker, maxChars, maxBytes\)/);
  assert.match(packCheck, /function validatePackageFilesMetadata\(value\)/);
  assert.match(packCheck, /const binRecord = readTextFileRecord\(binPath, "dist\/src\/cli\.js", MAX_PACK_FILE_SIZE_BYTES\)/);
  assert.match(packCheck, /const mode = binRecord\.stats\.mode & 0o777/);
  assert.match(packCheck, /const versionArtifact = readTextFile\("dist\/src\/version\.js", "dist\/src\/version\.js", MAX_PACK_FILE_SIZE_BYTES\)/);
  assert.match(packCheck, /existsSync\("package-lock\.json"\)/);
  assert.match(packCheck, /package-lock\.json root package bin must match package\.json bin/);
  assert.match(packCheck, /package-lock\.json requires must be true/);
  assert.equal(packCheck.includes('readFileSync(0, "utf8")'), false);
  assert.equal(packCheck.includes('const bin = readFileSync(binPath, "utf8")'), false);
  assert.equal(String(packageJson.scripts?.["pack:check"]).includes("/tmp/novelist-pack.json"), false);
  assert.equal(String(packageJson.scripts?.["pack:check"]).includes(">"), false);
});

test("package lock root metadata matches publishable package entrypoints", async () => {
  const packageJson = JSON.parse(await readFile(join(process.cwd(), "package.json"), "utf8")) as {
    name?: unknown;
    version?: unknown;
    license?: unknown;
    bin?: unknown;
    engines?: unknown;
    devDependencies?: unknown;
  };
  const packageLock = JSON.parse(await readFile(join(process.cwd(), "package-lock.json"), "utf8")) as {
    name?: unknown;
    version?: unknown;
    lockfileVersion?: unknown;
    requires?: unknown;
    packages?: Record<string, unknown>;
  };
  const rootPackage = packageLock.packages?.[""] as {
    name?: unknown;
    version?: unknown;
    license?: unknown;
    bin?: unknown;
    engines?: unknown;
    devDependencies?: unknown;
  } | undefined;

  assert.equal(packageLock.name, packageJson.name);
  assert.equal(packageLock.version, packageJson.version);
  assert.equal(packageLock.lockfileVersion, 3);
  assert.equal(packageLock.requires, true);
  assert.equal(packageJson.license, "MIT");
  assert.equal(rootPackage?.license, packageJson.license);
  assert.deepEqual(rootPackage?.bin, packageJson.bin);
  assert.deepEqual(rootPackage?.engines, packageJson.engines);
  assert.deepEqual(rootPackage?.devDependencies, packageJson.devDependencies);
  assert.deepEqual(Object.keys(packageLock.packages ?? {}).sort(), ["", "node_modules/typescript"]);
});

