test("pack check reports malformed JSON metadata with a bounded diagnostic", async () => {
  const root = testRoot("novelist-pack-check-json-malformed-test");
  await mkdir(root, { recursive: true });
  await writeFile(join(root, "package.json"), `{"name":"novelist-mcp","bad":"${"x".repeat(2000)}`, "utf8");
  await writeFile(join(root, "pack.json"), "[]", "utf8");

  await assertRejects(
    execFilePromise(process.execPath, [join(process.cwd(), "scripts", "pack-check.mjs"), "pack.json"], root),
    /package\.json must contain valid JSON/
  );

  await writeFile(join(root, "package.json"), `{"name":"novelist-mcp","bad":"${"가".repeat(600)}`, "utf8");
  try {
    await execFilePromise(process.execPath, [join(process.cwd(), "scripts", "pack-check.mjs"), "pack.json"], root);
    throw new Error("pack check should reject malformed multibyte JSON");
  } catch (error) {
    const message = String((error as Error).message);
    assert.match(message, /package\.json must contain valid JSON/);
    assert.ok(testTextEncoder.encode(message).length < 1800, `diagnostic was not byte-bounded: ${testTextEncoder.encode(message).length}`);
  }
});

