test("pack check rejects unreviewed external validator runtime artifact content", async () => {
  const root = testRoot("novelist-pack-check-external-validator-runtime-content-test");
  await mkdir(join(root, "dist", "src"), { recursive: true });
  await mkdir(join(root, "src"), { recursive: true });
  await writeFile(join(root, "README.md"), "# Test\n", "utf8");
  for (const file of ["cli", "index", "mcp", "pipeline", "externalEpubCheck"]) {
    await writeFile(join(root, "src", `${file}.ts`), "export {};\n", "utf8");
    await writeFile(join(root, "dist", "src", `${file}.js`), file === "cli" ? REVIEWED_CLI_FIXTURE : file === "mcp" ? REVIEWED_MCP_FIXTURE : file === "pipeline" ? REVIEWED_PIPELINE_FIXTURE : "export {};\n", "utf8");
    await writeFile(join(root, "dist", "src", `${file}.d.ts`), "export {};\n", "utf8");
  }
  await execFilePromise("chmod", ["755", join(root, "dist", "src", "cli.js")], root);
  await writeFile(join(root, "package.json"), JSON.stringify({
    name: "novelist-mcp",
    version: "0.1.0",
    description: "test package",
    license: "MIT",
    type: "module",
    engines: { node: ">=22.0.0" },
    main: "dist/src/index.js",
    types: "dist/src/index.d.ts",
    exports: { ".": { types: "./dist/src/index.d.ts", import: "./dist/src/index.js" } },
    bin: { "novelist-mcp": "dist/src/cli.js" },
    files: ["dist/src", "README.md", "package.json"]
  }), "utf8");
  await writeFile(join(root, "pack.json"), JSON.stringify([{ files: [
    { path: "README.md" },
    { path: "dist/src/cli.js", mode: 0o755 },
    { path: "dist/src/cli.d.ts", mode: 0o644 },
    { path: "package.json" },
    { path: "dist/src/index.js", mode: 0o644 },
    { path: "dist/src/index.d.ts", mode: 0o644 },
    { path: "dist/src/mcp.js", mode: 0o644 },
    { path: "dist/src/mcp.d.ts", mode: 0o644 },
    { path: "dist/src/pipeline.js", mode: 0o644 },
    { path: "dist/src/pipeline.d.ts", mode: 0o644 },
    { path: "dist/src/externalEpubCheck.js", mode: 0o644 },
    { path: "dist/src/externalEpubCheck.d.ts", mode: 0o644 }
  ] }]), "utf8");

  await assertRejects(
    execFilePromise(process.execPath, [join(process.cwd(), "scripts", "pack-check.mjs"), "pack.json"], root),
    /dist\/src\/externalEpubCheck\.js must contain reviewed external validator runtime code/
  );
});

