test("EPUB build runs configured external validator", async () => {
  const storage = new NovelStorage(testRoot("novelist-epubcheck-test"));
  const pipeline = new NovelPipeline(storage, new StubNovelAgents(), {
    ...loadConfig({}),
    epubCheckCommand: "/bin/true",
    epubCheckArgs: ["{epub}"]
  });
  const data = await completeTinyVolume(pipeline);

  const epub = await pipeline.buildEpub(data);
  const validation = (epub.data as { validation: { external: { configured: boolean; valid: boolean } } }).validation;

  assert.equal(validation.external.configured, true);
  assert.equal(validation.external.valid, true);
});

test("EPUB build reports resolved external validator commands after redaction", async () => {
  const storage = new NovelStorage(testRoot("novelist-epubcheck-resolved-command-test"));
  await mkdir(storage.root, { recursive: true });
  const commandPath = join(storage.root, "validator-link");
  await symlink("/bin/true", commandPath);
  const pipeline = new NovelPipeline(storage, new StubNovelAgents(), {
    ...loadConfig({}),
    epubCheckCommand: commandPath,
    epubCheckArgs: ["{epub}"]
  });
  const data = await completeTinyVolume(pipeline);

  const epub = await pipeline.buildEpub(data);
  const external = (epub.data as {
    validation: { external: { command?: string; resolvedCommand?: string; configured: boolean; valid: boolean } };
  }).validation.external;

  assert.equal(external.configured, true);
  assert.equal(external.valid, true);
  assert.equal(external.command, "<data-root>/validator-link");
  assert.equal(external.resolvedCommand, await realpath("/bin/true"));
});

test("EPUB build redacts storage roots from external validator details", async () => {
  const storage = new NovelStorage(testRoot("novelist-epubcheck-redaction-test"));
  const pipeline = new NovelPipeline(storage, new StubNovelAgents(), {
    ...loadConfig({}),
    epubCheckCommand: "/usr/bin/printf",
    epubCheckArgs: ["%s", "{epub}"]
  });
  const data = await completeTinyVolume(pipeline);

  const epub = await pipeline.buildEpub(data);
  const epubData = epub.data as {
    path: string;
    validation: { external: { args?: string[]; stdout?: string } };
  };
  const externalText = JSON.stringify(epubData.validation.external);

  assert.equal(epubData.path.includes(storage.root), true);
  assert.equal(externalText.includes(storage.root), false);
  assert.match(externalText, /<data-root>/);
});

test("EPUB build cancellation after archive preparation does not write a candidate file", async () => {
  const storage = new NovelStorage(testRoot("novelist-epub-cancel-before-candidate-test"));
  const pipeline = new NovelPipeline(storage, new StubNovelAgents());
  const data = await completeTinyVolume(pipeline);
  let checks = 0;

  await assertRejects(
    pipeline.buildEpub(data, {
      isCancelled: () => {
        checks += 1;
        return checks >= 5;
      }
    }),
    /cancelled while writing epub candidate archive/
  );

  const volumeEntries = await readdir(storage.volumeDir(data.franchiseId, data.workId, data.volumeId));
  assert.deepEqual(volumeEntries.filter((entry) => entry.includes(".candidate-")), []);
  assert.deepEqual(volumeEntries.filter((entry) => entry.endsWith(".epub")), []);
});

