test("failed EPUB validation preserves the previous final EPUB", async () => {
  const storage = new NovelStorage(testRoot("novelist-epubcheck-preserve-test"));
  const successfulPipeline = new NovelPipeline(storage, new StubNovelAgents(), {
    ...loadConfig({}),
    epubCheckCommand: "/bin/true",
    epubCheckArgs: ["{epub}"]
  });
  const data = await completeTinyVolume(successfulPipeline);
  const built = await successfulPipeline.buildEpub(data);
  const finalPath = (built.data as { path: string }).path;
  const original = await readFile(finalPath);
  const failingPipeline = new NovelPipeline(storage, new StubNovelAgents(), {
    ...loadConfig({}),
    epubCheckCommand: "/bin/false",
    epubCheckArgs: ["{epub}"]
  });

  await assertRejects(failingPipeline.buildEpub(data), /External EPUB validation failed/);

  const afterFailure = await readFile(finalPath);
  const volumeEntries = await readdir(storage.volumeDir(data.franchiseId, data.workId, data.volumeId));
  assert.deepEqual(afterFailure, original);
  assert.deepEqual(volumeEntries.filter((entry) => entry.includes(".candidate-")), []);
});

