test("direct pipeline cleanup errors redact inline secrets", async () => {
  const storage = new SecretEpubCandidateCleanupStorage(testRoot("novelist-epubcheck-cleanup-secret-test"));
  const pipeline = new NovelPipeline(storage, new StubNovelAgents(), {
    ...loadConfig({}),
    epubCheckCommand: "/bin/false",
    epubCheckArgs: ["{epub}"]
  });
  const data = await completeTinyVolume(pipeline);

  try {
    await pipeline.buildEpub(data);
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    assert.match(message, /External EPUB validation failed/);
    assert.match(message, /Candidate cleanup failed/);
    assert.match(message, /Bearer \[Redacted\]/);
    assert.match(message, /sk-\[Redacted\]/);
    assert.equal(message.includes("pipeline-secret-token"), false);
    assert.equal(message.includes("sk-pipelinecleanup123"), false);
    return;
  }
  throw new Error("Expected buildEpub to reject.");
});

