test("EPUB candidate promotion rejects incomplete states and invalid archives", async () => {
  const storage = new NovelStorage(testRoot("novelist-epub-candidate-promote-validation-test"));
  const pipeline = new NovelPipeline(storage);
  const data = await completeTinyVolume(pipeline);
  const completeState = await storage.loadState(data.franchiseId, data.workId, data.volumeId);
  const incompleteState = {
    ...completeState,
    status: "drafting"
  } as typeof completeState;
  const volumeDir = storage.volumeDir(completeState.franchiseId, completeState.workId, completeState.volumeId);
  const validCandidate = join(volumeDir, `${completeState.volumeId}.candidate-${randomUUID()}.epub`);
  const invalidCandidate = join(volumeDir, `${completeState.volumeId}.candidate-${randomUUID()}.epub`);

  await writeFile(validCandidate, buildEpubArchive(completeState, "본문"));
  await assertRejects(storage.promoteEpubCandidate(incompleteState, validCandidate), /EPUB candidate can only be promoted for a complete volume/);
  assert.equal(validateEpubArchive(await readFile(validCandidate)).valid, true);

  await writeFile(invalidCandidate, new Uint8Array([9, 8, 7]));
  await assertRejects(storage.promoteEpubCandidate(completeState, invalidCandidate), /EPUB candidate archive validation failed/);
  assert.equal(await readFile(invalidCandidate).then((bytes) => bytes.length), 3);
  assert.equal(await storageExists(storage.epubPath(completeState)), false);
});

