test("EPUB candidate promotion rejects non-regular candidate paths", async () => {
  const root = testRoot("novelist-epub-candidate-regular-file-test");
  const outside = testRoot("novelist-epub-candidate-regular-file-outside");
  const storage = new NovelStorage(root);
  const pipeline = new NovelPipeline(storage);
  const data = await completeTinyVolume(pipeline);
  const state = await storage.loadState(data.franchiseId, data.workId, data.volumeId);
  const volumeDir = storage.volumeDir(state.franchiseId, state.workId, state.volumeId);
  const directoryCandidate = join(volumeDir, `${state.volumeId}.candidate-${randomUUID()}.epub`);
  await mkdir(directoryCandidate, { recursive: true });

  await assertRejects(storage.promoteEpubCandidate(state, directoryCandidate), /must be a regular file/);
  assert.equal(await storageExists(storage.epubPath(state)), false);

  await mkdir(outside, { recursive: true });
  const outsideTarget = join(outside, "outside.epub");
  await writeFile(outsideTarget, "outside target", "utf8");
  const symlinkCandidate = join(volumeDir, `${state.volumeId}.candidate-${randomUUID()}.epub`);
  await symlink(outsideTarget, symlinkCandidate);

  await assertRejects(storage.promoteEpubCandidate(state, symlinkCandidate), /resolves outside storage root|must be a regular file/);
  assert.equal(await readFile(outsideTarget, "utf8"), "outside target");
  assert.equal(await storageExists(storage.epubPath(state)), false);
});

