test("external EPUB validator result JSON ignores polluted toJSON prototypes", async () => {
  const epubPath = await writeExternalValidatorFixture("novelist-external-validator-json");
  const resolvedPrintf = await realpath("/usr/bin/printf");
  const result = await runExternalEpubCheck(epubPath, {
    ...loadConfig({}),
    operationTimeoutMs: 30_000,
    epubCheckCommand: "/usr/bin/printf",
    epubCheckArgs: ["%s", "{epub}"]
  });
  const expectedArgsJson = JSON.stringify(["%s", epubPath]);
  const objectToJson = Object.getOwnPropertyDescriptor(Object.prototype, "toJSON");
  const arrayToJson = Object.getOwnPropertyDescriptor(Array.prototype, "toJSON");
  try {
    Object.defineProperty(Object.prototype, "toJSON", {
      configurable: true,
      value: () => ({ polluted: true, secret: "sk-external-result-secret" })
    });
    Object.defineProperty(Array.prototype, "toJSON", {
      configurable: true,
      value: () => ["polluted", "sk-external-arg-secret"]
    });

    assert.deepEqual(JSON.parse(JSON.stringify(result)), {
      configured: true,
      valid: true,
      command: "/usr/bin/printf",
      ...(resolvedPrintf === "/usr/bin/printf" ? {} : { resolvedCommand: resolvedPrintf }),
      args: ["%s", epubPath],
      stdout: epubPath,
      stderr: ""
    });
    assert.equal(JSON.stringify(result.args), expectedArgsJson);
  } finally {
    if (objectToJson) {
      Object.defineProperty(Object.prototype, "toJSON", objectToJson);
    } else {
      delete (Object.prototype as { toJSON?: unknown }).toJSON;
    }
    if (arrayToJson) {
      Object.defineProperty(Array.prototype, "toJSON", arrayToJson);
    } else {
      delete (Array.prototype as { toJSON?: unknown }).toJSON;
    }
  }
});

