test("external EPUB validator timeout can be capped by remaining operation time", async () => {
  const startedAt = Date.now();
  const epubPath = await writeExternalValidatorFixture("novelist-external-validator-timeout");
  const result = await runExternalEpubCheck(epubPath, {
    ...loadConfig({}),
    operationTimeoutMs: 5000,
    epubCheckCommand: process.execPath,
    epubCheckArgs: ["-e", "setTimeout(() => undefined, 1000);", "{epub}"]
  }, 25);
  const elapsed = Date.now() - startedAt;

  assert.equal(result.configured, true);
  assert.equal(result.valid, false);
  assert.ok(elapsed < 1000, `validator did not use the remaining timeout cap: ${elapsed}ms`);
  assert.match(result.error ?? "", /Command failed|timed out|SIGTERM|node/);
});

