test("pipeline rejects invalid direct constructor dependencies without invoking getters", () => {
  const storage = new NovelStorage(testRoot("novelist-pipeline-constructor-validation-test"));
  const agents = new StubNovelAgents();
  let storageGetterRan = false;
  const accessorStorage = Object.create(storage) as NovelStorage;
  Object.defineProperty(accessorStorage, "loadState", {
    enumerable: true,
    get() {
      storageGetterRan = true;
      throw new Error("pipeline storage getter must not run");
    }
  });
  let rootGetterRan = false;
  const accessorRootStorage = Object.create(storage) as NovelStorage;
  Object.defineProperty(accessorRootStorage, "root", {
    enumerable: true,
    get() {
      rootGetterRan = true;
      throw new Error("pipeline storage root getter must not run");
    }
  });
  let agentGetterRan = false;
  const accessorAgents = Object.create(agents) as StubNovelAgents;
  Object.defineProperty(accessorAgents, "planInitial", {
    enumerable: true,
    get() {
      agentGetterRan = true;
      throw new Error("pipeline agent getter must not run");
    }
  });

  assert.throws(
    () => new NovelPipeline(null as unknown as ConstructorParameters<typeof NovelPipeline>[0], agents),
    /NovelPipeline\.storage must be an object/
  );
  const constructorSecret = "Authorization: Bearer pipeline-constructor-secret";
  const assertWrappedConstructorError = (operation: () => unknown, expected: RegExp): void => {
    assert.throws(operation, expected);
    try {
      operation();
    } catch (error) {
      assert.doesNotMatch(String(error), new RegExp(constructorSecret));
      return;
    }
    throw new Error("expected NovelPipeline constructor validation failure");
  };
  assertWrappedConstructorError(
    () => new NovelPipeline(new Proxy(storage, {
      ownKeys() {
        throw new Error(`leaked pipeline storage keys trap ${constructorSecret}`);
      }
    }), agents),
    /NovelPipeline\.storage keys must be readable/
  );
  assertWrappedConstructorError(
    () => new NovelPipeline(new Proxy(storage, {
      getOwnPropertyDescriptor() {
        throw new Error(`leaked pipeline storage descriptor trap ${constructorSecret}`);
      }
    }), agents),
    /NovelPipeline\.storage property descriptors must be readable/
  );
  assertWrappedConstructorError(
    () => new NovelPipeline(new Proxy(storage, {
      getPrototypeOf() {
        throw new Error(`leaked pipeline storage prototype trap ${constructorSecret}`);
      }
    }), agents),
    /NovelPipeline\.storage prototype must be readable/
  );
  assertWrappedConstructorError(
    () => new NovelPipeline(storage, new Proxy(agents, {
      ownKeys() {
        throw new Error(`leaked pipeline agents keys trap ${constructorSecret}`);
      }
    })),
    /NovelPipeline\.agents keys must be readable/
  );
  assertWrappedConstructorError(
    () => new NovelPipeline(storage, new Proxy(agents, {
      getOwnPropertyDescriptor() {
        throw new Error(`leaked pipeline agents descriptor trap ${constructorSecret}`);
      }
    })),
    /NovelPipeline\.agents property descriptors must be readable/
  );
  assert.throws(
    () => new NovelPipeline(accessorStorage, agents),
    /NovelPipeline\.storage\.loadState must be a data function/
  );
  assert.equal(storageGetterRan, false);
  const missingRecoveryStorage = Object.create(storage) as NovelStorage;
  Object.defineProperty(missingRecoveryStorage, "writeWorldFile", {
    enumerable: true,
    value: undefined
  });
  assert.throws(
    () => new NovelPipeline(missingRecoveryStorage, agents),
    /NovelPipeline\.storage\.writeWorldFile must be a data function/
  );
  assert.throws(
    () => new NovelPipeline(accessorRootStorage, agents),
    /NovelPipeline\.storage\.root must be an enumerable data string/
  );
  assert.equal(rootGetterRan, false);
  const symbolStorage = Object.create(storage) as NovelStorage & Record<symbol, unknown>;
  symbolStorage[Symbol("pipeline-storage")] = true;
  assert.throws(
    () => new NovelPipeline(symbolStorage, agents),
    /NovelPipeline\.storage must not contain symbol properties/
  );
  const multibyteLongRootStorage = Object.create(storage) as NovelStorage;
  Object.defineProperty(multibyteLongRootStorage, "root", {
    enumerable: true,
    value: `/tmp/${"가".repeat(1365)}`
  });
  assert.throws(
    () => new NovelPipeline(multibyteLongRootStorage, agents),
    /NovelPipeline\.storage\.root must be at most 4096 UTF-8 bytes/
  );
  const rootStorage = Object.create(storage) as NovelStorage;
  Object.defineProperty(rootStorage, "root", {
    enumerable: true,
    value: "/tmp/.."
  });
  assert.throws(
    () => new NovelPipeline(rootStorage, agents),
    /NovelPipeline\.storage\.root must not be the filesystem root/
  );
  assert.throws(
    () => new NovelPipeline(storage, accessorAgents),
    /NovelPipeline\.agents\.planInitial must be a data function/
  );
  assert.equal(agentGetterRan, false);
  const symbolAgents = Object.create(agents) as StubNovelAgents & Record<symbol, unknown>;
  symbolAgents[Symbol("pipeline-agents")] = true;
  assert.throws(
    () => new NovelPipeline(storage, symbolAgents),
    /NovelPipeline\.agents must not contain symbol properties/
  );
});

