test("volume lock retry timers are capped to the Node setTimeout limit", async () => {
  const root = testRoot("novelist-lock-long-retry-timer-test");
  const storage = new NovelStorage({
    ...loadConfig({}),
    dataDir: root,
    lockTimeoutMs: 35,
    lockRetryMs: 30 * 24 * 60 * 60 * 1000,
    lockStaleMs: 30 * 24 * 60 * 60 * 1000,
    logLevel: "silent"
  });
  const lockPath = volumeLockPath(root, "timer-world", "timer-work", "timer-volume");
  const recordedTimeouts: number[] = [];
  const originalSetTimeout = globalThis.setTimeout;

  await mkdir(lockPath, { recursive: true });
  (globalThis as unknown as { setTimeout: typeof setTimeout }).setTimeout = ((callback: () => void, ms: number): unknown => {
    recordedTimeouts.push(ms);
    return originalSetTimeout(callback, 0);
  }) as typeof setTimeout;
  try {
    await assertRejects(
      storage.withVolumeLock("timer-world", "timer-work", "timer-volume", async () => undefined),
      /Timed out acquiring lock/
    );
  } finally {
    (globalThis as unknown as { setTimeout: typeof setTimeout }).setTimeout = originalSetTimeout;
  }

  assert.equal(recordedTimeouts.length > 0, true);
  assert.equal(recordedTimeouts.every((ms) => ms <= 2_147_483_647), true);
  assert.equal(recordedTimeouts.some((ms) => ms === 2_147_483_647), true);
});

