test("volume lock owner writes ignore polluted toJSON prototypes", async () => {
  const root = testRoot("novelist-lock-owner-tojson-test");
  const storage = new NovelStorage({
    ...loadConfig({}),
    dataDir: root,
    lockTimeoutMs: 80,
    lockRetryMs: 5,
    lockStaleMs: 20,
    logLevel: "silent"
  });
  const lockPath = volumeLockPath(root, "tojson-world", "tojson-work", "tojson-volume");
  const objectToJson = Object.getOwnPropertyDescriptor(Object.prototype, "toJSON");
  try {
    Object.defineProperty(Object.prototype, "toJSON", {
      configurable: true,
      value: () => ({ franchiseId: "polluted", token: "polluted-token" })
    });
    await storage.withVolumeLock("tojson-world", "tojson-work", "tojson-volume", async () => {
      const owner = JSON.parse(await readFile(join(lockPath, "owner.json"), "utf8")) as Record<string, unknown>;
      assert.equal(typeof owner.token, "string");
      assert.ok(owner.token !== "polluted-token");
      assert.equal(typeof owner.updatedAt, "string");
      assert.equal(Object.prototype.hasOwnProperty.call(owner, "franchiseId"), false);
    });
  } finally {
    if (objectToJson) {
      Object.defineProperty(Object.prototype, "toJSON", objectToJson);
    } else {
      delete (Object.prototype as { toJSON?: unknown }).toJSON;
    }
  }
});

