test("atomic binary writes wrap unreadable Uint8Array-like reflection before writing", async () => {
  const root = testRoot("novelist-atomic-binary-reflection-test");
  const storage = new NovelStorage(root);
  const target = join(root, "binary.dat");
  const secret = "Authorization: Bearer atomic-binary-reflection-secret";

  const assertBoundedAtomicBinaryError = async (content: unknown, expected: RegExp): Promise<void> => {
    let caught: unknown;
    try {
      await storage.writeFileAtomic(target, content as Uint8Array);
    } catch (error) {
      caught = error;
    }
    if (!(caught instanceof Error)) {
      throw caught ?? new Error("Expected atomic binary content validation to fail.");
    }
    assert.match(caught.message, expected);
    assert.doesNotMatch(caught.message, /atomic-binary-reflection-secret/);
    await assertRejects(readFile(target), /ENOENT/);
  };

  await assertBoundedAtomicBinaryError(
    new Proxy(new Uint8Array([1, 2, 3]), {
      getPrototypeOf() {
        throw new Error(`raw binary prototype trap leaked ${secret}`);
      }
    }),
    /Atomic write content .* Uint8Array prototype must be readable/
  );

  await assertBoundedAtomicBinaryError(
    new Proxy(new Uint8Array([1, 2, 3]), {
      get(target, key, receiver) {
        if (key === "byteLength") {
          throw new Error(`raw binary byteLength trap leaked ${secret}`);
        }
        return Reflect.get(target, key, receiver);
      }
    }),
    /Atomic write content .* Uint8Array byteLength must be readable/
  );

  await assertBoundedAtomicBinaryError(
    new Proxy(new Uint8Array([1, 2, 3]), {
      get(target, key, receiver) {
        if (key === "byteLength") {
          return target.byteLength;
        }
        if (key === Symbol.iterator) {
          throw new Error(`raw binary snapshot trap leaked ${secret}`);
        }
        return Reflect.get(target, key, receiver);
      }
    }),
    /Atomic write content .* must be snapshot-readable/
  );
});

