test("JSON metadata writes reject lossy non-JSON-compatible values before writing", async () => {
  const root = testRoot("novelist-json-compatible-test");
  const storage = new NovelStorage(root);
  const target = join(root, "invalid.json");
  const circular: Record<string, unknown> = {};
  circular.self = circular;
  const shared = { value: "shared" };
  const sparse: unknown[] = [];
  sparse[1] = "present";
  const nonStandardArray = ["safe"];
  Object.setPrototypeOf(nonStandardArray, { inherited: "bad" });
  let objectGetterRan = false;
  const accessorObject = Object.defineProperty({ ok: true }, "danger", {
    enumerable: true,
    get() {
      objectGetterRan = true;
      throw new Error("json metadata object getter must not run");
    }
  });
  let arrayGetterRan = false;
  const accessorArray = ["safe"];
  Object.defineProperty(accessorArray, "0", {
    enumerable: true,
    get() {
      arrayGetterRan = true;
      throw new Error("json metadata array getter must not run");
    }
  });

  await assertRejects(storage.writeJson(target, { omitted: undefined }), /JSON metadata file\.omitted must not be undefined/);
  await assertRejects(storage.writeJson(target, { nonFinite: Number.NaN }), /JSON metadata file\.nonFinite must be a finite number/);
  await assertRejects(storage.writeJson(target, { unsafeInteger: Number.MAX_SAFE_INTEGER + 1 }), /JSON metadata file\.unsafeInteger must be a safe integer/);
  await assertRejects(storage.writeJson(target, { control: "bad\u0001value" }), /JSON metadata file\.control must not contain control characters/);
  await assertRejects(storage.writeJson(target, { oversized: "x".repeat(1024 * 1024 + 1) }), /JSON metadata file\.oversized must be at most/);
  await assertRejects(storage.writeJson(target, { oversizedBytes: "가".repeat(400000) }), /JSON metadata file\.oversizedBytes must be at most 1048576 UTF-8 bytes/);
  await assertRejects(storage.writeJson(target, { callback: () => undefined }), /JSON metadata file\.callback must contain only JSON-compatible values/);
  await assertRejects(storage.writeJson(target, { createdAt: new Date() }), /JSON metadata file\.createdAt must be a plain JSON object/);
  await assertRejects(storage.writeJson(target, { sparse }), /JSON metadata file\.sparse\[0\] must not be a sparse array hole/);
  await assertRejects(storage.writeJson(target, { nonStandardArray }), /JSON metadata file\.nonStandardArray must be a standard array/);
  await assertRejects(storage.writeJson(target, { accessorObject }), /JSON metadata file\.accessorObject must not contain non-enumerable or accessor properties/);
  await assertRejects(storage.writeJson(target, { accessorArray }), /JSON metadata file\.accessorArray\[0\] must not be a non-enumerable or accessor array item/);
  await assertRejects(storage.writeJson(target, circular), /JSON metadata file\.self must not contain circular references/);
  assert.equal(objectGetterRan, false);
  assert.equal(arrayGetterRan, false);
  await assertRejects(readFile(target, "utf8"), /ENOENT/);

  await storage.writeJson(target, { first: shared, second: shared });
  assert.deepEqual(await storage.readJson(target), { first: { value: "shared" }, second: { value: "shared" } });
});

test("JSON metadata writes wrap unreadable reflection metadata before writing", async () => {
  const root = testRoot("novelist-json-reflection-trap-test");
  const storage = new NovelStorage(root);
  const target = join(root, "reflection.json");
  const secret = "Authorization: Bearer json-metadata-reflection-secret";
  const secretPattern = /Authorization: Bearer json-metadata-reflection-secret/;

  const assertBoundedReflectionError = async (value: unknown, expected: RegExp) => {
    let caught: unknown;
    try {
      await storage.writeJson(target, value);
    } catch (error) {
      caught = error;
    }
    assert.ok(caught instanceof Error);
    assert.match(String(caught), expected);
    assert.doesNotMatch(String(caught), secretPattern);
    await assertRejects(readFile(target, "utf8"), /ENOENT/);
  };

  await assertBoundedReflectionError(
    new Proxy(
      { safe: true },
      {
        getPrototypeOf() {
          throw new Error(`raw object prototype trap leaked ${secret}`);
        }
      }
    ),
    /JSON metadata file prototype must be readable/
  );

  await assertBoundedReflectionError(
    new Proxy(
      { safe: true },
      {
        ownKeys() {
          throw new Error(`raw object keys trap leaked ${secret}`);
        }
      }
    ),
    /JSON metadata file keys must be readable/
  );

  await assertBoundedReflectionError(
    new Proxy(
      { safe: true },
      {
        getOwnPropertyDescriptor() {
          throw new Error(`raw object descriptor trap leaked ${secret}`);
        }
      }
    ),
    /JSON metadata file property descriptors must be readable/
  );

  await assertBoundedReflectionError(
    {
      items: new Proxy(["safe"], {
        getPrototypeOf() {
          throw new Error(`raw array prototype trap leaked ${secret}`);
        }
      })
    },
    /JSON metadata file\.items prototype must be readable/
  );

  await assertBoundedReflectionError(
    {
      items: new Proxy(["safe"], {
        ownKeys() {
          throw new Error(`raw array keys trap leaked ${secret}`);
        }
      })
    },
    /JSON metadata file\.items keys must be readable/
  );

  await assertBoundedReflectionError(
    {
      items: new Proxy(["safe"], {
        getOwnPropertyDescriptor() {
          throw new Error(`raw array descriptor trap leaked ${secret}`);
        }
      })
    },
    /JSON metadata file\.items property descriptors must be readable/
  );
});

test("JSON metadata writes serialize validated snapshots instead of polluted prototypes", async () => {
  const root = testRoot("novelist-json-snapshot-prototype-pollution-test");
  const storage = new NovelStorage(root);
  const target = join(root, "snapshot.json");
  const objectHadToJson = Object.prototype.hasOwnProperty.call(Object.prototype, "toJSON");
  const arrayHadToJson = Object.prototype.hasOwnProperty.call(Array.prototype, "toJSON");
  const originalObjectToJson = (Object.prototype as { toJSON?: unknown }).toJSON;
  const originalArrayToJson = (Array.prototype as { toJSON?: unknown }).toJSON;
  let objectToJsonRan = false;
  let arrayToJsonRan = false;

  try {
    Object.defineProperty(Object.prototype, "toJSON", {
      value() {
        objectToJsonRan = true;
        return { polluted: true };
      },
      configurable: true
    });
    Object.defineProperty(Array.prototype, "toJSON", {
      value() {
        arrayToJsonRan = true;
        return ["polluted"];
      },
      configurable: true
    });

    await storage.writeJson(target, { nested: { value: "safe" }, items: ["safe"] });
  } finally {
    if (objectHadToJson) {
      Object.defineProperty(Object.prototype, "toJSON", {
        value: originalObjectToJson,
        configurable: true,
        writable: true
      });
    } else {
      delete (Object.prototype as { toJSON?: unknown }).toJSON;
    }
    if (arrayHadToJson) {
      Object.defineProperty(Array.prototype, "toJSON", {
        value: originalArrayToJson,
        configurable: true,
        writable: true
      });
    } else {
      delete (Array.prototype as { toJSON?: unknown }).toJSON;
    }
  }

  assert.equal(objectToJsonRan, false);
  assert.equal(arrayToJsonRan, false);
  assert.deepEqual(await storage.readJson(target), { nested: { value: "safe" }, items: ["safe"] });
});

