test("OpenAI adapter rejects overridden native Response surfaces without invoking accessors", async () => {
  const config = loadConfig({
    NOVELIST_AGENT_PROVIDER: "openai",
    NOVELIST_OPENAI_API_KEY: "test-key",
    NOVELIST_OPENAI_BASE_URL: "https://model.test/v1",
    NOVELIST_OPENAI_MODEL: "story-model",
    NOVELIST_OPENAI_MAX_RETRIES: "0"
  });
  const request = {
    franchiseName: "네이티브 표면 세계",
    workRequest: "네이티브 표면 작품"
  };
  let subclassStatusGetterRan = false;
  class OverriddenResponse extends Response {}
  const subclassResponse = new OverriddenResponse("{}", { status: 200 });
  Object.defineProperty(subclassResponse, "status", {
    enumerable: true,
    get() {
      subclassStatusGetterRan = true;
      throw new Error("native subclass status getter must not run");
    }
  });

  await assertRejects(
    new OpenAiNovelAgents(
      config,
      async () => subclassResponse as unknown as Awaited<ReturnType<NonNullable<ConstructorParameters<typeof OpenAiNovelAgents>[1]>>>,
      async () => undefined
    ).planInitial(request),
    /must be an exact native Response or plain response object/
  );
  assert.equal(subclassStatusGetterRan, false);

  const response = new Response(JSON.stringify({ choices: [{ message: { content: "본문" } }] }), {
    status: 200,
    headers: { "content-type": "application/json" }
  });
  let ownStatusGetterRan = false;
  Object.defineProperty(response, "status", {
    enumerable: true,
    get() {
      ownStatusGetterRan = true;
      throw new Error("native own status getter must not run");
    }
  });
  await assertRejects(
    new OpenAiNovelAgents(
      config,
      async () => response as unknown as Awaited<ReturnType<NonNullable<ConstructorParameters<typeof OpenAiNovelAgents>[1]>>>,
      async () => undefined
    ).planInitial(request),
    /status must not be overridden on a native Response instance/
  );
  assert.equal(ownStatusGetterRan, false);

  const secret = "Authorization: Bearer native-response-reflection-secret sk-native-response-secret";
  const reflectionResponse = new Proxy(
    new Response(JSON.stringify({ choices: [{ message: { content: "본문" } }] }), {
      status: 200,
      headers: { "content-type": "application/json" }
    }),
    {
      getOwnPropertyDescriptor() {
        throw new Error(`raw native response descriptor trap leaked ${secret}`);
      }
    }
  );
  let caught: unknown;
  try {
    await new OpenAiNovelAgents(
      config,
      async () => reflectionResponse as unknown as Awaited<ReturnType<NonNullable<ConstructorParameters<typeof OpenAiNovelAgents>[1]>>>,
      async () => undefined
    ).planInitial(request);
  } catch (error) {
    caught = error;
  }
  if (!(caught instanceof Error)) {
    throw caught ?? new Error("Expected native response reflection validation to fail.");
  }
  assert.match(caught.message, /OpenAI-compatible response for planner property descriptors must be readable/);
  assert.doesNotMatch(caught.message, /native-response-reflection-secret|sk-native-response-secret/);
});

test("OpenAI adapter rejects non-JSON successful response content types", async () => {
  const config = loadConfig({
    NOVELIST_AGENT_PROVIDER: "openai",
    NOVELIST_OPENAI_API_KEY: "test-key",
    NOVELIST_OPENAI_BASE_URL: "https://model.test/v1",
    NOVELIST_OPENAI_MODEL: "story-model",
    NOVELIST_OPENAI_MAX_RETRIES: "0"
  });
  const nativeAgent = new OpenAiNovelAgents(
    config,
    async () => new Response(JSON.stringify({ choices: [{ message: { content: "본문" } }] }), {
      status: 200,
      headers: { "content-type": "text/html; charset=utf-8" }
    }) as unknown as Awaited<ReturnType<NonNullable<ConstructorParameters<typeof OpenAiNovelAgents>[1]>>>,
    async () => undefined
  );
  await assertRejects(
    nativeAgent.planInitial({
      franchiseName: "비JSON 응답 세계",
      workRequest: "비JSON 응답 작품"
    }),
    /headers\.content-type must be application\/json or a \+json media type/
  );

  const customAgent = new OpenAiNovelAgents(
    config,
    async () => ({
      ok: true,
      status: 200,
      headers: { "content-type": "application/problem+json" },
      async text() {
        return JSON.stringify({ choices: [{ message: { content: "커스텀 JSON 응답" } }] });
      }
    }),
    async () => undefined
  );
  const result = await customAgent.planInitial({
    franchiseName: "커스텀 JSON 세계",
    workRequest: "커스텀 JSON 작품"
  });
  assert.equal(result.text, "커스텀 JSON 응답");

  const secret = "Authorization: Bearer native-headers-secret sk-native-headers-secret";
  const headers = new Proxy(new Headers({ "content-type": "application/json" }), {
    get(target, key, receiver) {
      if (key === "get") {
        return () => {
          throw new Error(`raw native headers getter leaked ${secret}`);
        };
      }
      return Reflect.get(target, key, receiver);
    }
  });
  let caught: unknown;
  try {
    await new OpenAiNovelAgents(
      config,
      async () => ({
        ok: true,
        status: 200,
        headers,
        async text() {
          return JSON.stringify({ choices: [{ message: { content: "네이티브 헤더" } }] });
        }
      }),
      async () => undefined
    ).planInitial({
      franchiseName: "네이티브 헤더 세계",
      workRequest: "네이티브 헤더 작품"
    });
  } catch (error) {
    caught = error;
  }
  if (!(caught instanceof Error)) {
    throw caught ?? new Error("Expected native header read validation to fail.");
  }
  assert.match(caught.message, /headers\.content-type must be readable/);
  assert.doesNotMatch(caught.message, /native-headers-secret|sk-native-headers-secret/);
});

