test("OpenAI adapter sends chat completion requests and retries transient failures", async () => {
  const calls: Array<{ url: string; body: string }> = [];
  let attempt = 0;
  const agent = new OpenAiNovelAgents(
    {
      ...loadConfig({
        NOVELIST_AGENT_PROVIDER: "openai",
        NOVELIST_OPENAI_API_KEY: "test-key",
        NOVELIST_OPENAI_BASE_URL: "https://model.test/v1",
        NOVELIST_OPENAI_MODEL: "story-model",
        NOVELIST_OPENAI_MAX_RETRIES: "2",
        NOVELIST_OPENAI_RETRY_BASE_MS: "1"
      })
    },
    async (url, init) => {
      calls.push({ url, body: init?.body ?? "" });
      attempt += 1;
      if (attempt === 1) {
        return fakeResponse(false, 429, { error: "rate limited" });
      }
      return fakeResponse(true, 200, {
        choices: [{ message: { content: "# 전개안\n\n성공" } }]
      });
    },
    async () => undefined
  );

  const result = await agent.planInitial({
    franchiseName: "모델 세계",
    workRequest: "모델 작품"
  });

  assert.equal(attempt, 2);
  assert.match(result.text, /성공/);
  assert.equal(calls[0]?.url, "https://model.test/v1/chat/completions");
  assert.match(calls[0]?.body ?? "", /story-model/);
});

