test("OpenAI adapter redacts and normalizes retry sleep failures", async () => {
  const apiKey = "sleep-secret-key";
  const baseUrl = "https://sleep-openai.test/v1";
  const agent = new OpenAiNovelAgents(
    loadConfig({
      NOVELIST_AGENT_PROVIDER: "openai",
      NOVELIST_OPENAI_API_KEY: apiKey,
      NOVELIST_OPENAI_BASE_URL: baseUrl,
      NOVELIST_OPENAI_MAX_RETRIES: "1",
      NOVELIST_OPENAI_RETRY_BASE_MS: "1"
    }),
    async () => fakeResponse(false, 429, { error: "rate limited" }),
    async () => {
      throw new Error(`sleep\u0001failed\nfor ${baseUrl}/chat/completions with Authorization: Bearer ${apiKey} and sk-sleepsecret123`);
    }
  );

  try {
    await agent.planInitial({
      franchiseName: "슬립 오류 세계",
      workRequest: "슬립 오류 작품"
    });
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    assert.match(message, /retry sleep failed/);
    assert.match(message, /sleep failed for/);
    assert.match(message, /<openai-base-url>/);
    assert.match(message, /Bearer \[Redacted\]/);
    assert.match(message, /sk-\[Redacted\]/);
    assert.equal(message.includes(apiKey), false);
    assert.equal(message.includes(baseUrl), false);
    assert.equal(/[\u0000-\u001f\u007f]/u.test(message), false);
    return;
  }
  throw new Error("Expected OpenAI adapter to reject retry sleep failures.");
});

