test("OpenAI adapter normalizes unreadable network error name metadata", async () => {
  const secret = "Authorization: Bearer openai-error-name-reflection-secret sk-error-name-secret";
  const traps = ["descriptor", "prototype"] as const;

  for (const trap of traps) {
    const networkError = new Proxy(new Error("bounded network failure"), {
      getOwnPropertyDescriptor(target, key) {
        if (trap === "descriptor" && key === "name") {
          throw new Error(`raw error name descriptor trap leaked ${secret}`);
        }
        return Reflect.getOwnPropertyDescriptor(target, key);
      },
      getPrototypeOf(target) {
        if (trap === "prototype") {
          throw new Error(`raw error name prototype trap leaked ${secret}`);
        }
        return Reflect.getPrototypeOf(target);
      }
    });
    const agent = new OpenAiNovelAgents(
      loadConfig({
        NOVELIST_AGENT_PROVIDER: "openai",
        NOVELIST_OPENAI_API_KEY: "test-key",
        NOVELIST_OPENAI_MAX_RETRIES: "0"
      }),
      async () => {
        throw networkError;
      },
      async () => undefined
    );

    try {
      await agent.planInitial({
        franchiseName: `오류 이름 리플렉션 ${trap} 세계`,
        workRequest: `오류 이름 리플렉션 ${trap} 작품`
      });
    } catch (error) {
      const output = `${error instanceof Error ? error.name : ""}\n${error instanceof Error ? error.message : String(error)}`;
      assert.match(output, /bounded network failure/);
      assert.doesNotMatch(output, /openai-error-name-reflection-secret|sk-error-name-secret/);
      assert.equal(error instanceof Error ? error.name : "", "Error");
      continue;
    }
    throw new Error("Expected OpenAI adapter to reject unreadable network error name metadata.");
  }
});

