test("OpenAI adapter request timeout is capped by operation timeout", async () => {
  const agent = new OpenAiNovelAgents(
    loadConfig({
      NOVELIST_AGENT_PROVIDER: "openai",
      NOVELIST_OPENAI_API_KEY: "test-key",
      NOVELIST_OPENAI_TIMEOUT_MS: String(30 * 24 * 60 * 60 * 1000),
      NOVELIST_OPERATION_TIMEOUT_MS: "5",
      NOVELIST_OPENAI_MAX_RETRIES: "0"
    }),
    async (_url, init) =>
      new Promise((_, reject) => {
        const signal = init?.signal as { addEventListener?: (event: "abort", listener: () => void) => void };
        signal.addEventListener?.("abort", () => {
          const error = new Error("request aborted");
          error.name = "AbortError";
          reject(error);
        });
      }),
    async () => undefined
  );

  await assertRejects(
    agent.planInitial({
      franchiseName: "요청 타임아웃 세계",
      workRequest: "요청 타임아웃 작품"
    }),
    /request aborted/
  );
});

test("OpenAI adapter caps long provider timers to the Node setTimeout limit", async () => {
  const recordedTimeouts: number[] = [];
  const originalSetTimeout = globalThis.setTimeout;
  (globalThis as unknown as { setTimeout: typeof setTimeout }).setTimeout = ((callback: () => void, ms: number): unknown => {
    recordedTimeouts.push(ms);
    return originalSetTimeout(() => undefined, 0);
  }) as typeof setTimeout;
  try {
    const agent = new OpenAiNovelAgents(
      loadConfig({
        NOVELIST_AGENT_PROVIDER: "openai",
        NOVELIST_OPENAI_API_KEY: "test-key",
        NOVELIST_OPERATION_TIMEOUT_MS: String(30 * 24 * 60 * 60 * 1000),
        NOVELIST_OPENAI_TIMEOUT_MS: String(30 * 24 * 60 * 60 * 1000),
        NOVELIST_OPENAI_MAX_RETRIES: "0"
      }),
      async () => fakeResponse(true, 200, { choices: [{ message: { content: "본문" } }] }),
      async () => undefined
    );

    await agent.planInitial({
      franchiseName: "긴 타이머 세계",
      workRequest: "긴 타이머 작품"
    });
  } finally {
    (globalThis as unknown as { setTimeout: typeof setTimeout }).setTimeout = originalSetTimeout;
  }

  assert.equal(recordedTimeouts.length >= 2, true);
  assert.equal(recordedTimeouts.every((ms) => ms <= 2_147_483_647), true);
  assert.equal(recordedTimeouts.some((ms) => ms === 2_147_483_647), true);
});

test("OpenAI adapter redacts and normalizes response body read failures", async () => {
  const apiKey = "body-read-secret-key";
  const baseUrl = "https://body-read-openai.test/v1";
  const agent = new OpenAiNovelAgents(
    loadConfig({
      NOVELIST_AGENT_PROVIDER: "openai",
      NOVELIST_OPENAI_API_KEY: apiKey,
      NOVELIST_OPENAI_BASE_URL: baseUrl,
      NOVELIST_OPENAI_MAX_RETRIES: "0"
    }),
    async () => ({
      ok: true,
      status: 200,
      async text() {
        throw new Error(`body\u0001read\nfailed for ${baseUrl} with raw key ${apiKey}, Authorization: bearer ${apiKey}, and sk-bodyread123`);
      }
    }),
    async () => undefined
  );

  try {
    await agent.planInitial({
      franchiseName: "본문 읽기 오류 세계",
      workRequest: "본문 읽기 오류 작품"
    });
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    assert.equal(/[\u0000-\u001f\u007f]/u.test(message), false);
    assert.equal(message.includes(apiKey), false);
    assert.equal(message.includes(baseUrl), false);
    assert.equal(message.includes("sk-bodyread123"), false);
    assert.match(message, /response body read failed/);
    assert.match(message, /<openai-api-key>/);
    assert.match(message, /<openai-base-url>/);
    assert.match(message, /Bearer \[Redacted\]/);
    assert.match(message, /sk-\[Redacted\]/);
    return;
  }
  throw new Error("Expected OpenAI adapter to reject body read failures.");
});

