test("OpenAI adapter rejects non-serializable prompt context before fetch", async () => {
  let called = false;
  const agent = new OpenAiNovelAgents(
    loadConfig({
      NOVELIST_AGENT_PROVIDER: "openai",
      NOVELIST_OPENAI_API_KEY: "test-key",
      NOVELIST_OPENAI_MAX_RETRIES: "2",
      NOVELIST_OPENAI_RETRY_BASE_MS: "1"
    }),
    async () => {
      called = true;
      return fakeResponse(true, 200, { choices: [{ message: { content: "should not be called" } }] });
    },
    async () => undefined
  );

  assert.throws(
    () =>
      agent.writeBeat({
        state: { invalid: 10n },
        currentBeat: { chapterNo: 1, beatNo: 1, title: "비트", targetWords: 100, status: "pending", retryCount: 0 }
      } as unknown as AgentContext),
    /prompt context must be JSON serializable/
  );
  assert.throws(
    () =>
      agent.writeBeat({
        state: { createdAt: new Date() },
        currentBeat: { chapterNo: 1, beatNo: 1, title: "비트", targetWords: 100, status: "pending", retryCount: 0 }
      } as unknown as AgentContext),
    /plain JSON object/
  );
  assert.throws(
    () =>
      agent.writeBeat({
        state: { omitted: undefined },
        currentBeat: { chapterNo: 1, beatNo: 1, title: "비트", targetWords: 100, status: "pending", retryCount: 0 }
      } as unknown as AgentContext),
    /OpenAI-compatible prompt context\.state\.omitted must not be undefined/
  );
  assert.throws(
    () =>
      agent.writeBeat({
        state: { unsafeInteger: Number.MAX_SAFE_INTEGER + 1 },
        currentBeat: { chapterNo: 1, beatNo: 1, title: "비트", targetWords: 100, status: "pending", retryCount: 0 }
      } as unknown as AgentContext),
    /OpenAI-compatible prompt context\.state\.unsafeInteger must be a safe integer/
  );
  assert.throws(
    () =>
      agent.writeBeat({
        state: { control: "bad\u0001value" },
        currentBeat: { chapterNo: 1, beatNo: 1, title: "비트", targetWords: 100, status: "pending", retryCount: 0 }
      } as unknown as AgentContext),
    /OpenAI-compatible prompt context\.state\.control must not contain control characters/
  );
  assert.throws(
    () =>
      agent.writeBeat({
        state: { oversized: "x".repeat(1024 * 1024 + 1) },
        currentBeat: { chapterNo: 1, beatNo: 1, title: "비트", targetWords: 100, status: "pending", retryCount: 0 }
      } as unknown as AgentContext),
    /OpenAI-compatible prompt context\.state\.oversized must be at most/
  );
  assert.throws(
    () =>
      agent.writeBeat({
        state: { oversized: "가".repeat(700_000) },
        currentBeat: { chapterNo: 1, beatNo: 1, title: "비트", targetWords: 100, status: "pending", retryCount: 0 }
      } as unknown as AgentContext),
    /OpenAI-compatible prompt context\.state\.oversized must be at most 2097152 UTF-8 bytes/
  );
  const longMultibyteKeyState = Object.create(null) as Record<string, unknown>;
  Object.defineProperty(longMultibyteKeyState, "가".repeat(683), {
    enumerable: true,
    value: "value"
  });
  assert.throws(
    () =>
      agent.writeBeat({
        state: longMultibyteKeyState,
        currentBeat: { chapterNo: 1, beatNo: 1, title: "비트", targetWords: 100, status: "pending", retryCount: 0 }
      } as unknown as AgentContext),
    /OpenAI-compatible prompt context\.state object keys must be at most 2048 UTF-8 bytes/
  );
  const sparse: unknown[] = [];
  sparse[1] = "present";
  assert.throws(
    () =>
      agent.writeBeat({
        state: { sparse },
        currentBeat: { chapterNo: 1, beatNo: 1, title: "비트", targetWords: 100, status: "pending", retryCount: 0 }
      } as unknown as AgentContext),
    /sparse array hole/
  );
  const nonStandardArray = ["safe"];
  Object.setPrototypeOf(nonStandardArray, { inherited: "bad" });
  assert.throws(
    () =>
      agent.writeBeat({
        state: { nonStandardArray },
        currentBeat: { chapterNo: 1, beatNo: 1, title: "비트", targetWords: 100, status: "pending", retryCount: 0 }
      } as unknown as AgentContext),
    /OpenAI-compatible prompt context\.state\.nonStandardArray must be a standard array/
  );
  assert.throws(
    () =>
      agent.writeBeat({
        state: Object.defineProperty({}, "hidden", { value: "secret", enumerable: false }),
        currentBeat: { chapterNo: 1, beatNo: 1, title: "비트", targetWords: 100, status: "pending", retryCount: 0 }
      } as unknown as AgentContext),
    /non-enumerable or accessor properties/
  );
  let arrayGetterRan = false;
  const accessorArray = ["safe"];
  Object.defineProperty(accessorArray, "0", {
    enumerable: true,
    get() {
      arrayGetterRan = true;
      throw new Error("prompt array getter must not run");
    }
  });
  assert.throws(
    () =>
      agent.writeBeat({
        state: { accessorArray },
        currentBeat: { chapterNo: 1, beatNo: 1, title: "비트", targetWords: 100, status: "pending", retryCount: 0 }
      } as unknown as AgentContext),
    /must be an enumerable data item/
  );
  assert.equal(arrayGetterRan, false);
  assert.equal(called, false);
});

test("OpenAI adapter preserves prototype-like prompt context keys as JSON data", async () => {
  const calls: Array<{ body: string }> = [];
  const agent = new OpenAiNovelAgents(
    loadConfig({
      NOVELIST_AGENT_PROVIDER: "openai",
      NOVELIST_OPENAI_API_KEY: "test-key",
      NOVELIST_OPENAI_MAX_RETRIES: "0"
    }),
    async (_url, init) => {
      calls.push({ body: init?.body ?? "" });
      return fakeResponse(true, 200, { choices: [{ message: { content: "본문" } }] });
    },
    async () => undefined
  );
  const state = Object.create(null) as Record<string, unknown>;
  Object.defineProperty(state, "__proto__", {
    enumerable: true,
    value: { preserved: true }
  });

  await agent.writeBeat({
    state,
    currentBeat: { chapterNo: 1, beatNo: 1, title: "비트", targetWords: 100, status: "pending", retryCount: 0 }
  } as unknown as AgentContext);

  const request = JSON.parse(calls[0]?.body ?? "{}") as { messages?: Array<{ content?: string }> };
  const userPrompt = request.messages?.[1]?.content ?? "";
  assert.match(userPrompt, /"__proto__"/);
  assert.match(userPrompt, /"preserved": true/);
  assert.equal(({} as { preserved?: boolean }).preserved, undefined);
});

test("OpenAI adapter snapshots prompt context keys only once per object", async () => {
  const calls: Array<{ body: string }> = [];
  const agent = new OpenAiNovelAgents(
    loadConfig({
      NOVELIST_AGENT_PROVIDER: "openai",
      NOVELIST_OPENAI_API_KEY: "test-key",
      NOVELIST_OPENAI_MAX_RETRIES: "0"
    }),
    async (_url, init) => {
      calls.push({ body: init?.body ?? "" });
      return fakeResponse(true, 200, { choices: [{ message: { content: "본문" } }] });
    },
    async () => undefined
  );
  let stateOwnKeysCalls = 0;
  const state = new Proxy(
    { title: "프록시 상태" },
    {
      ownKeys(target) {
        stateOwnKeysCalls += 1;
        if (stateOwnKeysCalls > 1) {
          throw new Error("prompt context keys should not be read twice");
        }
        return Reflect.ownKeys(target);
      }
    }
  );

  await agent.writeBeat({
    state,
    currentBeat: { chapterNo: 1, beatNo: 1, title: "비트", targetWords: 100, status: "pending", retryCount: 0 }
  } as unknown as AgentContext);

  const request = JSON.parse(calls[0]?.body ?? "{}") as { messages?: Array<{ content?: string }> };
  assert.match(request.messages?.[1]?.content ?? "", /프록시 상태/);
  assert.equal(stateOwnKeysCalls, 1);
});

test("OpenAI adapter serializes request body snapshots instead of polluted prototypes", async () => {
  const calls: Array<{ body: string }> = [];
  const objectHadToJson = Object.prototype.hasOwnProperty.call(Object.prototype, "toJSON");
  const arrayHadToJson = Object.prototype.hasOwnProperty.call(Array.prototype, "toJSON");
  const originalObjectToJson = (Object.prototype as { toJSON?: unknown }).toJSON;
  const originalArrayToJson = (Array.prototype as { toJSON?: unknown }).toJSON;
  let objectToJsonRan = false;
  let arrayToJsonRan = false;
  const responseBody = JSON.stringify({ choices: [{ message: { content: "본문" } }] });
  const agent = new OpenAiNovelAgents(
    loadConfig({
      NOVELIST_AGENT_PROVIDER: "openai",
      NOVELIST_OPENAI_API_KEY: "test-key",
      NOVELIST_OPENAI_MAX_RETRIES: "0"
    }),
    async (_url, init) => {
      calls.push({ body: init?.body ?? "" });
      return fakeTextResponse(true, 200, responseBody);
    },
    async () => undefined
  );

  try {
    Object.defineProperty(Object.prototype, "toJSON", {
      value() {
        objectToJsonRan = true;
        return { polluted: true };
      },
      configurable: true
    });
    Object.defineProperty(Array.prototype, "toJSON", {
      value() {
        arrayToJsonRan = true;
        return ["polluted"];
      },
      configurable: true
    });

    await agent.writeBeat({
      state: {
        franchiseId: "safe-franchise",
        chapters: [{ chapterNo: 1, beats: [{ beatNo: 1, title: "비트" }] }]
      },
      currentBeat: { chapterNo: 1, beatNo: 1, title: "비트", targetWords: 100, status: "pending", retryCount: 0 }
    } as unknown as AgentContext);
  } finally {
    if (objectHadToJson) {
      Object.defineProperty(Object.prototype, "toJSON", {
        value: originalObjectToJson,
        configurable: true,
        writable: true
      });
    } else {
      delete (Object.prototype as { toJSON?: unknown }).toJSON;
    }
    if (arrayHadToJson) {
      Object.defineProperty(Array.prototype, "toJSON", {
        value: originalArrayToJson,
        configurable: true,
        writable: true
      });
    } else {
      delete (Array.prototype as { toJSON?: unknown }).toJSON;
    }
  }

  const request = JSON.parse(calls[0]?.body ?? "{}") as { model?: string; messages?: Array<{ content?: string }> };
  const userPrompt = request.messages?.[1]?.content ?? "";

  assert.equal(objectToJsonRan, false);
  assert.equal(arrayToJsonRan, false);
  assert.equal(request.model, "gpt-4.1-mini");
  assert.match(userPrompt, /safe-franchise/);
  assert.match(userPrompt, /"chapters"/);
});

test("OpenAI adapter wraps unreadable prompt context reflection before requests", async () => {
  let called = false;
  const agent = new OpenAiNovelAgents(
    loadConfig({
      NOVELIST_AGENT_PROVIDER: "openai",
      NOVELIST_OPENAI_API_KEY: "test-key"
    }),
    async () => {
      called = true;
      return fakeResponse(true, 200, { choices: [{ message: { content: "should not be called" } }] });
    },
    async () => undefined
  );
  const secret = "Authorization: Bearer openai-prompt-reflection-secret sk-openai-promptsecret123";
  const secretPattern = /openai-prompt-reflection-secret|sk-openai-promptsecret123/;
  const currentBeat = { chapterNo: 1, beatNo: 1, title: "비트", targetWords: 100, status: "pending", retryCount: 0 };

  const assertBoundedPromptReflectionError = (state: unknown, expected: RegExp) => {
    let caught: unknown;
    try {
      agent.writeBeat({ state, currentBeat } as unknown as AgentContext);
    } catch (error) {
      caught = error;
    }
    if (!(caught instanceof Error)) {
      throw caught ?? new Error("Expected prompt reflection validation to fail.");
    }
    assert.match(caught.message, /OpenAI-compatible prompt context must be JSON serializable/);
    assert.match(caught.message, expected);
    assert.doesNotMatch(caught.message, secretPattern);
  };

  assertBoundedPromptReflectionError(
    new Proxy(
      { safe: true },
      {
        getPrototypeOf() {
          throw new Error(`raw prompt object prototype trap leaked ${secret}`);
        }
      }
    ),
    /OpenAI-compatible prompt context\.state prototype must be readable/
  );

  assertBoundedPromptReflectionError(
    new Proxy(
      { safe: true },
      {
        ownKeys() {
          throw new Error(`raw prompt object keys trap leaked ${secret}`);
        }
      }
    ),
    /OpenAI-compatible prompt context\.state keys must be readable/
  );

  assertBoundedPromptReflectionError(
    new Proxy(
      { safe: true },
      {
        getOwnPropertyDescriptor() {
          throw new Error(`raw prompt object descriptor trap leaked ${secret}`);
        }
      }
    ),
    /OpenAI-compatible prompt context\.state property descriptors must be readable/
  );

  assertBoundedPromptReflectionError(
    {
      items: new Proxy(["safe"], {
        getPrototypeOf() {
          throw new Error(`raw prompt array prototype trap leaked ${secret}`);
        }
      })
    },
    /OpenAI-compatible prompt context\.state\.items prototype must be readable/
  );

  assertBoundedPromptReflectionError(
    {
      items: new Proxy(["safe"], {
        ownKeys() {
          throw new Error(`raw prompt array keys trap leaked ${secret}`);
        }
      })
    },
    /OpenAI-compatible prompt context\.state\.items keys must be readable/
  );

  assertBoundedPromptReflectionError(
    {
      items: new Proxy(["safe"], {
        getOwnPropertyDescriptor() {
          throw new Error(`raw prompt array descriptor trap leaked ${secret}`);
        }
      })
    },
    /OpenAI-compatible prompt context\.state\.items property descriptors must be readable/
  );
  assert.equal(called, false);
});

