test("current lookup does not hide unreadable states while falling back", async () => {
  const root = testRoot("novelist-current-missing-unreadable-test");
  const storage = new NovelStorage(root);
  const pipeline = new NovelPipeline(storage);
  const readable = await pipeline.newProject({
    franchiseName: "포인터 누락 정상 세계",
    workRequest: "포인터 누락 정상 작품"
  });
  const readableData = readable.data as { franchiseId: string; workId: string; volumeId: string };
  const broken = await pipeline.newProject({
    franchiseName: "포인터 누락 손상 세계",
    workRequest: "포인터 누락 손상 작품"
  });
  const brokenData = broken.data as { franchiseId: string; workId: string; volumeId: string };
  await unlink(storage.currentPointerPath());
  await unlink(storage.currentPointerBackupPath()).catch(() => undefined);
  await writeFile(storage.statePath(brokenData.franchiseId, brokenData.workId, brokenData.volumeId), "{bad json", "utf8");

  let message = "";
  try {
    await pipeline.status({ current: true });
  } catch (error) {
    message = error instanceof Error ? error.message : String(error);
  }
  assert.match(message, /Skipped 1 unreadable volume states/);
  assert.match(message, new RegExp(`${brokenData.franchiseId}/${brokenData.workId}/${brokenData.volumeId}`));
  assert.equal(message.includes(storage.root), false);

  const explicit = await pipeline.status({
    franchiseId: readableData.franchiseId,
    workId: readableData.workId,
    volumeId: readableData.volumeId
  });
  const summary = explicit.data as { franchiseId: string };
  assert.equal(summary.franchiseId, readableData.franchiseId);
});

test("current lookup bounds unreadable state diagnostics while falling back", async () => {
  const root = testRoot("novelist-current-missing-unreadable-bounds-test");
  const storage = new NovelStorage(root);
  const pipeline = new NovelPipeline(storage);
  const created = await pipeline.newProject({
    franchiseName: "현재 진단 제한 세계",
    workRequest: "현재 진단 제한 작품"
  });
  const data = created.data as { franchiseId: string; workId: string };
  await unlink(storage.currentPointerPath());
  await unlink(storage.currentPointerBackupPath()).catch(() => undefined);

  for (let index = 0; index < 60; index += 1) {
    const volumeId = `broken-current-${String(index).padStart(2, "0")}`;
    const brokenVolumeDir = storage.volumeDir(data.franchiseId, data.workId, volumeId);
    await mkdir(brokenVolumeDir, { recursive: true });
    await writeFile(join(brokenVolumeDir, "state.json"), `{bad json ${"x".repeat(2000)}`, "utf8");
  }

  let message = "";
  try {
    await pipeline.status({ current: true });
  } catch (error) {
    message = error instanceof Error ? error.message : String(error);
  }

  assert.match(message, /Skipped 60 unreadable volume states/);
  assert.match(message, /truncated 40 unreadable states/);
  assert.match(message, /broken-current-00/);
  assert.ok(!/broken-current-59/.test(message), "diagnostic message should omit truncated state samples");
  assert.equal(message.includes(storage.root), false);
  assert.ok(message.length < 20_000, `diagnostic message was too large: ${message.length}`);
});

