test("state saves reject non-plain metadata without invoking accessors", async () => {
  const root = testRoot("novelist-state-save-accessor-test");
  const storage = new NovelStorage(root);
  const pipeline = new NovelPipeline(storage);
  const created = await pipeline.newProject({
    franchiseName: "상태 접근자 세계",
    workRequest: "상태 접근자 작품"
  });
  const data = created.data as { franchiseId: string; workId: string; volumeId: string };
  const state = await storage.loadState(data.franchiseId, data.workId, data.volumeId);
  const statePath = storage.statePath(data.franchiseId, data.workId, data.volumeId);
  const originalStateFile = await readFile(statePath, "utf8");
  Object.defineProperty(state, "volumeTitle", {
    enumerable: true,
    get() {
      throw new Error("state getter must not run");
    }
  });

  await assertRejects(storage.saveState(state), /VolumeState must not contain non-enumerable or accessor properties/);
  assert.equal(await readFile(statePath, "utf8"), originalStateFile);

  const secret = "Authorization: Bearer storage-state-secret";
  const assertWrappedStateError = async (candidate: VolumeState, expected: RegExp): Promise<void> => {
    await assertRejects(storage.saveState(candidate), expected);
    try {
      await storage.saveState(candidate);
    } catch (error) {
      assert.doesNotMatch(String(error), new RegExp(secret));
      return;
    }
    throw new Error("expected storage state validation failure");
  };
  await assertWrappedStateError(new Proxy(state, {
    getPrototypeOf() {
      throw new Error(`leaked storage state prototype trap ${secret}`);
    }
  }), /Storage state prototype must be readable/);
  await assertWrappedStateError(new Proxy(state, {
    ownKeys() {
      throw new Error(`leaked storage state keys trap ${secret}`);
    }
  }), /Storage state keys must be readable/);
  await assertWrappedStateError(new Proxy(state, {
    getOwnPropertyDescriptor() {
      throw new Error(`leaked storage state descriptor trap ${secret}`);
    }
  }), /Storage state property descriptors must be readable/);
  assert.equal(await readFile(statePath, "utf8"), originalStateFile);
});

