test("direct state validation rejects non-standard array properties without invoking getters", async () => {
  const storage = new NovelStorage(testRoot("novelist-direct-state-array-property-test"));
  const pipeline = new NovelPipeline(storage);
  const created = await pipeline.newProject({
    franchiseName: "상태 배열 속성 세계",
    workRequest: "상태 배열 속성 작품"
  });
  const data = created.data as { franchiseId: string; workId: string; volumeId: string };
  const state = await storage.loadState(data.franchiseId, data.workId, data.volumeId);

  const extraChapters = [...state.chapters] as unknown[];
  (extraChapters as unknown as { extra: string }).extra = "unsupported";
  assert.throws(
    () => validateVolumeState({ ...state, chapters: extraChapters }),
    /VolumeState\.chapters\.extra is not a supported array field/
  );

  const symbolChapters = [...state.chapters] as unknown[];
  (symbolChapters as unknown as Record<symbol, unknown>)[Symbol("chapters")] = "unsupported";
  assert.throws(
    () => validateVolumeState({ ...state, chapters: symbolChapters }),
    /VolumeState\.chapters must not contain symbol properties/
  );

  let getterRan = false;
  const accessorChapters = [...state.chapters] as unknown[];
  Object.defineProperty(accessorChapters, "extra", {
    enumerable: true,
    get() {
      getterRan = true;
      throw new Error("state array extra getter must not run");
    }
  });
  assert.throws(
    () => validateVolumeState({ ...state, chapters: accessorChapters }),
    /VolumeState\.chapters\.extra is not a supported array field/
  );
  assert.equal(getterRan, false);

  const nonStandardChapters = [...state.chapters];
  Object.setPrototypeOf(nonStandardChapters, { inherited: "bad" });
  assert.throws(
    () => validateVolumeState({ ...state, chapters: nonStandardChapters }),
    /VolumeState\.chapters must be a standard array/
  );
});

test("direct state validation wraps unreadable reflection failures", async () => {
  const storage = new NovelStorage(testRoot("novelist-direct-state-reflection-test"));
  const pipeline = new NovelPipeline(storage);
  const created = await pipeline.newProject({
    franchiseName: "상태 리플렉션 세계",
    workRequest: "상태 리플렉션 작품"
  });
  const data = created.data as { franchiseId: string; workId: string; volumeId: string };
  const state = await storage.loadState(data.franchiseId, data.workId, data.volumeId);
  const secret = "Authorization: Bearer state-secret";
  const assertWrapped = (fn: () => unknown, expected: RegExp): void => {
    assert.throws(fn, expected);
    try {
      fn();
    } catch (error) {
      assert.doesNotMatch(String(error), new RegExp(secret));
      return;
    }
    throw new Error("expected validation failure");
  };

  assertWrapped(
    () => validateVolumeState(new Proxy({ ...state }, {
      getPrototypeOf() {
        throw new Error(`leaked state prototype trap ${secret}`);
      }
    })),
    /VolumeState prototype must be readable/
  );

  assertWrapped(
    () => validateVolumeState(new Proxy({ ...state }, {
      ownKeys() {
        throw new Error(`leaked state keys trap ${secret}`);
      }
    })),
    /VolumeState property keys must be readable/
  );

  assertWrapped(
    () => validateVolumeState(new Proxy({ ...state }, {
      getOwnPropertyDescriptor() {
        throw new Error(`leaked state descriptor trap ${secret}`);
      }
    })),
    /VolumeState property descriptors must be readable/
  );

  assertWrapped(
    () => validateVolumeState({
      ...state,
      chapters: new Proxy([...state.chapters], {
        getPrototypeOf() {
          throw new Error(`leaked state array prototype trap ${secret}`);
        }
      })
    }),
    /VolumeState\.chapters prototype must be readable/
  );

  assertWrapped(
    () => validateVolumeState({
      ...state,
      chapters: new Proxy([...state.chapters], {
        ownKeys() {
          throw new Error(`leaked state array keys trap ${secret}`);
        }
      })
    }),
    /VolumeState\.chapters property keys must be readable/
  );

  assertWrapped(
    () => validateVolumeState({
      ...state,
      chapters: new Proxy([...state.chapters], {
        getOwnPropertyDescriptor() {
          throw new Error(`leaked state array descriptor trap ${secret}`);
        }
      })
    }),
    /VolumeState\.chapters property descriptors must be readable/
  );
});

test("direct state validation preserves prototype-like keys for supported-field checks", async () => {
  const storage = new NovelStorage(testRoot("novelist-direct-state-prototype-key-test"));
  const pipeline = new NovelPipeline(storage);
  const created = await pipeline.newProject({
    franchiseName: "상태 특수 키 세계",
    workRequest: "상태 특수 키 작품"
  });
  const data = created.data as { franchiseId: string; workId: string; volumeId: string };
  const state = await storage.loadState(data.franchiseId, data.workId, data.volumeId);
  const topLevel = Object.create(null) as Record<string, unknown>;
  for (const [key, value] of Object.entries(state)) {
    topLevel[key] = value;
  }
  Object.defineProperty(topLevel, "__proto__", {
    enumerable: true,
    value: { polluted: true }
  });

  assert.throws(
    () => validateVolumeState(topLevel),
    /VolumeState\.__proto__ is not a supported field/
  );
  assert.equal(({} as { polluted?: boolean }).polluted, undefined);

  const nestedBeat = Object.create(null) as Record<string, unknown>;
  for (const [key, value] of Object.entries(state.chapters[0]!.beats[0]!)) {
    nestedBeat[key] = value;
  }
  Object.defineProperty(nestedBeat, "__proto__", {
    enumerable: true,
    value: { polluted: true }
  });
  const nestedState = {
    ...state,
    chapters: [
      {
        ...state.chapters[0]!,
        beats: [nestedBeat, ...state.chapters[0]!.beats.slice(1)]
      },
      ...state.chapters.slice(1)
    ]
  };

  assert.throws(
    () => validateVolumeState(nestedState),
    /BeatState\.__proto__ is not a supported field/
  );
  assert.equal(({} as { polluted?: boolean }).polluted, undefined);
});

test("direct state validation bounds object field names before supported-field diagnostics", async () => {
  const storage = new NovelStorage(testRoot("novelist-direct-state-object-key-test"));
  const pipeline = new NovelPipeline(storage);
  const created = await pipeline.newProject({
    franchiseName: "상태 키 세계",
    workRequest: "상태 키 작품"
  });
  const data = created.data as { franchiseId: string; workId: string; volumeId: string };
  const state = await storage.loadState(data.franchiseId, data.workId, data.volumeId);

  assert.throws(
    () => validateVolumeState({ ...state, "bad\nkey": "value" }),
    /VolumeState field names must not contain control characters/
  );
  assert.throws(
    () => validateVolumeState({ ...state, ["x".repeat(1025)]: "value" }),
    /VolumeState field names must be at most 1024 characters/
  );
  assert.throws(
    () => validateVolumeState({ ...state, ["가".repeat(700)]: "value" }),
    /VolumeState field names must be at most 2048 UTF-8 bytes/
  );
  assert.throws(
    () => validateVolumeState({ ...state, ...Object.fromEntries(Array.from({ length: 1000 }, (_value, index) => [`extra${index}`, index])) }),
    /VolumeState must contain at most 1000 fields/
  );

  const nestedBeat = {
    ...state.chapters[0]!.beats[0]!,
    ["nested\u0001key"]: "value"
  };
  assert.throws(
    () => validateVolumeState({
      ...state,
      chapters: [
        {
          ...state.chapters[0]!,
          beats: [nestedBeat, ...state.chapters[0]!.beats.slice(1)]
        },
        ...state.chapters.slice(1)
      ]
    }),
    /BeatState field names must not contain control characters/
  );
});

