test("state loading rejects multiline title and scope labels while preserving multiline prose fields", async () => {
  const root = testRoot("novelist-state-single-line-label-test");
  const storage = new NovelStorage(root);
  const pipeline = new NovelPipeline(storage);
  const created = await pipeline.newProject({
    franchiseName: "단일 라인 세계",
    workRequest: "단일 라인 작품"
  });
  const data = created.data as { franchiseId: string; workId: string; volumeId: string };
  const statePath = storage.statePath(data.franchiseId, data.workId, data.volumeId);
  const original = JSON.parse(await readFile(statePath, "utf8")) as VolumeState;
  await unlink(storage.stateBackupPath(data.franchiseId, data.workId, data.volumeId)).catch(() => undefined);

  const multilineProseState = {
    ...original,
    confirmations: [{ ...original.confirmations[0]!, message: `${original.confirmations[0]!.message}\n추가 확인 문장` }],
    chapters: [
      {
        ...original.chapters[0]!,
        beats: [
          {
            ...original.chapters[0]!.beats[0]!,
            status: "needs_revision",
            lastFeedback: "첫 줄 피드백\n둘째 줄 피드백"
          },
          ...original.chapters[0]!.beats.slice(1)
        ]
      },
      ...original.chapters.slice(1)
    ]
  } as VolumeState;
  await writeFile(statePath, JSON.stringify(multilineProseState), "utf8");
  const multilineLoaded = await storage.loadState(data.franchiseId, data.workId, data.volumeId);
  assert.match(multilineLoaded.confirmations[0]?.message ?? "", /추가 확인 문장/);
  assert.match(multilineLoaded.chapters[0]?.beats[0]?.lastFeedback ?? "", /둘째 줄 피드백/);

  await writeFile(statePath, JSON.stringify({ ...original, volumeTitle: "권 제목\n다음 줄" }), "utf8");
  await assertRejects(storage.loadState(data.franchiseId, data.workId, data.volumeId), /VolumeState\.volumeTitle must be a single-line string/);

  await writeFile(statePath, JSON.stringify({
    ...original,
    chapters: [{ ...original.chapters[0]!, title: "장 제목\t탭" }, ...original.chapters.slice(1)]
  }), "utf8");
  await assertRejects(storage.loadState(data.franchiseId, data.workId, data.volumeId), /ChapterState\.title must be a single-line string/);

  await writeFile(statePath, JSON.stringify({
    ...original,
    chapters: [
      {
        ...original.chapters[0]!,
        beats: [{ ...original.chapters[0]!.beats[0]!, title: "비트 제목\n다음 줄" }, ...original.chapters[0]!.beats.slice(1)]
      },
      ...original.chapters.slice(1)
    ]
  }), "utf8");
  await assertRejects(storage.loadState(data.franchiseId, data.workId, data.volumeId), /BeatState\.title must be a single-line string/);

  await writeFile(statePath, JSON.stringify({
    ...original,
    conflicts: [{ id: "scope-label", scope: "beat\n1", description: "설명\n본문", severity: "warning", resolved: false }]
  }), "utf8");
  await assertRejects(storage.loadState(data.franchiseId, data.workId, data.volumeId), /ConflictRecord\.scope must be a single-line string/);
});

