test("state loading rejects excessive confirmation and conflict counts", async () => {
  const root = testRoot("novelist-state-record-count-bound-test");
  const storage = new NovelStorage(root);
  const pipeline = new NovelPipeline(storage);
  const created = await pipeline.newProject({
    franchiseName: "상태 기록 개수 검증 세계",
    workRequest: "상태 기록 개수 검증 작품"
  });
  const data = created.data as { franchiseId: string; workId: string; volumeId: string };
  const statePath = storage.statePath(data.franchiseId, data.workId, data.volumeId);
  const originalState = JSON.parse(await readFile(statePath, "utf8")) as {
    confirmations: Array<Record<string, unknown>>;
    conflicts: Array<{ id: string; scope: string; description: string; severity: string; resolved: boolean }>;
  };

  const tooManyConfirmations = {
    ...originalState,
    confirmations: Array.from({ length: 1001 }, (_, index) => ({
      ...originalState.confirmations[0],
      id: `confirm-count-${String(index).padStart(4, "0")}`
    }))
  };
  await unlink(storage.stateBackupPath(data.franchiseId, data.workId, data.volumeId)).catch(() => undefined);
  await writeFile(statePath, JSON.stringify(tooManyConfirmations), "utf8");

  await assertRejects(storage.loadState(data.franchiseId, data.workId, data.volumeId), /VolumeState\.confirmations must contain at most 1000 items/);

  const tooManyConflicts = {
    ...originalState,
    conflicts: Array.from({ length: 1001 }, (_, index) => ({
      id: `conflict-count-${String(index).padStart(4, "0")}`,
      scope: "state",
      description: "count bound",
      severity: "warning",
      resolved: false
    }))
  };
  await writeFile(statePath, JSON.stringify(tooManyConflicts), "utf8");

  await assertRejects(storage.loadState(data.franchiseId, data.workId, data.volumeId), /VolumeState\.conflicts must contain at most 1000 items/);
});

