async function assertRejects(promise: Promise<unknown>, pattern: RegExp): Promise<void> {
  try {
    await promise;
  } catch (error) {
    assert.match(error instanceof Error ? error.message : String(error), pattern);
    return;
  }
  throw new Error("Expected promise to reject.");
}

interface ToolSchema {
  type?: string;
  description?: string;
  required?: string[];
  additionalProperties?: boolean;
  properties?: Record<string, ToolSchema & { enum?: unknown[]; minLength?: number; maxLength?: number; "x-maxUtf8Bytes"?: number; pattern?: string; minimum?: number; maximum?: number }>;
  oneOf?: ToolSchema[];
  anyOf?: ToolSchema[];
  not?: ToolSchema;
}

function testRoot(prefix: string): string {
  return join(TEST_TMP_ROOT, `${prefix}-${randomUUID()}`);
}

function indexTypeExports(source: string): string[] {
  const names: string[] = [];
  for (const match of source.matchAll(/export\s+type\s+\{([^}]*)\}\s+from\s+"[^"]+";/gu)) {
    for (const rawName of match[1]!.split(",")) {
      const name = rawName.trim();
      if (name) {
        names.push(name.split(/\s+as\s+/u).pop()!.trim());
      }
    }
  }
  return names.sort();
}

async function writeReviewedPackageFixture(root: string, overrides: Record<string, string> = {}): Promise<void> {
  await mkdir(join(root, "dist", "src"), { recursive: true });
  await mkdir(join(root, "src"), { recursive: true });
  await writeFile(join(root, "README.md"), "# Test\n", "utf8");
  const sourceFiles = (await readdir(join(process.cwd(), "src"))).filter((file) => file.endsWith(".ts")).sort();
  for (const sourceFile of sourceFiles) {
    await writeFile(join(root, "src", sourceFile), "export {};\n", "utf8");
  }
  const distFiles = (await readdir(join(process.cwd(), "dist", "src"))).filter((file) => file.endsWith(".js") || file.endsWith(".d.ts")).sort();
  for (const distFile of distFiles) {
    const content = Object.prototype.hasOwnProperty.call(overrides, distFile)
      ? overrides[distFile]
      : await readFile(join(process.cwd(), "dist", "src", distFile), "utf8");
    await writeFile(join(root, "dist", "src", distFile), content, "utf8");
  }
  await execFilePromise("chmod", ["755", join(root, "dist", "src", "cli.js")], root);
  await writeFile(join(root, "package.json"), JSON.stringify({
    name: "novelist-mcp",
    version: "0.1.0",
    description: "test package",
    license: "MIT",
    type: "module",
    engines: { node: ">=22.0.0" },
    main: "dist/src/index.js",
    types: "dist/src/index.d.ts",
    exports: { ".": { types: "./dist/src/index.d.ts", import: "./dist/src/index.js" } },
    bin: { "novelist-mcp": "dist/src/cli.js" },
    files: ["dist/src", "README.md", "package.json"]
  }), "utf8");
  const files = [
    { path: "README.md", mode: 0o644 },
    { path: "package.json", mode: 0o644 },
    ...distFiles.map((file) => ({ path: `dist/src/${file}`, mode: file === "cli.js" ? 0o755 : 0o644 }))
  ];
  await writeFile(join(root, "pack.json"), JSON.stringify([{
    name: "novelist-mcp",
    version: "0.1.0",
    files,
    entryCount: files.length,
    unpackedSize: 10,
    bundled: []
  }]), "utf8");
}

function makeTestChapter(chapterNo: number, beatCount: number): {
  chapterNo: number;
  title: string;
  targetWords: number;
  beats: Array<{ chapterNo: number; beatNo: number; title: string; targetWords: number; status: string; retryCount: number }>;
} {
  return {
    chapterNo,
    title: `테스트 ${chapterNo}장`,
    targetWords: beatCount,
    beats: Array.from({ length: beatCount }, (_, index) => ({
      chapterNo,
      beatNo: index + 1,
      title: `테스트 ${chapterNo}-${index + 1}`,
      targetWords: 1,
      status: "pending",
      retryCount: 0
    }))
  };
}

function restoreEnv(name: string, value: string | undefined): void {
  if (value === undefined) {
    delete process.env[name];
  } else {
    process.env[name] = value;
  }
}

