type ResultReflectionTrap = "objectKeys" | "objectDescriptor" | "arrayPrototype" | "arrayKeys" | "arrayDescriptor";

class ReflectionTrapResultPipeline extends NovelPipeline {
  constructor(storage: NovelStorage, private readonly trap: ResultReflectionTrap) {
    super(storage);
  }

  async newProject(_input: NewProjectInput): Promise<ToolResult> {
    const secret = "Authorization: Bearer job-result-secret";
    const objectData = new Proxy({ safe: "value" }, {
      ownKeys: this.trap === "objectKeys"
        ? () => {
            throw new Error(`leaked job result object keys trap ${secret}`);
          }
        : undefined,
      getOwnPropertyDescriptor: this.trap === "objectDescriptor"
        ? () => {
            throw new Error(`leaked job result object descriptor trap ${secret}`);
          }
        : undefined
    });
    const arrayData = new Proxy(["value"], {
      getPrototypeOf: this.trap === "arrayPrototype"
        ? () => {
            throw new Error(`leaked job result array prototype trap ${secret}`);
          }
        : undefined,
      ownKeys: this.trap === "arrayKeys"
        ? () => {
            throw new Error(`leaked job result array keys trap ${secret}`);
          }
        : undefined,
      getOwnPropertyDescriptor: this.trap === "arrayDescriptor"
        ? () => {
            throw new Error(`leaked job result array descriptor trap ${secret}`);
          }
        : undefined
    });
    return {
      status: "ok",
      message: "reflection trap result",
      data: this.trap.startsWith("array") ? { items: arrayData } : objectData
    };
  }
}

