class OneTimeConflictAgents extends StubNovelAgents {
  worldBuilds = 0;
  skeletonPlans = 0;
  private conflictsRemaining = 1;

  async buildWorld(input: Parameters<StubNovelAgents["buildWorld"]>[0], approvedOutline: string): Promise<AgentResult> {
    this.worldBuilds += 1;
    return super.buildWorld(input, approvedOutline);
  }

  async planSkeleton(state: Parameters<StubNovelAgents["planSkeleton"]>[0], input: Parameters<StubNovelAgents["planSkeleton"]>[1]): Promise<AgentResult> {
    this.skeletonPlans += 1;
    return super.planSkeleton(state, input);
  }

  async checkContinuity(_context: AgentContext, text: string): Promise<AgentResult> {
    if (this.conflictsRemaining > 0) {
      this.conflictsRemaining -= 1;
      return {
        text,
        issues: ["한 번만 발생하는 설정 충돌"],
        conflict: {
          id: "conflict-once",
          scope: "continuity",
          description: "한 번만 발생하는 설정 충돌",
          severity: "blocking",
          resolved: false
        }
      };
    }
    return { text, issues: [] };
  }
}

