class MutatingAgentContextAgents extends StubNovelAgents {
  editorSawVolumeTitle?: string;
  editorSawBeatStatus?: string;
  editorSawFeedback?: string[];

  async planSkeleton(state: VolumeState, input: NewProjectInput): Promise<AgentResult> {
    state.volumeTitle = "mutated by skeleton planner";
    state.chapters[0]!.beats[0]!.title = "mutated by skeleton planner";
    return super.planSkeleton(state, input);
  }

  async writeBeat(context: AgentContext): Promise<AgentResult> {
    context.state.volumeTitle = "mutated by writer";
    if (context.currentBeat) {
      context.currentBeat.status = "complete";
    }
    context.feedback?.push("mutated by writer");
    return super.writeBeat(context);
  }

  async editBeat(context: AgentContext, draft: string): Promise<AgentResult> {
    this.editorSawVolumeTitle = context.state.volumeTitle;
    this.editorSawBeatStatus = context.currentBeat?.status;
    this.editorSawFeedback = [...(context.feedback ?? [])];
    return super.editBeat(context, draft);
  }
}

