class ReflectionTrapIssueArrayAgents extends StubNovelAgents {
  constructor(private readonly trap: "prototype" | "keys" | "descriptor") {
    super();
  }

  async planInitial(): Promise<AgentResult> {
    const secret = "Authorization: Bearer agent-issues-reflection-secret";
    const issues = new Proxy(["safe"], {
      getPrototypeOf: () => {
        if (this.trap === "prototype") {
          throw new Error(`leaked agent issue array prototype trap ${secret}`);
        }
        return Array.prototype;
      },
      ownKeys: (target) => {
        if (this.trap === "keys") {
          throw new Error(`leaked agent issue array keys trap ${secret}`);
        }
        return Reflect.ownKeys(target);
      },
      getOwnPropertyDescriptor: (target, key) => {
        if (this.trap === "descriptor") {
          throw new Error(`leaked agent issue array descriptor trap ${secret}`);
        }
        return Object.getOwnPropertyDescriptor(target, key);
      }
    });
    return { text: "reflection 이슈", issues };
  }
}

