class ShutdownHoldAgents extends StubNovelAgents {
  private released = false;
  private releaseWaiters: Array<() => void> = [];
  private held = false;
  private heldWaiters: Array<() => void> = [];

  async planInitial(input: Parameters<StubNovelAgents["planInitial"]>[0]): Promise<AgentResult> {
    if (!this.released) {
      this.held = true;
      for (const waiter of this.heldWaiters.splice(0)) {
        waiter();
      }
      await new Promise<void>((resolveRelease) => {
        this.releaseWaiters.push(resolveRelease);
      });
    }
    return super.planInitial(input);
  }

  release(): void {
    this.released = true;
    for (const waiter of this.releaseWaiters.splice(0)) {
      waiter();
    }
  }

  async waitUntilHeld(): Promise<void> {
    if (this.held) {
      return;
    }
    await new Promise<void>((resolveHeld) => {
      this.heldWaiters.push(resolveHeld);
    });
  }
}

