class ReflectionTrapHealthStorage extends NovelStorage {
  constructor(root: string, private readonly trap: "prototype" | "keys" | "descriptor") {
    super(root);
  }

  async healthCheck(): Promise<StorageHealthCheck> {
    const secret = "Authorization: Bearer storage-health-reflection-secret";
    return new Proxy(
      {
        root: this.root,
        writable: true,
        jobStoreReadable: true,
        currentPointerReadable: true,
        jobCount: 0,
        jobQuarantineCount: 0
      },
      {
        getPrototypeOf: () => {
          if (this.trap === "prototype") {
            throw new Error(`leaked storage health prototype trap ${secret}`);
          }
          return Object.prototype;
        },
        ownKeys: (target) => {
          if (this.trap === "keys") {
            throw new Error(`leaked storage health keys trap ${secret}`);
          }
          return Reflect.ownKeys(target);
        },
        getOwnPropertyDescriptor: (target, key) => {
          if (this.trap === "descriptor") {
            throw new Error(`leaked storage health descriptor trap ${secret}`);
          }
          return Object.getOwnPropertyDescriptor(target, key);
        }
      }
    ) as StorageHealthCheck;
  }
}

