class FailingFirstJobWriteStorage extends NovelStorage {
  private writes = 0;

  async writeJob(jobId: string, value: unknown): Promise<void> {
    this.writes += 1;
    if (this.writes === 1) {
      throw new Error("first snapshot write failed");
    }
    return super.writeJob(jobId, value);
  }
}

