class HangingNthJobWriteStorage extends NovelStorage {
  private writes = 0;

  constructor(root: string, private readonly hangAt: number) {
    super(root);
  }

  async writeJob(jobId: string, value: unknown): Promise<void> {
    this.writes += 1;
    if (this.writes >= this.hangAt) {
      await new Promise<void>(() => undefined);
      return;
    }
    return super.writeJob(jobId, value);
  }
}

class ReleaseOnRunningCancellationWriteStorage extends NovelStorage {
  private released = false;

  constructor(root: string, private readonly release: () => void) {
    super(root);
  }

  async writeJob(jobId: string, value: unknown): Promise<void> {
    const snapshot = value as { status?: unknown; cancelRequested?: unknown };
    if (!this.released && snapshot.status === "running" && snapshot.cancelRequested === true) {
      this.released = true;
      this.release();
      await delay(35);
    }
    return super.writeJob(jobId, value);
  }
}

