class SwappingQuarantineParentStorage extends NovelStorage {
  private swapped = false;

  constructor(root: string, private readonly outside: string) {
    super(root);
  }

  protected async beforeDeleteJobQuarantineCandidate(path: string): Promise<void> {
    if (this.swapped) {
      return;
    }
    this.swapped = true;
    const quarantineDir = dirname(path);
    await rename(quarantineDir, join(dirname(quarantineDir), "quarantine-real"));
    await symlink(this.outside, quarantineDir);
  }
}

class ReplacingQuarantineCandidateStorage extends NovelStorage {
  private replaced = false;

  protected async beforeDeleteJobQuarantineCandidate(path: string): Promise<void> {
    if (this.replaced) {
      return;
    }
    this.replaced = true;
    await unlink(path);
    await writeFile(path, "replacement quarantine snapshot\n", "utf8");
  }
}

