class ReflectionTrapQuarantineCleanupFailureArrayStorage extends NovelStorage {
  constructor(root: string, private readonly trap: "prototype" | "keys" | "descriptor") {
    super(root);
  }

  async cleanupJobQuarantine(): Promise<JobQuarantineCleanupResult> {
    const secret = "Authorization: Bearer quarantine-array-reflection-secret";
    const failures = new Proxy(
      [
        {
          path: `${this.root}/jobs/quarantine/reflection-array-field.json`,
          error: "reflection array field"
        }
      ],
      {
        getPrototypeOf: () => {
          if (this.trap === "prototype") {
            throw new Error(`leaked quarantine failure array prototype trap ${secret}`);
          }
          return Array.prototype;
        },
        ownKeys: (target) => {
          if (this.trap === "keys") {
            throw new Error(`leaked quarantine failure array keys trap ${secret}`);
          }
          return Reflect.ownKeys(target);
        },
        getOwnPropertyDescriptor: (target, key) => {
          if (this.trap === "descriptor") {
            throw new Error(`leaked quarantine failure array descriptor trap ${secret}`);
          }
          return Object.getOwnPropertyDescriptor(target, key);
        }
      }
    );
    return {
      deleted: 0,
      failed: 1,
      failureItemLimit: 1,
      failures
    };
  }
}

