function readZipUint16(bytes: Uint8Array, offset: number): number {
  return bytes[offset]! | (bytes[offset + 1]! << 8);
}

function readZipUint32(bytes: Uint8Array, offset: number): number {
  return (bytes[offset]! | (bytes[offset + 1]! << 8) | (bytes[offset + 2]! << 16) | (bytes[offset + 3]! << 24)) >>> 0;
}

function findZipCentralDirectoryOffset(bytes: Uint8Array): number {
  for (let offset = 0; offset + 4 <= bytes.length; offset += 1) {
    if (readZipUint32(bytes, offset) === 0x02014b50) {
      return offset;
    }
  }
  throw new Error("ZIP central directory not found.");
}

function delay(ms: number): Promise<void> {
  return new Promise((resolveDelay) => {
    setTimeout(resolveDelay, ms);
  });
}

function fakeResponse(ok: boolean, status: number, payload: unknown) {
  return {
    ok,
    status,
    async text() {
      return JSON.stringify(payload);
    }
  };
}

function fakeTextResponse(ok: boolean, status: number, body: string) {
  return {
    ok,
    status,
    async text() {
      return body;
    }
  };
}

function execFilePromise(file: string, args: string[], cwd: string): Promise<{ stdout: string; stderr: string }> {
  return new Promise((resolveExec, rejectExec) => {
    execFile(file, args, { encoding: "utf8", timeout: 5000, maxBuffer: 1024 * 1024, cwd }, (error, stdout, stderr) => {
      if (error) {
        rejectExec(new Error(`${error.message}\n${stdout}\n${stderr}`));
        return;
      }
      resolveExec({ stdout, stderr });
    });
  });
}

function execFileWithInput(file: string, args: string[], cwd: string, input: string | Uint8Array): Promise<{ stdout: string; stderr: string }> {
  return new Promise((resolveExec, rejectExec) => {
    const child = execFile(file, args, { encoding: "utf8", timeout: 5000, maxBuffer: 1024 * 1024, cwd }, (error, stdout, stderr) => {
      if (error) {
        rejectExec(new Error(`${error.message}\n${stdout}\n${stderr}`));
        return;
      }
      resolveExec({ stdout, stderr });
    });
    child.stdin?.end(input);
  });
}

function execFileFailure(file: string, args: string[], cwd: string, env: Record<string, string | undefined>): Promise<{ stdout: string; stderr: string }> {
  return new Promise((resolveExec, rejectExec) => {
    const childEnv = Object.fromEntries(Object.entries(env).filter((entry): entry is [string, string] => entry[1] !== undefined));
    execFile(file, args, { encoding: "utf8", timeout: 5000, maxBuffer: 1024 * 1024, cwd, env: childEnv }, (error, stdout, stderr) => {
      if (!error) {
        rejectExec(new Error(`Expected command to fail.\n${stdout}\n${stderr}`));
        return;
      }
      resolveExec({ stdout, stderr });
    });
  });
}

async function packageVersion(): Promise<string> {
  const parsed = JSON.parse(await readFile(join(process.cwd(), "package.json"), "utf8")) as { version?: unknown };
  if (typeof parsed.version !== "string") {
    throw new Error("Test package.json version must be a string.");
  }
  return parsed.version;
}

function escapeRegExp(value: string): string {
  return value.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

function sortedUnique(values: string[]): string[] {
  return [...new Set(values)].sort();
}

async function waitForJob(jobs: JobManager, jobId: string) {
  for (let index = 0; index < 100; index += 1) {
    const status = jobs.status({ jobId });
    const snapshot = status.data as { status: string };
    if (snapshot.status === "succeeded" || snapshot.status === "failed" || snapshot.status === "cancelled") {
      return snapshot as { status: string; result?: unknown; error?: string; persistenceError?: string; persistencePending?: boolean };
    }
    await delay(5);
  }
  throw new Error("Timed out waiting for job.");
}

async function waitForPersistedJobStatus<T extends { status?: string }>(storage: NovelStorage, jobId: string, expectedStatus: string): Promise<T> {
  for (let index = 0; index < 100; index += 1) {
    try {
      const persisted = await storage.readJob<T>(jobId);
      if (persisted.status === expectedStatus) {
        return persisted;
      }
    } catch (error) {
      if (!isTransientPersistedJobReadError(error)) {
        throw error;
      }
    }
    await delay(5);
  }
  throw new Error(`Timed out waiting for persisted job status ${expectedStatus}.`);
}

function isTransientPersistedJobReadError(error: unknown): boolean {
  const message = error instanceof Error ? error.message : String(error);
  return (
    message.includes("ENOENT: no such file or directory") ||
    message.includes("JSON metadata file path changed while being opened:") ||
    message.includes("JSON metadata file changed while being read:")
  );
}

async function waitForJobStatus(jobs: JobManager, jobId: string, expectedStatus: string) {
  for (let index = 0; index < 100; index += 1) {
    const status = jobs.status({ jobId });
    const snapshot = status.data as { status: string };
    if (snapshot.status === expectedStatus) {
      return snapshot;
    }
    await delay(5);
  }
  throw new Error(`Timed out waiting for job status ${expectedStatus}.`);
}

function replaceFirstAscii(input: Uint8Array, search: string, replacement: string): Uint8Array {
  if (search.length !== replacement.length) {
    throw new Error("Replacement must have the same byte length.");
  }
  const output = new Uint8Array(input);
  const searchBytes = new TextEncoder().encode(search);
  const replacementBytes = new TextEncoder().encode(replacement);
  for (let index = 0; index <= output.length - searchBytes.length; index += 1) {
    let matched = true;
    for (let offset = 0; offset < searchBytes.length; offset += 1) {
      if (output[index + offset] !== searchBytes[offset]) {
        matched = false;
        break;
      }
    }
    if (matched) {
      output.set(replacementBytes, index);
      return output;
    }
  }
  throw new Error(`Pattern not found: ${search}`);
}

function replaceLastAscii(input: Uint8Array, search: string, replacement: string): Uint8Array {
  if (search.length !== replacement.length) {
    throw new Error("Replacement must have the same byte length.");
  }
  const output = new Uint8Array(input);
  const searchBytes = new TextEncoder().encode(search);
  const replacementBytes = new TextEncoder().encode(replacement);
  for (let index = output.length - searchBytes.length; index >= 0; index -= 1) {
    let matched = true;
    for (let offset = 0; offset < searchBytes.length; offset += 1) {
      if (output[index + offset] !== searchBytes[offset]) {
        matched = false;
        break;
      }
    }
    if (matched) {
      output.set(replacementBytes, index);
      return output;
    }
  }
  throw new Error(`Pattern not found: ${search}`);
}

function replaceAllAsciiFirstByte(input: Uint8Array, search: string, replacementByte: number): Uint8Array {
  const output = new Uint8Array(input);
  const searchBytes = new TextEncoder().encode(search);
  let replacements = 0;
  for (let index = 0; index <= output.length - searchBytes.length; index += 1) {
    let matched = true;
    for (let offset = 0; offset < searchBytes.length; offset += 1) {
      if (output[index + offset] !== searchBytes[offset]) {
        matched = false;
        break;
      }
    }
    if (matched) {
      output[index] = replacementByte;
      replacements += 1;
    }
  }
  if (replacements === 0) {
    throw new Error(`Pattern not found: ${search}`);
  }
  return output;
}

function replaceFirstAsciiAndCrc(input: Uint8Array, search: string, replacement: Uint8Array): Uint8Array {
  const searchBytes = new TextEncoder().encode(search);
  if (searchBytes.length !== replacement.length) {
    throw new Error("Replacement must have the same byte length.");
  }
  const output = new Uint8Array(input);
  let localOffset = 0;
  while (localOffset + 4 <= output.length && readTestU32(output, localOffset) === 0x04034b50) {
    const compressedSize = readTestU32(output, localOffset + 18);
    const nameLength = readTestU16(output, localOffset + 26);
    const extraLength = readTestU16(output, localOffset + 28);
    const dataStart = localOffset + 30 + nameLength + extraLength;
    const dataEnd = dataStart + compressedSize;
    const matchOffset = findBytes(output, searchBytes, dataStart, dataEnd);
    if (matchOffset !== -1) {
      output.set(replacement, matchOffset);
      const crc = testCrc32(output.slice(dataStart, dataEnd));
      writeTestU32(output, localOffset + 14, crc);
      updateCentralDirectoryCrc(output, localOffset, crc);
      return output;
    }
    localOffset = dataEnd;
  }
  throw new Error(`Pattern not found in ZIP entry data: ${search}`);
}

function insertMimetypeExtraField(input: Uint8Array): Uint8Array {
  const extra = new Uint8Array([0x01, 0x02]);
  const firstNameLength = readTestU16(input, 26);
  const firstExtraLengthOffset = 28;
  const firstExtraStart = 30 + firstNameLength;
  const eocdOffset = findLastZipSignature(input, 0x06054b50);
  const centralStart = readTestU32(input, eocdOffset + 16);
  const output = new Uint8Array(input.length + extra.length);
  output.set(input.slice(0, firstExtraStart), 0);
  output.set(extra, firstExtraStart);
  output.set(input.slice(firstExtraStart), firstExtraStart + extra.length);
  writeTestU16(output, firstExtraLengthOffset, extra.length);

  let centralOffset = centralStart + extra.length;
  while (readTestU32(output, centralOffset) === 0x02014b50) {
    const localOffsetField = centralOffset + 42;
    const localOffset = readTestU32(output, localOffsetField);
    if (localOffset > 0) {
      writeTestU32(output, localOffsetField, localOffset + extra.length);
    }
    const nameLength = readTestU16(output, centralOffset + 28);
    const extraLength = readTestU16(output, centralOffset + 30);
    const commentLength = readTestU16(output, centralOffset + 32);
    centralOffset += 46 + nameLength + extraLength + commentLength;
  }

  const shiftedEocdOffset = eocdOffset + extra.length;
  writeTestU32(output, shiftedEocdOffset + 16, centralStart + extra.length);
  return output;
}

function setFirstZipEntryFlags(input: Uint8Array, localFlags: number, centralFlags: number): Uint8Array {
  const output = new Uint8Array(input);
  const eocdOffset = findLastZipSignature(output, 0x06054b50);
  const centralStart = readTestU32(output, eocdOffset + 16);
  writeTestU16(output, 6, localFlags);
  writeTestU16(output, centralStart + 8, centralFlags);
  return output;
}

function addZipEndComment(input: Uint8Array): Uint8Array {
  const comment = new TextEncoder().encode("operator comment");
  const output = new Uint8Array(input.length + comment.length);
  output.set(input);
  output.set(comment, input.length);
  const eocdOffset = findLastZipSignature(output, 0x06054b50);
  writeTestU16(output, eocdOffset + 20, comment.length);
  return output;
}

function updateCentralDirectoryCrc(output: Uint8Array, targetLocalOffset: number, crc: number): void {
  const eocdOffset = findLastZipSignature(output, 0x06054b50);
  let centralOffset = readTestU32(output, eocdOffset + 16);
  while (readTestU32(output, centralOffset) === 0x02014b50) {
    if (readTestU32(output, centralOffset + 42) === targetLocalOffset) {
      writeTestU32(output, centralOffset + 16, crc);
      return;
    }
    const nameLength = readTestU16(output, centralOffset + 28);
    const extraLength = readTestU16(output, centralOffset + 30);
    const commentLength = readTestU16(output, centralOffset + 32);
    centralOffset += 46 + nameLength + extraLength + commentLength;
  }
  throw new Error(`Central directory entry not found for local offset ${targetLocalOffset}.`);
}

function findBytes(input: Uint8Array, search: Uint8Array, start: number, end: number): number {
  for (let index = start; index <= end - search.length; index += 1) {
    let matched = true;
    for (let offset = 0; offset < search.length; offset += 1) {
      if (input[index + offset] !== search[offset]) {
        matched = false;
        break;
      }
    }
    if (matched) {
      return index;
    }
  }
  return -1;
}

function findLastZipSignature(input: Uint8Array, signature: number): number {
  for (let offset = input.length - 4; offset >= 0; offset -= 1) {
    if (readTestU32(input, offset) === signature) {
      return offset;
    }
  }
  throw new Error(`ZIP signature not found: ${signature.toString(16)}`);
}

function readTestU16(input: Uint8Array, offset: number): number {
  return input[offset] | (input[offset + 1] << 8);
}

function readTestU32(input: Uint8Array, offset: number): number {
  return (input[offset] | (input[offset + 1] << 8) | (input[offset + 2] << 16) | (input[offset + 3] << 24)) >>> 0;
}

function writeTestU16(output: Uint8Array, offset: number, value: number): void {
  output[offset] = value & 0xff;
  output[offset + 1] = (value >>> 8) & 0xff;
}

function writeTestU32(output: Uint8Array, offset: number, value: number): void {
  output[offset] = value & 0xff;
  output[offset + 1] = (value >>> 8) & 0xff;
  output[offset + 2] = (value >>> 16) & 0xff;
  output[offset + 3] = (value >>> 24) & 0xff;
}

function testCrc32(data: Uint8Array): number {
  let crc = 0xffffffff;
  for (const byte of data) {
    crc = (crc >>> 8) ^ TEST_CRC_TABLE[(crc ^ byte) & 0xff];
  }
  return (crc ^ 0xffffffff) >>> 0;
}

const TEST_CRC_TABLE = Array.from({ length: 256 }, (_, index) => {
  let value = index;
  for (let bit = 0; bit < 8; bit += 1) {
    value = value & 1 ? 0xedb88320 ^ (value >>> 1) : value >>> 1;
  }
  return value >>> 0;
});

function createTestStoredZip(paths: string[]): Uint8Array {
  const encoder = new TextEncoder();
  const localParts: Uint8Array[] = [];
  const centralParts: Uint8Array[] = [];
  let offset = 0;
  for (const path of paths) {
    const name = encoder.encode(path);
    const data = encoder.encode("x");
    const crc = testCrc32(data);
    const local = testConcat([
      testU32(0x04034b50),
      testU16(20),
      testU16(0),
      testU16(0),
      testU16(0),
      testU16(0),
      testU32(crc),
      testU32(data.length),
      testU32(data.length),
      testU16(name.length),
      testU16(0),
      name,
      data
    ]);
    localParts.push(local);
    centralParts.push(testConcat([
      testU32(0x02014b50),
      testU16(20),
      testU16(20),
      testU16(0),
      testU16(0),
      testU16(0),
      testU16(0),
      testU32(crc),
      testU32(data.length),
      testU32(data.length),
      testU16(name.length),
      testU16(0),
      testU16(0),
      testU16(0),
      testU16(0),
      testU32(0),
      testU32(offset),
      name
    ]));
    offset += local.length;
  }
  const centralDirectory = testConcat(centralParts);
  return testConcat([
    ...localParts,
    centralDirectory,
    testU32(0x06054b50),
    testU16(0),
    testU16(0),
    testU16(paths.length),
    testU16(paths.length),
    testU32(centralDirectory.length),
    testU32(offset),
    testU16(0)
  ]);
}

function testU16(value: number): Uint8Array {
  return new Uint8Array([value & 0xff, (value >>> 8) & 0xff]);
}

function testU32(value: number): Uint8Array {
  return new Uint8Array([value & 0xff, (value >>> 8) & 0xff, (value >>> 16) & 0xff, (value >>> 24) & 0xff]);
}

function testConcat(parts: Uint8Array[]): Uint8Array {
  const total = parts.reduce((sum, part) => sum + part.length, 0);
  const output = new Uint8Array(total);
  let offset = 0;
  for (const part of parts) {
    output.set(part, offset);
    offset += part.length;
  }
  return output;
}

function volumeLockPath(root: string, franchiseId: string, workId: string, volumeId: string): string {
  const digest = createHash("sha256").update([franchiseId, workId, volumeId].join("\0")).digest("hex").slice(0, 32);
  return join(root, ".locks", `volume-${digest}`);
}

function extractToolPayload(response: unknown): { data?: unknown } {
  const result = (response as { result?: { content?: Array<{ text: string }> } }).result;
  const text = result?.content?.[0]?.text;
  if (!text) {
    throw new Error("Tool response did not contain text content.");
  }
  return JSON.parse(text) as { data?: unknown };
}

async function completeTinyVolume(pipeline: NovelPipeline): Promise<{ franchiseId: string; workId: string; volumeId: string }> {
  const suffix = randomUUID();
  const created = await pipeline.newProject({
    franchiseName: `검증 세계 ${suffix}`,
    workRequest: `검증 작품 ${suffix}`
  });
  const data = created.data as { confirmationId: string; franchiseId: string; workId: string; volumeId: string };
  let next = await pipeline.confirm({ confirmationId: data.confirmationId, approved: true });
  while (next.status !== "complete") {
    next = await pipeline.continue({
      franchiseId: data.franchiseId,
      workId: data.workId,
      volumeId: data.volumeId
    });
  }
  return { franchiseId: data.franchiseId, workId: data.workId, volumeId: data.volumeId };
}

async function writeExternalValidatorFixture(prefix: string): Promise<string> {
  const path = join(TEST_TMP_ROOT, `${prefix}-${randomUUID()}.epub`);
  await writeFile(path, "external validator fixture\n", "utf8");
  return path;
}
